/**
 * Rates store — persisted in localStorage, keyed by dateOfLive.
 * Stores: phpRate, silverRate, silverBrandedRate
 */

function load(key: string): Record<string, number> {
  try { return JSON.parse(localStorage.getItem(key) || '{}'); } catch { return {}; }
}
function save(key: string, data: Record<string, number>) {
  localStorage.setItem(key, JSON.stringify(data));
}

// ── PHP Rate ──────────────────────────────────────────────────
const PHP_KEY = 'phpRates_v1';
export function getPhpRate(date: string): number | null { return load(PHP_KEY)[date] ?? null; }
export function setPhpRate(date: string, rate: number) { const r = load(PHP_KEY); r[date] = rate; save(PHP_KEY, r); }
export function hasPhpRate(date: string): boolean { return getPhpRate(date) !== null; }

// ── Silver Rate ───────────────────────────────────────────────
const SILVER_KEY = 'silverRates_v1';
export function getSilverRateForDate(date: string): number | null { return load(SILVER_KEY)[date] ?? null; }
export function setSilverRate(date: string, rate: number) { const r = load(SILVER_KEY); r[date] = rate; save(SILVER_KEY, r); }

// ── Silver Branded Rate ───────────────────────────────────────
const SILVER_BRANDED_KEY = 'silverBrandedRates_v1';
export function getSilverBrandedRateForDate(date: string): number | null { return load(SILVER_BRANDED_KEY)[date] ?? null; }
export function setSilverBrandedRate(date: string, rate: number) { const r = load(SILVER_BRANDED_KEY); r[date] = rate; save(SILVER_BRANDED_KEY, r); }

