// Strict Global Fallback Baseline
const GLOBAL_DEFAULT_PHP_RATE = 16.7;

/**
 * Saves a specific exchange rate for a specific live date.
 */
export function setPhpRate(dateOfLive: string, rate: number) {
  if (!dateOfLive || isNaN(rate) || rate <= 0) return;
  try {
    const key = `phpRate_${dateOfLive}`;
    localStorage.setItem(key, rate.toString());
  } catch (e) {
    console.error('Failed to save PHP rate:', e);
  }
}

/**
 * Retrieves the specific exchange rate for a live date.
 * If none was specifically set by the admin on that computer, it strictly defaults to 16.7
 */
export function getPhpRate(dateOfLive: string): number {
  if (!dateOfLive) return GLOBAL_DEFAULT_PHP_RATE;
  try {
    const key = `phpRate_${dateOfLive}`;
    const stored = localStorage.getItem(key);
    if (stored) {
      const parsed = parseFloat(stored);
      if (!isNaN(parsed) && parsed > 0) return parsed;
    }
  } catch (e) {
    console.error('Failed to read PHP rate:', e);
  }

  // Enforces the Master Anchor fallback
  return GLOBAL_DEFAULT_PHP_RATE;
}

