import { z } from 'zod';
import { createEndpoint, Database, DatabaseRowType, Roles } from 'zite-integrations-backend-sdk';

const SUPER_ADMIN_EMAILS = [
  "reynanteevillegas@gmail.com",
  "villegasenrique0921@gmail.com",
  "roseannaranez2@gmail.com"
];

// Strict allowlist of fields that can be bulk-updated
const VALID_FIELDS = new Set<keyof DatabaseRowType>([
  'status', 'remittanceStatus', 'reviewChasing', 'dispatchDate', 'deliveredDate', 'additionalCharges', 'liverAdminRemarks'
]);

export default createEndpoint({
  description: 'Securely update multiple Database rows in a single background batch',
  authenticated: true,
  inputSchema: z.object({
    updates: z.array(z.object({
      rowId: z.number(),
      fields: z.record(z.unknown()),
    })),
  }),
  outputSchema: z.object({ success: z.boolean(), updatedCount: z.number() }),
  execute: async ({ input, context }) => {
    // 1. Enforce Admin/Dispatch Authorization
    if (!context?.user?.email) throw new Error("Unauthorized request");
    const userEmail = context.user.email.toLowerCase().trim();

    let isAuthorized = SUPER_ADMIN_EMAILS.includes(userEmail);
    if (!isAuthorized) {
      const roles = await Roles.findAll({});
      const found = roles?.find(r => (r.email || '')?.toLowerCase().trim() === userEmail);
      if (found) {
         const roleStr = (found.role || '').toLowerCase();
         if (['super_admin', 'admin', 'dispatch'].some(r => roleStr.includes(r))) {
            isAuthorized = true;
         }
      }
    }

    if (!isAuthorized) {
      throw new Error("Forbidden: Your account does not have permission for bulk updates.");
    }

    // 2. Safely process the background batch
    let count = 0;
    for (const update of input.updates) {
      const sanitized: Partial<DatabaseRowType> = {};
      for (const [key, value] of Object.entries(update.fields)) {
        if (VALID_FIELDS.has(key as keyof DatabaseRowType)) {
          (sanitized as Record<string, unknown>)[key] = value;
        }
      }

      if (Object.keys(sanitized).length > 0) {
        await Database.update({ rowId: update.rowId, row: sanitized });
        count++;
      }
    }

    return { success: true, updatedCount: count };
  },
});

