import { Search, X } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { useState, useEffect, ReactNode } from 'react';

interface Props {
  title: string;
  subtitle?: string;
  searchQuery: string;
  onSearchChange: (q: string) => void;
  rightContent?: ReactNode;
}

export default function TabHeader({ title, subtitle, searchQuery, onSearchChange, rightContent }: Props) {
  const [localQuery, setLocalQuery] = useState(searchQuery);

  useEffect(() => {
    const timer = setTimeout(() => {
      onSearchChange(localQuery);
    }, 300);
    return () => clearTimeout(timer);
  }, [localQuery, onSearchChange]);

  useEffect(() => {
    if (searchQuery === '') setLocalQuery('');
  }, [searchQuery]);

  return (
    <div className="sticky top-0 z-20 bg-background/95 backdrop-blur supports-[backdrop-filter]:bg-background/80 border-b border-border pb-4 pt-4 px-4">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
