import { useMemo, useState } from 'react';
import { ChevronDown, ChevronUp } from 'lucide-react';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { TabProps, DatabaseRowType } from '@/types';
import { calcItemPriceAED, parseDateRobust } from '@/lib/calculations';
import { formatDate } from '@/lib/formatters';
import TabHeader from '@/components/TabHeader';
import StatusBadge from '@/components/StatusBadge';
import KpiCard from '@/components/bossing/KpiCard';
import { startOfWeek, startOfMonth } from 'date-fns';

const ACTIVE_STATUSES = ['Delivered', 'Paid/DP but Item Hold'];

function calcGrams(records: DatabaseRowType[]): number {
  return records.reduce((s, r) => {
    const cat = (r.category || '').toLowerCase();
    if (cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond')) return s;
    return s + (Number(r.grams) || 0);
  }, 0);
}

type DateRange = 'all' | 'week' | 'month' | 'custom';

export default function LiverDashboard({ records, searchQuery, onSearchChange }: TabProps) {
  const [selectedLiver, setSelectedLiver] = useState('');
  const [range, setRange] = useState<DateRange>('all');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [showBreakdown, setShowBreakdown] = useState(false);

  const liverNames = useMemo(() => {
    return Array.from(new Set(
      records.map(r => r.liverName?.toUpperCase().trim()).filter(Boolean) as string[]
    )).sort((a, b) => a.localeCompare(b));
  }, [records]);

  const byLiver = useMemo(() => {
    if (!selectedLiver) return [];
    return records.filter(r =>
      r.liverName?.toUpperCase().trim() === selectedLiver &&
      ACTIVE_STATUSES.includes(r.status || '')
    );
  }, [records, selectedLiver]);

  const filtered = useMemo(() => {
    if (range === 'all') return byLiver;
    const now = new Date();
    let from: Date;
    let to: Date | undefined;
    if (range === 'week') from = startOfWeek(now, { weekStartsOn: 1 });
    else if (range === 'month') from = startOfMonth(now);
    else {
      from = customStart ? new Date(customStart) : new Date(0);
      to = customEnd ? new Date(customEnd) : undefined;
    }
    return byLiver.filter(r => {
      if (!r.dateOfLive) return false;
      const d = parseDateRobust(r.dateOfLive);
      if (!d) return false;
      if (d < from) return false;
      if (to) {
        const endOfDay = new Date(to);
        endOfDay.setHours(23, 59, 59, 999);
        if (d > endOfDay) return false;
      }
      return true;
    });
  }, [byLiver, range, customStart, customEnd]);

  const totalItems = filtered.length;
  const totalGrams = calcGrams(filtered);
  const totalSalesValue = filtered.reduce((s, r) => s + calcItemPriceAED(r), 0);

  const breakdownByDate = useMemo(() => {
    const map = new Map<string, DatabaseRowType[]>();
    for (const r of filtered) {
      const key = r.dateOfLive || 'Unknown';
      if (!map.has(key)) map.set(key, []);
      map.get(key)!.push(r);
    }
    return [...map.entries()].sort((a, b) => b[0].localeCompare(a[0]));
  }, [filtered]);

  const RANGES: { key: DateRange; label: string }[] = [
    { key: 'all', label: 'All Time' },
    { key: 'week', label: 'This Week' },
    { key: 'month', label: 'This Month' },
    { key: 'custom', label: 'Custom' },
  ];

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader title="Liver Dashboard" subtitle="Personal sales summary" searchQuery={searchQuery} onSearchChange={onSearchChange} />
      <div className="px-4 pt-4 space-y-4">

        {/* Filters row */}
        <div className="space-y-3">
          <div>
            <p className="text-xs text-muted-foreground mb-1.5">Select your name</p>
            <Select value={selectedLiver} onValueChange={setSelectedLiver}>
              <SelectTrigger className="h-9 text-sm bg-background border-border w-full max-w-xs">
                <SelectValue placeholder="Select liver name..." />
              </SelectTrigger>
              <SelectContent className="bg-popover border-border">
                {liverNames.map(name => (
                  <SelectItem key={name} value={name} className="text-sm">{name}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {selectedLiver && (
            <div>
              <p className="text-xs text-muted-foreground mb-1.5">Date range</p>
              <div className="flex gap-1.5 flex-wrap">
                {RANGES.map(r => (
                  <Button
                    key={r.key}
                    size="sm"
                    variant={range === r.key ? 'default' : 'outline'}
                    className={`text-xs h-7 ${range === r.key ? 'bg-primary text-primary-foreground' : 'border-border'}`}
                    onClick={() => setRange(r.key)}
                  >
                    {r.label}
                  </Button>
                ))}
              </div>
              {range === 'custom' && (
                <div className="flex gap-2 mt-2">
                  <div className="flex flex-col gap-1">
                    <label className="text-[10px] text-muted-foreground">Start Date</label>
                    <Input type="date" value={customStart} onChange={e => setCustomStart(e.target.value)} className="h-8 text-xs w-36 bg-background border-border" />
                  </div>
                  <div className="flex flex-col gap-1">
                    <label className="text-[10px] text-muted-foreground">End Date</label>
                    <Input type="date" value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="h-8 text-xs w-36 bg-background border-border" />
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        {selectedLiver && (
          <>
            {/* KPI cards */}
            <div className="grid grid-cols-1 gap-3">
              <KpiCard title="Total Items Sold" value={totalItems.toString()} subtitle="Delivered + Paid/DP but Item Hold" />
              <KpiCard title="Total Grams Sold" value={`${totalGrams.toFixed(2)}g`} subtitle="Excl. Per PC / Screw Type / Diamond" />
              <KpiCard title="Total Sales Value" value={`AED ${totalSalesValue.toFixed(2)}`} subtitle="Sum of item prices (AED)" highlight />
            </div>

            {/* Toggle Breakdown */}
            <Button
              variant="outline"
              size="sm"
              className="w-full h-9 text-xs border-primary/40 text-primary"
              onClick={() => setShowBreakdown(v => !v)}
            >
              {showBreakdown ? <ChevronUp className="h-3.5 w-3.5 mr-1.5" /> : <ChevronDown className="h-3.5 w-3.5 mr-1.5" />}
              {showBreakdown ? 'Hide' : 'Show'} Detailed Breakdown
            </Button>

            {/* Breakdown by date */}
            {showBreakdown && (
              <div className="rounded-lg border border-border overflow-hidden">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="bg-secondary/40 border-b border-border">
                      <th className="text-left px-3 py-2 text-muted-foreground font-medium">Date</th>
                      <th className="text-right px-3 py-2 text-muted-foreground font-medium">Items</th>
                      <th className="text-right px-3 py-2 text-muted-foreground font-medium">Total Grams</th>
                      <th className="text-right px-3 py-2 text-muted-foreground font-medium">Sales Value (AED)</th>
                    </tr>
                  </thead>
                  <tbody>
                    {breakdownByDate.map(([date, rows], i) => (
                      <tr key={date} className={`border-b border-border/40 ${i % 2 === 0 ? '' : 'bg-secondary/10'}`}>
                        <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{date ? formatDate(date) : '—'}</td>
                        <td className="px-3 py-2 text-right font-medium">{rows.length}</td>
                        <td className="px-3 py-2 text-right">{calcGrams(rows).toFixed(2)}g</td>
                        <td className="px-3 py-2 text-right font-medium text-primary">
                          {rows.reduce((s, r) => s + calcItemPriceAED(r), 0).toFixed(2)}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="bg-secondary/30 border-t border-border font-semibold">
                      <td className="px-3 py-2 text-xs text-muted-foreground">Totals</td>
                      <td className="px-3 py-2 text-right text-xs">{totalItems}</td>
                      <td className="px-3 py-2 text-right text-xs">{totalGrams.toFixed(2)}g</td>
                      <td className="px-3 py-2 text-right text-xs text-primary">{totalSalesValue.toFixed(2)}</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}

            {/* Read-only records table */}
            {filtered.length === 0 ? (
              <div className="text-center py-12 border border-dashed border-border rounded-xl">
                <p className="text-sm text-muted-foreground">No delivered or held items found.</p>
              </div>
            ) : (
              <div className="rounded-lg border border-border overflow-hidden">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="bg-secondary/40 border-b border-border">
                      <th className="text-left px-3 py-2 text-muted-foreground font-medium">Date</th>
                      <th className="text-left px-3 py-2 text-muted-foreground font-medium">Client</th>
                      <th className="text-left px-3 py-2 text-muted-foreground font-medium hidden sm:table-cell">Item</th>
                      <th className="text-left px-3 py-2 text-muted-foreground font-medium hidden sm:table-cell">Category</th>
                      <th className="text-right px-3 py-2 text-muted-foreground font-medium">Grams</th>
                      <th className="text-left px-3 py-2 text-muted-foreground font-medium">Status</th>
                      <th className="text-right px-3 py-2 text-muted-foreground font-medium">Amount</th>
                    </tr>
                  </thead>
                  <tbody>
                    {filtered.map((r, i) => (
                      <tr key={r.id} className={`border-b border-border/40 ${i % 2 === 0 ? '' : 'bg-secondary/10'}`}>
                        <td className="px-3 py-2 text-muted-foreground whitespace-nowrap">{r.dateOfLive ? formatDate(r.dateOfLive) : '—'}</td>
                        <td className="px-3 py-2 font-medium max-w-[100px] truncate">{r.minerName || '—'}</td>
                        <td className="px-3 py-2 text-muted-foreground max-w-[140px] truncate hidden sm:table-cell">{r.itemDescription || '—'}</td>
                        <td className="px-3 py-2 text-muted-foreground hidden sm:table-cell">{r.category || '—'}</td>
                        <td className="px-3 py-2 text-right">{r.grams ? `${r.grams}g` : '—'}</td>
                        <td className="px-3 py-2"><StatusBadge status={r.status || '—'} /></td>
                        <td className="px-3 py-2 text-right font-medium text-primary">AED {calcItemPriceAED(r).toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot>
                    <tr className="bg-secondary/30 border-t border-border font-semibold">
                      <td colSpan={4} className="px-3 py-2 text-xs text-muted-foreground">Totals ({totalItems} items)</td>
                      <td className="px-3 py-2 text-right text-xs">{totalGrams.toFixed(2)}g</td>
                      <td className="px-3 py-2" />
                      <td className="px-3 py-2 text-right text-xs text-primary">AED {totalSalesValue.toFixed(2)}</td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}
          </>
        )}

        {!selectedLiver && (
          <div className="text-center py-16 border border-dashed border-border rounded-xl">
            <p className="text-sm text-muted-foreground">Select your name above to view your sales dashboard.</p>
          </div>
        )}
      </div>
    </div>
  );
}

