  onClose: () => void;
}

const CURRENCIES = ['PHP', 'AED', 'USD'];

export default function InvoiceModal({ records, onClose }: Props) {
  const printRef = useRef<HTMLDivElement>(null);
  const [isCopying, setIsCopying] = useState(false);

  useEffect(() => {
    if (!document.getElementById('html2canvas-script') && !(window as any).html2canvas) {
      const script = document.createElement('script');
      script.id = 'html2canvas-script';
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';
      script.async = true;
      document.head.appendChild(script);
    }
  }, []);

  const activeRecords = useMemo(() => {
    const excludedStatuses = ['Cancelled', 'Returned Item'];
    return records
      .filter(r => !excludedStatuses.includes(r.status || ''))
      .sort((a, b) => {
        const dateA = a.dateOfLive ? (parseDateRobust(a.dateOfLive)?.getTime() || 0) : 0;
        const dateB = b.dateOfLive ? (parseDateRobust(b.dateOfLive)?.getTime() || 0) : 0;
        return dateA - dateB;
      });
  }, [records]);

  const baseRecord = activeRecords[0] || records[0];
  const [currency, setCurrency] = useState(baseRecord?.currency || 'PHP');

  const handlePrint = () => {
    const content = printRef.current?.innerHTML || '';
    const win = window.open('', '_blank');
    if (!win) return;
    win.document.write(`<!DOCTYPE html><html><head><title>Invoice - ${baseRecord?.minerName || ''}</title>
      <style>
        @page { size: A4; margin: 12mm; }
        body { margin: 0; padding: 0; background: #fff; font-family: Arial, sans-serif; }
        * { box-sizing: border-box; }
        img { max-width: 100%; }
      </style>
    </head><body>${content}</body></html>`);
    win.document.close();
    setTimeout(() => win.print(), 400);
  };

  const handleCopyImage = async () => {
    if (activeRecords.length === 0 || !printRef.current) return;

    const html2canvas = (window as any).html2canvas;
    if (!html2canvas) {
      toast.error('The image tool is still loading. Please try again in a few seconds.');
      return;
    }

    setIsCopying(true);
    toast.info('Generating image, please wait...');

    try {
      const makeImagePromise = async (): Promise<Blob> => {
        const canvas = await html2canvas(printRef.current!, {
          scale: 2, 
          useCORS: true, 
          backgroundColor: '#ffffff',
          scrollY: 0,
          windowHeight: printRef.current?.scrollHeight || window.innerHeight
        });
        return new Promise<Blob>((resolve, reject) => {
          canvas.toBlob((blob: Blob | null) => {
            if (blob) resolve(blob);
            else reject(new Error('Failed to generate image blob'));
          }, 'image/png');
        });
      };

      await navigator.clipboard.write([
        new ClipboardItem({
          'image/png': makeImagePromise()
        })
      ]);
      toast.success('Invoice image copied! You can now paste it into Meta Business Suite.');
    } catch (error: any) {
      console.error(error);
      if (error.name === 'NotAllowedError') {
         toast.error('Clipboard permission denied. Please allow clipboard access in your browser settings.');
      } else {
         toast.error('Failed to copy image. Try again.');
      }
    } finally {
      setIsCopying(false);
    }
  };

  return (
    <Dialog open onOpenChange={onClose}>
      <DialogContent className="max-w-3xl max-h-[92vh] overflow-y-auto bg-white border-border p-0" aria-describedby={undefined}>
        <DialogHeader className="px-4 pt-4 pb-2 border-b border-border">
          <div className="flex items-center justify-between gap-4">
            <DialogTitle className="text-base font-bold text-foreground">
              Statement of Account (Active)
            </DialogTitle>
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-2">
                <span className="text-xs text-muted-foreground font-medium">Currency:</span>
                <Select value={currency} onValueChange={setCurrency}>
                  <SelectTrigger className="h-8 w-24 text-xs">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {CURRENCIES.map(c => (
                      <SelectItem key={c} value={c}>{c}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <Button
                onClick={handleCopyImage}
                size="sm"
                variant="outline"
                className="h-8 border-blue-600 text-blue-700 hover:bg-blue-50"
                disabled={activeRecords.length === 0 || isCopying}
              >
                {isCopying ? <Loader2 className="h-3.5 w-3.5 mr-1.5 animate-spin" /> : <Copy className="h-3.5 w-3.5 mr-1.5" />}
                {isCopying ? 'Copying...' : 'Copy Image'}
              </Button>

              <Button onClick={handlePrint} size="sm" className="h-8 bg-primary text-primary-foreground" disabled={activeRecords.length === 0}>
                <Printer className="h-3.5 w-3.5 mr-1.5" /> Print / PDF
              </Button>
            </div>
          </div>
        </DialogHeader>

        {activeRecords.length === 0 && (
          <div className="p-8 text-center text-muted-foreground flex flex-col items-center">
            <AlertCircle className="h-8 w-8 text-amber-500 mb-2" />
            <p className="font-semibold text-amber-600">No Active Items</p>
            <p className="text-xs">This client's items have all been Delivered, Dispatched, or Cancelled.</p>
          </div>
        )}

        {activeRecords.length > 0 && (
          <div className="overflow-x-auto">
            <div ref={printRef} className="min-w-[640px] p-4 bg-white">
              <InvoicePrintContent records={activeRecords} currency={currency} />
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

src/api/generateInvoiceNumber.ts.content:
import { z } from 'zod';
import { createEndpoint, Database, DatabaseRowType } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  description: 'Generate a deterministic invoice number safely without memory exhaustion',
  authenticated: true,
  inputSchema: z.object({
    prefix: z.string().length(6),
    recordId: z.number(),
    dateOfLive: z.string(),
    minerName: z.string(),
  }),
  outputSchema: z.object({
    invoiceNumber: z.string(),
  }),
  execute: async ({ input }) => {
    const { prefix, dateOfLive, minerName } = input;

    // Memory Crash Prevention: Fetch in constrained chunks and discard unrelated rows
    const BATCH_SIZE = 500;
    const sameDateRecords: DatabaseRowType[] = [];
    let offset = 0;

    while (true) {
      const batch = await Database.findAll({ offset, limit: BATCH_SIZE });
      if (!batch || batch.length === 0) break;

      for (const r of batch) {
        if (r.dateOfLive === dateOfLive) {
          sameDateRecords.push(r);
        }
      }

      if (batch.length < BATCH_SIZE) break;
      offset += BATCH_SIZE;
    }

    // Group records by minerName, mapping the earliest row ID per client
    const clientMap = new Map<string, { minId: number }>();
    for (const r of sameDateRecords) {
      const key = (r.minerName || '').toLowerCase().trim();
      if (!key) continue;

      const existing = clientMap.get(key);
      if (!existing) {
        clientMap.set(key, { minId: r.id });
      } else if (r.id < existing.minId) {
        existing.minId = r.id;
      }
    }

    // Sort clients deterministically by their earliest record ID
    const sortedClients = Array.from(clientMap.entries())
      .sort((a, b) => a[1].minId - b[1].minId);

    const myKey = minerName.toLowerCase().trim();
    const clientIndex = sortedClients.findIndex(([key]) => key === myKey);

    const seq = clientIndex === -1 ? sortedClients.length + 1 : clientIndex + 1;
    return { invoiceNumber: `${prefix}${String(seq).padStart(3, '0')}` };
  },
});

