import { DatabaseRowType } from '@/types';
import { calcShippingFee, calcCCFee, clientRateAED, isPcItem, getQty, getSilverRate, calcTotalPaid } from '@/lib/calculations';
import { getPhpRate } from '@/lib/phpRateStore'; 
import { numberToWords } from '@/lib/numberToWords';
import { formatDate } from '@/lib/formatters';

interface Props {
  records: DatabaseRowType[];
  currency: string;
}

const LOGO_URL = 'https://wsrv.nl/?url=images.fillout.com/orgid-614156/flowpublicid-6ydzrkprmt/widgetid-default/mVy86cbPRgBbVeiVpWrXgn/pasted-image-1772870436282.png';

const NOTES = [
  'We can hold unpaid items for a maximum of 3 days from the invoice date.',
  'Failure to settle within 3 days may result in additional charges.',
  'Unpaid items will be automatically cancelled after the grace period without prior notice.',
  'All items undergo strict quality checking before dispatch.',
  'An unboxing video is strictly required. No video, no refund, no exchange.',
  'No cash refund. Store credit only.',
];

const n = (v: unknown) => parseFloat(String(v ?? 0)) || 0;
const rnd = (v: number) => Math.round(v);

export default function InvoicePrintContent({ records, currency }: Props) {
  const first = records[0];

  const phpRate = getPhpRate(first?.dateOfLive || '') || 16.7;

  const convertFromAED = (aedValue: number): number => {
    if (currency === 'PHP') return aedValue * phpRate;
    if (currency === 'USD') return aedValue / 3.67;
    return aedValue; 
  };

  const fmtAmt = (v: number) =>
    `${currency} ${rnd(v).toLocaleString('en-US')}`;

  const items = records.map(r => {
    const category = (r.category || '').toLowerCase().trim();
    const isScrewType = category.includes('screw type');
    const isPerPc = category.includes('per pc');
    const isSilver = category === 'silver';
    const isSilverBranded = category === 'silver branded';
    const isPc = isPcItem(r);
    const gramsValue = n(r.grams);
    const qtyValue = getQty(r);

    let trueAedRate = 0;
    if (isSilver || isSilverBranded) {
      trueAedRate = n(r.clientRate) > 0 ? clientRateAED(r) : getSilverRate(category, r)!;
    } else {
      trueAedRate = clientRateAED(r);
    }

    const displayRate = rnd(convertFromAED(trueAedRate));

    let amount: number;
    if (isScrewType || isPerPc) {
      amount = rnd(displayRate * qtyValue);
    } else if (isPc || gramsValue === 0) {
      amount = displayRate;
    } else {
      amount = rnd(displayRate * gramsValue);
    }

    let gramsDisplay = '';
    if (isScrewType || isPerPc) {
      gramsDisplay = `${qtyValue} PC${qtyValue > 1 ? 'S' : ''}`;
    } else {
      gramsDisplay = (isPc || gramsValue === 0) ? 'PC' : gramsValue.toFixed(2);
    }

    return {
      code: r.orderId || '—',
      desc: r.itemDescription || '—',
      tog: r.tog || r.category || '—',
      gramsDisplay,
      isPc: (isPc || isScrewType || isPerPc),
      rate: displayRate,
      amount,
      liver: r.liverName?.trim() || '',
      date: formatDate(r.dateOfLive) 
    };
  });

  const subtotal = items.reduce((s, i) => s + i.amount, 0);
  const shippingAED = first ? calcShippingFee(first) : 0;
  const shipping = rnd(convertFromAED(shippingAED));
  const additionalAED = n(first?.additionalCharges);
  const additional = rnd(convertFromAED(additionalAED));
  const ccFeeAED = first ? calcCCFee(first) : 0;
  const ccFee = rnd(convertFromAED(ccFeeAED));
  const total = subtotal + shipping + additional + ccFee;

  const totalPaidAED = records.reduce((s, r) => s + calcTotalPaid(r), 0);
  const totalPaidConverted = rnd(convertFromAED(totalPaidAED));
  const balanceDue = total - totalPaidConverted;

  const totalGrams = records.reduce((s, r) => {
    const cat = (r.category || '').toLowerCase();
    if (cat.includes('screw type') || cat.includes('per pc') || cat.includes('diamond')) return s;
    return s + n(r.grams);
  }, 0);

  const amountForWords = Math.max(0, totalPaidConverted > 0 ? balanceDue : total);
  const amountInWords = numberToWords(amountForWords, currency);

  const mopLabel = (() => {
    const mop = (first?.modeOfPayment || '').trim();
    if (!mop) return null;
    return mop.toUpperCase();
  })();

  const invoiceDate = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
  const invoiceNo = records.map(r => r.pureWeight).find(Boolean);

  const summaryRows: { label: string; value: string; red?: boolean }[] = [
    { label: 'TOTAL GRAMS', value: totalGrams > 0 ? totalGrams.toFixed(2) : '—' },
    { label: 'SHIPPING', value: shipping > 0 ? fmtAmt(shipping) : 'FREE' },
    ...(additional > 0 ? [{ label: 'ADDITIONAL CHARGES', value: fmtAmt(additional) }] : []),
    ...(ccFee > 0 ? [{ label: 'CC SURCHARGE', value: fmtAmt(ccFee) }] : []),
    { label: 'SUBTOTAL', value: fmtAmt(subtotal) },
    { label: 'TOTAL INVOICE AMOUNT', value: fmtAmt(total) },
    ...(totalPaidConverted > 0 ? [
      { label: 'TOTAL PAID', value: `- ${fmtAmt(totalPaidConverted)}`, red: true },
      { label: 'BALANCE DUE', value: fmtAmt(balanceDue), red: true },
    ] : []),
  ];

  const emptyRows = Math.max(0, 7 - items.length);

  return (
    <div style={{ position: 'relative', fontFamily: 'Arial, sans-serif', color: '#111', background: '#fff', fontSize: 12 }}>

      <div style={{
        position: 'absolute',
        top: '40%',
        left: '50%',
        transform: 'translate(-50%, -50%) rotate(-35deg)',
        fontSize: '65px',
        color: 'rgba(150, 150, 150, 0.12)',
        fontWeight: 900,
        whiteSpace: 'nowrap',
        pointerEvents: 'none',
        zIndex: 0,
        userSelect: 'none',
        textAlign: 'center'
      }}>
        MYKABAYAN OFFICIAL<br/>
        {invoiceNo || ''}
      </div>

      <div style={{ position: 'relative', zIndex: 1 }}>
        <div style={{ textAlign: 'center', border: '1px solid #999', padding: '4px', marginBottom: 0, background: '#fff' }}>
          <em style={{ fontSize: 14 }}>Statement of Account</em>
        </div>

        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'transparent' }}>
          <tbody>
            <tr>
              <td style={{ width: '65%', padding: '12px 16px', verticalAlign: 'top', border: '1px solid #999' }}>
                <div style={{ fontWeight: 900, fontSize: 24, letterSpacing: 1 }}>MYKABAYAN JEWELLERY</div>
                <div style={{ marginTop: 8, textAlign: 'left', fontSize: 11 }}>SATWA, DUBAI, UNITED ARAB EMIRATES</div>
                <div style={{ marginTop: 4, fontSize: 11 }}>WhatsApp &amp; Contact no.: +971 52 825 2405</div>
              </td>
              <td style={{ width: '35%', padding: '12px 16px', verticalAlign: 'middle', textAlign: 'center', border: '1px solid #999' }}>
                <img src={LOGO_URL} crossOrigin="anonymous" alt="Logo" style={{ width: '80px', height: '80px', objectFit: 'contain', display: 'block', margin: '0 auto' }} />
              </td>
            </tr>
            <tr>
              <td style={{ padding: '10px 16px', verticalAlign: 'middle', border: '1px solid #999' }}>
                <div style={{ fontWeight: 700, fontSize: 20, textAlign: 'center', letterSpacing: 1 }}>
                  {(first?.minerName || '').toUpperCase()}
                </div>
              </td>
              <td style={{ padding: '8px', textAlign: 'center', border: '1px solid #999' }}>
                <div style={{ fontWeight: 600, fontSize: 13 }}>{invoiceDate}</div>
                <div style={{ fontSize: 11, marginTop: 4 }}>Date Printed</div>
                {invoiceNo && (
                  <div style={{ marginTop: 8, borderTop: '1px solid #ccc', paddingTop: 6 }}>
                    <div style={{ fontWeight: 700, fontSize: 13, fontFamily: 'monospace', color: '#c00' }}>{invoiceNo}</div>
                    <div style={{ fontSize: 10, color: '#666', marginTop: 2 }}>Account ID / Invoice #</div>
                  </div>
                )}
              </td>
            </tr>
          </tbody>
        </table>

        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'transparent' }}>
          <thead>
            <tr style={{ background: 'rgba(224, 224, 224, 0.9)' }}>
              {['Date', 'Item Description', 'T.O.G', 'Grams/Qty', 'Rate', 'Amount'].map(h => (
                <th key={h} style={{ border: '1px solid #999', padding: '6px 8px', textAlign: 'center', fontSize: 11 }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {items.map((item, i) => (
              <tr key={i}>
                <td style={{ border: '1px solid #999', padding: '5px 8px', textAlign: 'center', fontSize: 11, color: '#666' }}>{item.date}</td>
                <td style={{ border: '1px solid #999', padding: '5px 8px', textAlign: 'center', fontSize: 11, fontWeight: 600 }}>
                  {item.desc.toUpperCase()}
                  {item.liver && <div style={{ fontSize: 9, fontWeight: 400, color: '#888', marginTop: 2 }}>Liver: {item.liver}</div>}
                </td>
                <td style={{ border: '1px solid #999', padding: '5px 8px', textAlign: 'center', fontSize: 11 }}>{item.tog.toUpperCase()}</td>
                <td style={{ border: '1px solid #999', padding: '5px 8px', textAlign: 'center', fontSize: 11, color: item.isPc ? 'red' : '#111', fontWeight: item.isPc ? 700 : 400 }}>
                  {item.gramsDisplay}
                </td>
                <td style={{ border: '1px solid #999', padding: '5px 8px', textAlign: 'center', fontSize: 11 }}>{item.rate.toLocaleString('en-US')}</td>
                <td style={{ border: '1px solid #999', padding: '5px 8px', textAlign: 'right', fontSize: 11 }}>{fmtAmt(item.amount)}</td>
              </tr>
            ))}
            {Array.from({ length: emptyRows }).map((_, i) => (
              <tr key={`empty-${i}`} style={{ height: 22 }}>
                {[1,2,3,4,5,6].map(c => <td key={c} style={{ border: '1px solid #999' }}>&nbsp;</td>)}
              </tr>
            ))}
          </tbody>
        </table>

        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'transparent' }}>
          <tbody>
            <tr>
              <td style={{ width: '50%', padding: '16px', verticalAlign: 'middle', border: '1px solid #999' }}>
                <div style={{ fontWeight: 900, fontSize: 26, lineHeight: 1.2, textAlign: 'center' }}>
                  CUSTOMER'S INVOICE<br />COPY
                </div>
                {mopLabel && (
                  <div style={{ marginTop: '8px', textAlign: 'center' }}>
                    <div style={{ display: 'inline-block', border: '2px solid red', color: 'red', padding: '4px 12px', fontWeight: 900, fontSize: '18px', letterSpacing: '2px', textTransform: 'uppercase' }}>
                      {mopLabel}
                    </div>
                  </div>
                )}
              </td>
              <td style={{ padding: 0, verticalAlign: 'top', border: '1px solid #999' }}>
                {summaryRows.map((row, i) => (
                  <div key={i} style={{ display: 'flex', justifyContent: 'space-between', background: row.red ? 'rgba(255, 240, 240, 0.9)' : (i % 2 === 0 ? 'rgba(224, 224, 224, 0.9)' : 'rgba(245, 245, 245, 0.9)'), padding: '5px 10px', borderBottom: '1px solid #ccc' }}>
                    <span style={{ fontWeight: 700, fontSize: 11, color: row.red ? '#cc0000' : '#111' }}>{row.label}</span>
                    <span style={{ fontSize: 11, fontWeight: row.red ? 700 : 400, color: row.red ? '#cc0000' : '#111' }}>{row.value}</span>
                  </div>
                ))}
              </td>
            </tr>
          </tbody>
        </table>

        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'transparent' }}>
          <tbody>
            <tr>
              <td style={{ padding: '4px 12px', border: '1px solid #999', borderBottom: 'none' }}>
                <span style={{ color: 'red', fontWeight: 700, fontSize: 11 }}>Amount in Words:</span>
              </td>
            </tr>
            <tr>
              <td style={{ padding: '4px 12px 10px', textAlign: 'center', fontWeight: 700, fontSize: 13, border: '1px solid #999' }}>
                {amountInWords}
              </td>
            </tr>
          </tbody>
        </table>

        <div style={{ padding: '8px 12px', border: '1px solid #999', marginTop: -1, background: '#fff' }}>
          <div style={{ color: 'red', fontWeight: 700, fontSize: 12, marginBottom: 4 }}>NOTE:</div>
          {NOTES.map((note, i) => (
            <div key={i} style={{ fontSize: 10, marginBottom: 2 }}>{i + 1}. {note}</div>
          ))}
        </div>
      </div>
    </div>
  );
}

src/components/UploadMasterlistFAB.tsx.content:
import { useState, useRef } from 'react';
import { Upload, X, Loader2, CheckCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from '@/components/ui/sheet';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { uploadFile } from 'zite-file-upload-sdk';
import { createUpload } from 'zite-endpoints-sdk';

interface Props {
  onRefresh: () => void;
}

export default function UploadMasterlistFAB({ onRefresh }: Props) {
  const [open, setOpen] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleUpload = async () => {
    if (!selectedFile) { toast.error('Please select a file'); return; }
    setUploading(true);
    try {
      const { fileUrl } = await uploadFile({ data: selectedFile, filename: selectedFile.name });
      await createUpload({ masterlistFile: fileUrl, status: 'Uploaded' });
      toast.success('File uploaded successfully! Refresh the records when processing is complete.');
      setOpen(false);
      setSelectedFile(null);
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Upload failed');
    } finally {
      setUploading(false);
    }
  };

  return (
    <Sheet open={open} onOpenChange={setOpen}>
      <SheetTrigger asChild>
        <Button size="sm" className="h-7 px-2 text-[10px] sm:text-xs bg-primary text-primary-foreground cursor-pointer">
          <Upload className="h-3 w-3 sm:mr-1" />
          <span className="hidden sm:inline">Upload Masterlist</span>
          <span className="sm:hidden">Upload</span>
        </Button>
      </SheetTrigger>

      <SheetContent side="bottom" className="bg-card border-border pb-8">
        <SheetHeader className="mb-4">
          <SheetTitle className="font-cinzel text-primary">Upload Masterlist</SheetTitle>
        </SheetHeader>
        <div className="space-y-4">
          <div>
            <Label className="text-sm text-muted-foreground mb-2 block">Select Excel / CSV File</Label>
            <div
              className="border-2 border-dashed border-border rounded-lg p-6 text-center cursor-pointer"
              onClick={() => fileRef.current?.click()}
            >
              {selectedFile ? (
                <div className="flex items-center justify-center gap-2">
                  <CheckCircle className="h-4 w-4 text-primary" />
                  <span className="text-sm text-foreground">{selectedFile.name}</span>
                  <button onClick={e => { e.stopPropagation(); setSelectedFile(null); }}>
                    <X className="h-4 w-4 text-muted-foreground" />
                  </button>
                </div>
              ) : (
                <div>
                  <Upload className="h-8 w-8 text-muted-foreground mx-auto mb-2" />
                  <p className="text-sm text-muted-foreground">Tap to select file</p>
                </div>
              )}
            </div>
            <input ref={fileRef} type="file" className="hidden" onChange={e => setSelectedFile(e.target.files?.[0] || null)} />
          </div>
          <Button onClick={handleUpload} disabled={uploading || !selectedFile} className="w-full bg-primary text-primary-foreground">
            {uploading ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" /> Uploading...</> : 'Upload File'}
          </Button>
        </div>
      </SheetContent>
    </Sheet>
  );
}

src/components/admin/AdminPipeline.tsx.content:
import { useMemo, useState } from 'react';
import { ChevronDown, Layout, Crown, BookOpen, Plus, Calendar, Clock, PauseCircle } from 'lucide-react';
import { TabProps, DatabaseRowType } from '@/types';
import { applySearch, groupByMiner, groupByMinerName, formatDate } from '@/lib/formatters';
import TabHeader from '@/components/TabHeader';
import AdminClientCard from './AdminClientCard';
import ReviewChasingCard from './ReviewChasingCard';
import AddClientModal from '@/components/accounts/AddClientModal';
import { Button } from '@/components/ui/button';

export default function AdminPipeline({ records, searchQuery, onSearchChange, onUpdate, userEmail, userFirstName, onRefresh }: TabProps) {
  const [expandedPages, setExpandedPages] = useState<Record<string, boolean>>({});
  const [expandedResellers, setExpandedResellers] = useState<Record<string, boolean>>({});
  const [expandedReviewChasing, setExpandedReviewChasing] = useState<Record<string, boolean>>({});
  const [expandedWFDP, setExpandedWFDP] = useState<Record<string, boolean>>({});
  const [expandedDates, setExpandedDates] = useState<Record<string, boolean>>({});
  const [showAddModal, setShowAddModal] = useState(false);

  const pageGroups = useMemo(() => {
    const searched = applySearch(records, searchQuery);

    // FIX: The 3-day restriction is removed. Delivered items stay forever UNTIL explicitly skipped or completed.
    const activeAdminRecords = searched.filter(r => {
      const status = r.status || '';
      if (status === 'Pending' || status === 'Waiting for Details' || status === 'Waiting for Downpayment') return true;
      if (status === 'Reseller') return true;
      if (status === 'Paid/DP but Item Hold') return true;
      if (status === 'Payment for Verification') return true;
      if (status === 'Delivered') {
        if (r.reviewChasing === 'Skipped' || r.reviewChasing === 'Completed') return false;
        return true; 
      }
      return false;
    });

    const groups: Record<string, DatabaseRowType[]> = {};
    activeAdminRecords.forEach(r => {
      let pageKey = (r.page || 'Other').trim();
      if (pageKey.toUpperCase().includes('MYK')) pageKey = 'MYK';
      else if (pageKey.toUpperCase().includes('EMPIRE')) pageKey = 'Empire Gold By ETG';
      if (!groups[pageKey]) groups[pageKey] = [];
      groups[pageKey].push(r);
    });

    return Object.keys(groups)
      .sort((a, b) => {
        if (a === 'MYK') return -1; if (b === 'MYK') return 1;
        if (a === 'Empire Gold By ETG') return -1; if (b === 'Empire Gold By ETG') return 1;
        return a.localeCompare(b);
      })
      .reduce((acc, key) => { acc[key] = groups[key]; return acc; }, {} as Record<string, DatabaseRowType[]>);
  }, [records, searchQuery]);

  const togglePage = (page: string) =>
    setExpandedPages(prev => ({ ...prev, [page]: !prev[page] }));

  const toggleDate = (key: string) =>
    setExpandedDates(prev => ({ ...prev, [key]: !prev[key] }));

  const groupMinedByDate = (minedItems: DatabaseRowType[]): Map<string, Map<string, DatabaseRowType[]>> => {
    const byDate = new Map<string, Map<string, DatabaseRowType[]>>();
    for (const r of minedItems) {
      const date = r.dateOfLive || 'Unknown Date';
      const miner = r.minerName?.trim() || 'Unknown Client';
      if (!byDate.has(date)) byDate.set(date, new Map());
      const byMiner = byDate.get(date)!;
      if (!byMiner.has(miner)) byMiner.set(miner, []);
      byMiner.get(miner)!.push(r);
    }
    return new Map([...byDate.entries()].sort((a, b) => b[0].localeCompare(a[0])));
  };

  const renderPageSection = (pageName: string, pageRecords: DatabaseRowType[]) => {
    const isExpanded = expandedPages[pageName] === true;
    const minedItems = pageRecords.filter(r =>
      r.status === 'Pending' || r.status === 'Waiting for Details'
    );
    const wfdpItems = pageRecords.filter(r => r.status === 'Waiting for Downpayment');
    const resellerItems = pageRecords.filter(r => r.status === 'Reseller');
    const onHoldItems = pageRecords.filter(r => r.status === 'Paid/DP but Item Hold' || r.status === 'Payment for Verification');
    const onHoldByDate = groupMinedByDate(onHoldItems);
    const reviewChasingItems = pageRecords.filter(r => r.status === 'Delivered');
    const minedByDate = groupMinedByDate(minedItems);
    const wfdpByDate = groupMinedByDate(wfdpItems);
