                              <span className="text-[10px] font-bold bg-indigo-400/20 text-indigo-400 px-2 py-0.5 rounded-md">{totalItems}</span>
                              <ChevronDown className={`h-4 w-4 text-indigo-400 transition-transform duration-200 ${isDateExpanded ? 'rotate-180' : ''}`} />
                            </div>
                            {isDateExpanded && (
                              <div className="pl-2 animate-in fade-in slide-in-from-top-1 duration-200">
                                {Array.from(minerMap.entries()).map(([name, items]) => (
                                  <AdminClientCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} userEmail={userEmail} />
                                ))}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })()}

            {resellerGrouped.size > 0 && (() => {
              const isResellerExpanded = expandedResellers[pageName] === true;
              return (
                <div>
                  <div
                    className="flex items-center gap-2 mb-4 cursor-pointer"
                    onClick={() => setExpandedResellers(prev => ({ ...prev, [pageName]: prev[pageName] === undefined ? false : !prev[pageName] }))}
