                    <span className="text-[10px] font-black text-teal-500 uppercase tracking-[0.2em] pl-1">Resellers</span>
                    <div className="h-px flex-1 bg-teal-500/20" />
                    <span className="text-[10px] font-bold bg-teal-500/20 text-teal-500 px-2 py-0.5 rounded-md">{resellerGrouped.size}</span>
                    <ChevronDown className={`h-4 w-4 text-teal-500 transition-transform duration-200 ${isResellerExpanded ? 'rotate-180' : ''}`} />
                  </div>
                  {isResellerExpanded && Array.from(resellerGrouped.entries()).map(([name, items]) => (
                    <AdminClientCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} userEmail={userEmail} />
                  ))}
                </div>
              );
            })()}

            {reviewChasingGroups.size > 0 && (() => {
              const isReviewExpanded = expandedReviewChasing[pageName] === true;
              return (
                <div>
                  <div
                    className="flex items-center gap-2 mb-4 cursor-pointer"
                    onClick={() => setExpandedReviewChasing(prev => ({ ...prev, [pageName]: prev[pageName] === undefined ? false : !prev[pageName] }))}
                  >
                    <span className="text-[10px] font-black text-primary uppercase tracking-[0.2em] pl-1">Review Chasing</span>
                    <div className="h-px flex-1 bg-primary/20" />
                    <span className="text-[10px] font-bold bg-primary/20 text-primary px-2 py-0.5 rounded-md">{reviewChasingGroups.size}</span>
                    <ChevronDown className={`h-4 w-4 text-primary transition-transform duration-200 ${isReviewExpanded ? 'rotate-180' : ''}`} />
                  </div>
                  {isReviewExpanded && (
                    <div className="grid grid-cols-1 gap-3">
                      {Array.from(reviewChasingGroups.entries()).map(([name, items]) => (
                        <ReviewChasingCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} />
                      ))}
                    </div>
                  )}
                </div>
              );
            })()}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader title="Admin Pipeline" subtitle="Active Tasks & Pipeline" searchQuery={searchQuery} onSearchChange={onSearchChange} />
      <div className="px-4 pt-4">
        <div className="flex justify-end mb-4">
          <Button onClick={() => setShowAddModal(true)} className="bg-primary text-primary-foreground hover:bg-primary/90 text-xs h-9 shadow-sm">
            <Plus className="h-4 w-4 mr-1.5" /> Add Client
          </Button>
        </div>
      </div>
      <div className="px-4">
        {Object.keys(pageGroups).length > 0
          ? Object.keys(pageGroups).map(page => renderPageSection(page, pageGroups[page]))
          : (
            <div className="text-center py-24 border-2 border-dashed border-border rounded-2xl">
              <p className="text-sm text-muted-foreground font-medium">No records found matching your search.</p>
            </div>
          )}
      </div>
      {showAddModal && <AddClientModal onClose={() => setShowAddModal(false)} userFirstName={userFirstName} userEmail={userEmail} onRefresh={onRefresh} existingRecords={records} />}
    </div>
  );
}

