import { useMemo, useState } from 'react';
import { ClipboardList, Package, Truck, MapPin, Store, ChevronDown, PauseCircle, Users, Layout, Crown, BookOpen, XCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { TabProps, DatabaseRowType } from '@/types';
import { applySearch, groupByPageDateMiner, formatDate } from '@/lib/formatters';
import CollapsibleGroup from '@/components/CollapsibleGroup';
import TabHeader from '@/components/TabHeader';
import DispatchClientCard from './DispatchClientCard';
import PulloutReport from './PulloutReport';

export default function DispatchBoard({ records, searchQuery, onSearchChange, onUpdate, userEmail }: TabProps) {
  const [showReport, setShowReport] = useState(false);
  const [showPullout, setShowPullout] = useState(false);
  const [showHold, setShowHold] = useState(false);
  const [showReseller, setShowReseller] = useState(false);
  const [showDispatched, setShowDispatched] = useState(false);
  const [showCancelled, setShowCancelled] = useState(false);

  const { forPullout, onHold, reseller, dispatched, cancelled } = useMemo(() => {
    const filtered = records.filter(r => {
      const s = r.status || '';
      if (!['For Pullout', 'Dispatch', 'Dispatched', 'Delivered', 'Given to Shop', 'Paid/DP but Item Hold', 'Payment for Verification', 'Reseller', 'Cancelled'].includes(s)) return false;
      const mos = (r.modeOfSale || '').toLowerCase().trim();
      if (mos === 'in-store' || mos === 'walk-in' || mos === 'walk in') return false;
      return true;
    });
    const searched = applySearch(filtered, searchQuery);
    return {
      forPullout: groupByPageDateMiner(searched.filter(r => r.status === 'For Pullout' || r.status === 'Dispatch')),
      onHold: groupByPageDateMiner(searched.filter(r => r.status === 'Paid/DP but Item Hold' || r.status === 'Payment for Verification')),
      reseller: groupByPageDateMiner(searched.filter(r => r.status === 'Reseller')),
      dispatched: groupByPageDateMiner(searched.filter(r => r.status === 'Dispatched' || r.status === 'Delivered' || r.status === 'Given to Shop')),
      cancelled: groupByPageDateMiner(searched.filter(r => r.status === 'Cancelled')),
    };
  }, [records, searchQuery]);

  const pulloutCount = useMemo(() => records.filter(r => r.status === 'For Pullout' || r.status === 'Dispatch').length, [records]);

  const getPageIcon = (page: string) => {
    if (page === 'MYK') return <Crown className="h-4 w-4 text-yellow-500" />;
    if (page === 'Empire Gold By ETG') return <BookOpen className="h-4 w-4 text-primary" />;
    return <Layout className="h-4 w-4 text-muted-foreground" />;
  };

  const renderGroupedRecords = (groupedData: Map<string, Map<string, Map<string, DatabaseRowType[]>>>) => {
    if (groupedData.size === 0) {
      return <p className="text-xs text-muted-foreground px-1">No items found in this category.</p>;
    }
    return Array.from(groupedData.entries()).map(([page, dateMap]) => {
      const totalItems = Array.from(dateMap.values()).reduce((s, m) => s + Array.from(m.values()).reduce((ss, v) => ss + v.length, 0), 0);
      return (
        <div key={page} className="mb-6">
          <div className="flex items-center gap-2 mb-3 py-2 px-3 bg-secondary/40 rounded-lg border border-primary/10">
            {getPageIcon(page)}
            <h3 className="font-cinzel text-sm text-primary tracking-wide uppercase">{page}</h3>
            <div className="h-px flex-1 bg-primary/10" />
            <span className="text-[10px] font-bold bg-primary/20 text-primary px-2 py-0.5 rounded-md">{totalItems}</span>
          </div>
          <div className="pl-2 sm:pl-4 space-y-2">
            {Array.from(dateMap.entries()).map(([date, minerMap]) => (
              <CollapsibleGroup key={date} label={formatDate(date)} colorClass="text-muted-foreground" lineClass="bg-border/40" indent defaultOpen={false}>
                {Array.from(minerMap.entries()).map(([miner, items]) => (
                  <DispatchClientCard 
                    key={miner} 
                    minerName={miner} 
                    records={items} 
                    allRecords={records} 
                    onUpdate={onUpdate} 
                    userEmail={userEmail} 
                  />
                ))}
              </CollapsibleGroup>
            ))}
          </div>
        </div>
      );
    });
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader
        title="Dispatch Board"
        searchQuery={searchQuery}
        onSearchChange={onSearchChange}
        rightContent={
          <Button variant="outline" size="sm" className="border-border text-xs h-8" onClick={() => setShowReport(true)}>
            <ClipboardList className="h-3.5 w-3.5 mr-1" />
            Report ({pulloutCount})
          </Button>
        }
      />
      <div className="px-4 pt-4">

        <button className="flex w-full items-center gap-2 mb-5 cursor-pointer text-left focus:outline-none" onClick={() => setShowPullout(!showPullout)}>
          <Package className="h-4 w-4 text-purple-400" />
          <span className="font-cinzel text-xs text-purple-400 font-bold">FOR PULLOUT</span>
          <div className="h-px flex-1 bg-purple-400/30" />
          <ChevronDown className={`h-4 w-4 text-purple-400 transition-transform ${showPullout ? 'rotate-180' : ''}`} />
        </button>
        {showPullout && <div className="mb-8 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroupedRecords(forPullout)}</div>}

        <button className="flex w-full items-center gap-2 mb-5 cursor-pointer text-left focus:outline-none" onClick={() => setShowReseller(!showReseller)}>
          <Users className="h-4 w-4 text-teal-400" />
          <span className="font-cinzel text-xs text-teal-400 font-bold">RESELLER</span>
          <div className="h-px flex-1 bg-teal-400/30" />
          <ChevronDown className={`h-4 w-4 text-teal-400 transition-transform ${showReseller ? 'rotate-180' : ''}`} />
        </button>
        {showReseller && <div className="mb-8 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroupedRecords(reseller)}</div>}

        <button className="flex w-full items-center gap-2 mb-5 cursor-pointer text-left focus:outline-none" onClick={() => setShowHold(!showHold)}>
          <PauseCircle className="h-4 w-4 text-indigo-400" />
          <span className="font-cinzel text-xs text-indigo-400 font-bold">PAID/DP BUT ON HOLD</span>
          <div className="h-px flex-1 bg-indigo-400/30" />
          <ChevronDown className={`h-4 w-4 text-indigo-400 transition-transform ${showHold ? 'rotate-180' : ''}`} />
        </button>
        {showHold && <div className="mb-8 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroupedRecords(onHold)}</div>}

        <button className="flex w-full items-center gap-2 mb-5 cursor-pointer text-left focus:outline-none" onClick={() => setShowDispatched(!showDispatched)}>
          <Truck className="h-4 w-4 text-orange-400" />
          <span className="font-cinzel text-xs text-orange-400 font-bold">DISPATCHED / DELIVERED</span>
          <div className="h-px flex-1 bg-orange-400/30" />
          <ChevronDown className={`h-4 w-4 text-orange-400 transition-transform ${showDispatched ? 'rotate-180' : ''}`} />
        </button>
        {showDispatched && <div className="mb-8 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroupedRecords(dispatched)}</div>}

        <button className="flex w-full items-center gap-2 mb-5 cursor-pointer text-left focus:outline-none" onClick={() => setShowCancelled(!showCancelled)}>
          <XCircle className="h-4 w-4 text-destructive" />
          <span className="font-cinzel text-xs text-destructive font-bold">CANCELLED</span>
          <div className="h-px flex-1 bg-destructive/30" />
          <ChevronDown className={`h-4 w-4 text-destructive transition-transform ${showCancelled ? 'rotate-180' : ''}`} />
        </button>
        {showCancelled && <div className="animate-in fade-in slide-in-from-top-2 duration-200">{renderGroupedRecords(cancelled)}</div>}
      </div>

      {showReport && <PulloutReport records={records} onClose={() => setShowReport(false)} />}
    </div>
  );
}

src/components/dispatch/PulloutReport.ts.content:
import { useRef } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Printer } from 'lucide-react';
import { DatabaseRowType } from '@/types';
import { formatDate } from '@/lib/formatters';
import { calcProfitAED } from '@/lib/calculations';

interface Props {
  records: DatabaseRowType[];
  onClose: () => void;
}

function groupBySourceThenMiner(records: DatabaseRowType[]) {
  const grouped = new Map<string, Map<string, DatabaseRowType[]>>();
  for (const r of records) {
    const source = r.source?.trim() || 'Main Store'; 
    const miner = r.minerName?.trim() || 'Unknown Client';

    if (!grouped.has(source)) grouped.set(source, new Map());
    const bySource = grouped.get(source)!;

    if (!bySource.has(miner)) bySource.set(miner, []);
    bySource.get(miner)!.push(r);
  }
  return new Map([...grouped.entries()].sort((a, b) => a[0].localeCompare(b[0])));
}

export default function PulloutReport({ records, onClose }: Props) {
  const printRef = useRef<HTMLDivElement>(null);
  const forPullout = records.filter(r => r.status === 'For Pullout' || r.status === 'Dispatch');
  const grouped = groupBySourceThenMiner(forPullout);

  const handlePrint = () => {
    const content = printRef.current?.innerHTML || '';
    const win = window.open('', '_blank');
    if (!win) return;
    win.document.write(`<html><head><title>Pullout Report</title>
    <link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@700&display=swap" rel="stylesheet">
    <style>
      body { font-family: sans-serif; color: #111; background: #fff; margin: 0; padding: 24px; font-size: 12px; }
      .font-cinzel { font-family: 'Cinzel', serif; font-weight: 700; }
      .internal-banner { border: 2px solid #dc2626; background: #fee2e2; padding: 8px 16px; text-align: center; font-weight: bold; color: #dc2626; margin-bottom: 12px; font-size: 13px; }
      h2 { font-size: 16px; margin-bottom: 4px; }
      table { width: 100%; border-collapse: collapse; margin-bottom: 16px; }
      th { background: #f0f0f0; padding: 6px; text-align: left; font-size: 11px; border-bottom: 2px solid #ccc; }
      th.r, td.r { text-align: right; }
      td { padding: 6px; border-bottom: 1px solid #ddd; }
      .source-header { background: #111; color: #fff; padding: 6px 12px; font-size: 14px; margin-top: 16px; margin-bottom: 8px; border-radius: 4px; }
      .miner-header { border-bottom: 2px solid #C9A84C; padding-bottom: 4px; margin-bottom: 4px; margin-top: 16px; display: flex; justify-content: space-between; align-items: flex-end; }
      .miner-name { font-size: 13px; font-weight: bold; }
      .miner-date { font-size: 11px; color: #666; margin-left: 8px; font-weight: normal; }
    </style></head><body>
    <div class="internal-banner font-cinzel">⚠ INTERNAL PULLOUT — DO NOT SEND TO CLIENT ⚠</div>
    ${content}
    </body></html>`);
    win.document.close();
    win.print();
  };

  return (
    <Dialog open onOpenChange={onClose}>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto bg-card border-border">
        <DialogHeader>
          <DialogTitle className="font-cinzel text-primary">Pullout Report — Internal Use Only</DialogTitle>
        </DialogHeader>

        <div ref={printRef} className="text-sm">
          <div className="border-2 border-destructive rounded-lg px-4 py-2 mb-4 text-center bg-destructive/10 no-print">
            <p className="text-destructive font-bold text-sm tracking-wide">⚠ INTERNAL PULLOUT — DO NOT SEND TO CLIENT ⚠</p>
          </div>

          <p className="text-xs text-muted-foreground mb-4">
            Generated: {new Date().toLocaleString()} · {forPullout.length} items for pullout
          </p>

          {grouped.size === 0 ? (
            <p className="text-center text-muted-foreground py-8">No items with "For Pullout" status.</p>
          ) : (
            Array.from(grouped.entries()).map(([source, byMiner]) => (
              <div key={source} className="mb-8">
                <div className="source-header bg-secondary text-foreground px-3 py-2 rounded-md font-bold mb-2">
                  <span className="font-cinzel text-primary">{source}</span>
                </div>

                {Array.from(byMiner.entries()).map(([miner, items]) => {
                  const totalProfit = items.reduce((s, r) => s + calcProfitAED(r), 0);
                  const firstDate = formatDate(items[0]?.dateOfLive);

                  return (
                    <div key={miner} className="mb-6 pl-2">
                      <div className="miner-header flex justify-between items-end mb-2 pb-1 border-b border-primary/30">
                        <div>
                          <span className="miner-name text-sm font-bold text-foreground">{miner}</span>
                          <span className="miner-date text-xs text-muted-foreground ml-2">Live: {firstDate}</span>
                        </div>
                        <span className="text-xs font-medium text-muted-foreground">
                          {items.length} item{items.length !== 1 ? 's' : ''} · Profit: AED {totalProfit.toFixed(2)}
                        </span>
                      </div>

                      <table className="w-full text-xs">
                        <thead>
                          <tr className="text-muted-foreground">
                            <th className="text-left py-1 font-medium">Item</th>
                            <th className="text-left py-1 font-medium">Cat</th>
                            <th className="text-right py-1 font-medium">Grams</th>
                            <th className="text-right py-1 font-medium">Gold Rate</th>
                            <th className="text-right py-1 font-medium">Profit (AED)</th>
                          </tr>
                        </thead>
                        <tbody>
                          {items.map(r => (
                            <tr key={r.id} className="border-b border-border/40">
                              <td className="py-1.5 pr-2">{r.itemDescription}</td>
                              <td className="py-1.5">{r.category}</td>
                              <td className="py-1.5 text-right">{r.grams ? `${r.grams}g` : 'PC'}</td>
                              <td className="py-1.5 text-right">{r.goldRate ? Number(r.goldRate).toFixed(2) : '—'}</td>
                              <td className="py-1.5 text-right">{calcProfitAED(r).toFixed(2)}</td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  );
                })}
              </div>
            ))
          )}
        </div>

        <Button onClick={handlePrint} className="w-full mt-4 bg-primary text-primary-foreground">
          <Printer className="h-4 w-4 mr-2" /> Print Report
        </Button>
      </DialogContent>
    </Dialog>
  );
}

src/components/accounts/AddClientModal.t.content:
import { useState, useMemo } from 'react';
import { Loader2, CopyPlus, AlertTriangle } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { createRecord } from 'zite-endpoints-sdk';
import { MOP_OPTIONS, REGION_OPTIONS } from '@/lib/formatters';
import { calcItemCostAED, calcItemPriceAED } from '@/lib/calculations';
import { setPhpRate as savePhpRate } from '@/lib/phpRateStore';
import { DatabaseRowType } from '@/types';

function generateCustomerId(): string {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let id = 'CUST-';
  for (let i = 0; i < 5; i++) id += chars[Math.floor(Math.random() * chars.length)];
  return id;
}

function resolveCustomerId(minerName: string, existingRecords: DatabaseRowType[]): string {
  const key = minerName.trim().toLowerCase();
  const match = existingRecords.find(r => r.minerName?.trim().toLowerCase() === key && r.customerId);
  return match?.customerId || generateCustomerId();
}

interface Props {
  onClose: () => void;
  userFirstName?: string;
  userEmail?: string;
  onRefresh?: () => void;
  existingRecords?: DatabaseRowType[];
}

const LOCATION_OPTIONS = ['Local', 'Pinas', 'International'];
const CURRENCY_OPTIONS = ['AED', 'PHP', 'USD'];
const STATUS_OPTIONS = ['Pending', 'Waiting for Details', 'Paid/DP but Item Hold', 'Payment for Verification', 'Reseller', 'Walk-in', 'In-Store'];
const REMITTANCE_OPTIONS = ['Pending Payment', 'Secured via Courier', 'Secured via Bank Transfer', 'Secured via Cash', 'Secured via Tabby', 'Secured via Tamara'];
const CATEGORY_OPTIONS = ['Normal', 'Special Price', 'Special Price EF', 'Silver', 'Silver Branded', 'VCA', 'Per PC', 'Diamond', 'Other'];
const PAGE_OPTIONS = ['MYK', 'EMPIRE GOLD BY ETG'];
const TOG_OPTIONS = ['S-925', '18K', '21K', '24K'];
const MODE_OF_SALE_OPTIONS = ['Live', 'Outsource', 'Dropshipping', 'In-Store', 'Offline', 'Reseller'];
const SOURCE_OPTIONS = ['MYK SHOP', 'CROWN', 'DG', 'MSET SHOP', 'SATWA OFFICE', 'UMAAR SUPPLIER'];

export default function AddClientModal({ onClose, userFirstName, userEmail, onRefresh, existingRecords = [] }: Props) {
  const [saving, setSaving] = useState(false);
  const [phpRate, setPhpRate] = useState('16.6');
  const [form, setForm] = useState({
    minerName: '',
    itemDescription: '',
    category: '',
    mc: '',
    grams: '',
    clientRate: '',
    goldRate: '',
    orderId: '',
    currency: 'AED',
    modeOfPayment: '',
    modeOfSale: '',
    source: '',
    locationOfMiner: 'Local',
    regions: '',
    status: 'Walk-in',
    remittanceStatus: 'Pending Payment',
    dateOfLive: new Date().toISOString().split('T')[0],
    liverName: userFirstName || '',
    page: '',
    tog: '',
    supplierRateOverride: '',
  });

  const set = (key: string, val: string) => setForm(p => ({ ...p, [key]: val }));

  const isManualSupplierRate = form.category === 'Diamond' || form.category === 'Per PC';
  const autoSupplierRate = useMemo(() => {
    const gr = parseFloat(form.goldRate) || 0;
    const mc = parseFloat(form.mc) || 0;
    return gr > 0 || mc > 0 ? (gr + mc).toFixed(2) : '';
  }, [form.goldRate, form.mc]);
  const supplierRate = isManualSupplierRate ? form.supplierRateOverride : autoSupplierRate;

  const getPerPcSupplierRate = (tog: string, category: string) => {
    if (category === 'Per PC') {
      if (tog === 'S-925') return '32';
      return '115';
    }
    return '';
  };

  const handleCategoryChange = (val: string) => {
    let newMc = form.mc;
    let newGoldRate = form.goldRate;
    let newSupplierRateOverride = form.supplierRateOverride;

    if (val === 'Normal') newMc = '16';
    else if (val === 'Special Price') newMc = '21';
    else if (val === 'Special Price EF') newMc = '25';
    else if (val === 'Silver' || val === 'Silver Branded') newMc = '0';
    else if (val === 'Diamond') {
      newMc = '0';
      newGoldRate = '0';
      newSupplierRateOverride = '';
    } else if (val === 'Per PC') {
      newMc = '0';
      newGoldRate = '0';
      newSupplierRateOverride = getPerPcSupplierRate(form.tog, val);
    }
    setForm(p => ({ ...p, category: val, mc: newMc, goldRate: newGoldRate, supplierRateOverride: newSupplierRateOverride }));
  };

  const handleTogChange = (val: string) => {
    const updates: Partial<typeof form> = { tog: val };
    if (form.category === 'Per PC') {
      updates.supplierRateOverride = getPerPcSupplierRate(val, 'Per PC');
    }
    setForm(p => ({ ...p, ...updates }));
  };

  const isDuplicateBarcode = useMemo(() => {
    if (!form.orderId.trim()) return false;
    const target = form.orderId.trim().toUpperCase();
    return existingRecords.some(r => r.orderId?.trim().toUpperCase() === target);
  }, [form.orderId, existingRecords]);

  const handleSave = async (isBulkAdd: boolean) => {
    if (!form.minerName.trim() || !form.itemDescription.trim()) {
      toast.error('Client name and item description are required');
      return;
    }
    if (!form.page) {
      toast.error('Page is required');
      return;
    }
    if (isDuplicateBarcode) {
      toast.error('Cannot save: This Order ID/Barcode already exists in the system.');
      return;
    }

    setSaving(true);

    const finalMinerName = form.minerName.trim().toUpperCase();
    const finalItemDesc = form.itemDescription.trim().toUpperCase();
    const finalOrderId = form.orderId ? form.orderId.trim().toUpperCase() : undefined;

    try {
      const preview: DatabaseRowType = {
        id: 0,
        minerName: finalMinerName,
        itemDescription: finalItemDesc,
        category: form.category,
        mc: form.mc,
        grams: form.grams ? parseFloat(form.grams) : undefined,
        clientRate: form.clientRate ? parseFloat(form.clientRate) : undefined,
        goldRate: form.goldRate ? parseFloat(form.goldRate) : undefined,
        supplierRate: (isManualSupplierRate ? form.supplierRateOverride : supplierRate) || undefined,
        currency: form.currency,
        tog: form.tog || undefined,
      };

      const profit = (calcItemPriceAED(preview) - calcItemCostAED(preview)).toFixed(2);

      const timestamp = new Date().toLocaleString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' });
      const creator = userEmail ? userEmail.split('@')[0] : (form.liverName || 'unknown');
      const auditTrail = `[Created by ${creator} on ${timestamp}]`;
      const customerId = resolveCustomerId(finalMinerName, existingRecords);

      await createRecord({
        fields: {
          minerName: finalMinerName,
          itemDescription: finalItemDesc,
          category: form.category,
          orderId: finalOrderId,
          mc: form.mc ? parseFloat(form.mc) : undefined,
          grams: form.grams ? parseFloat(form.grams) : undefined,
          clientRate: form.clientRate ? parseFloat(form.clientRate) : undefined,
          goldRate: form.goldRate ? parseFloat(form.goldRate) : undefined,
          supplierRate: (isManualSupplierRate ? form.supplierRateOverride : supplierRate) || undefined,
          pureWeight: undefined,
          currency: form.currency,
          modeOfPayment: form.modeOfPayment || undefined,
          modeOfSale: form.modeOfSale || undefined,
          source: form.source || undefined,
          locationOfMiner: form.locationOfMiner,
          regions: form.regions || undefined,
          status: form.status,
          remittanceStatus: form.remittanceStatus,
          dateOfLive: form.dateOfLive,
          liverName: form.liverName || undefined,
          page: form.page,
          tog: form.tog || undefined,
          reviewChasing: 'Pending',
          profit,
          auditTrail,
          customerId,
        },
      });
      if (isPinas && phpRate) {
        savePhpRate(form.dateOfLive, parseFloat(phpRate));
      }

      toast.success(isBulkAdd ? 'Item added! Ready for next item.' : 'Client record created');
      onRefresh?.();

      if (isBulkAdd) {
        setForm(p => ({ 
          ...p, 
          itemDescription: '', 
          grams: '', 
          orderId: '', 
          tog: '', 
          category: '', 
          mc: '', 
          goldRate: '', 
          clientRate: '', 
          supplierRateOverride: '' 
        }));
      } else {
        onClose();
      }

    } catch {
      toast.error('Failed to create record');
    } finally {
      setSaving(false);
    }
  };

  const isPinas = form.locationOfMiner === 'Pinas';

  return (
    <Dialog open onOpenChange={onClose}>
      <DialogContent className="max-w-md bg-card border-border max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="font-cinzel text-primary">Add Client Record</DialogTitle>
        </DialogHeader>

        <div className="space-y-3 text-sm">
          <div className="grid grid-cols-2 gap-2">
            <div className="col-span-2">
              <Label className="text-xs text-muted-foreground">Client Name *</Label>
              <Input value={form.minerName} onChange={e => set('minerName', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border uppercase" placeholder="Miner / Client name" />
            </div>
            <div className="col-span-2">
              <Label className="text-xs text-muted-foreground">Item Description *</Label>
              <Input value={form.itemDescription} onChange={e => set('itemDescription', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border uppercase" placeholder="e.g. GOLD RING 18K" />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Page *</Label>
              <Select value={form.page} onValueChange={v => set('page', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {PAGE_OPTIONS.map(p => <SelectItem key={p} value={p} className="text-xs">{p}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Liver Name</Label>
              <Input value={form.liverName} onChange={e => set('liverName', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="Liver name" />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Category</Label>
              <Select value={form.category} onValueChange={handleCategoryChange}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {CATEGORY_OPTIONS.map(c => <SelectItem key={c} value={c} className="text-xs">{c}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">T.O.G</Label>
              <Select value={form.tog} onValueChange={handleTogChange}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {TOG_OPTIONS.map(t => <SelectItem key={t} value={t} className="text-xs">{t}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            <div className="col-span-2">
              <div className="flex items-center justify-between mb-0.5">
                <Label className="text-xs text-muted-foreground">Order ID / Barcode</Label>
                {isDuplicateBarcode && (
                  <span className="text-[10px] font-bold text-destructive flex items-center animate-pulse">
                    <AlertTriangle className="w-3 h-3 mr-1" /> ALREADY EXISTS
                  </span>
                )}
              </div>
              <Input 
                value={form.orderId} 
                onChange={e => set('orderId', e.target.value)} 
                className={`h-8 text-xs bg-background uppercase transition-colors ${isDuplicateBarcode ? 'border-destructive focus-visible:ring-destructive' : 'border-border'}`} 
                placeholder="e.g. AM-SL-030909" 
              />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Grams (0 = PC)</Label>
              <Input type="number" value={form.grams} onChange={e => set('grams', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0.00" />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">MC (Making Charge)</Label>
              <Input type="number" value={form.mc} onChange={e => set('mc', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0" />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Gold Rate</Label>
              <Input type="number" value={form.goldRate} onChange={e => set('goldRate', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0.00" />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Client Rate</Label>
              <Input type="number" value={form.clientRate} onChange={e => set('clientRate', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0.00" />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">
                Supplier Rate
              </Label>
              {isManualSupplierRate ? (
                <Input
                  type="number"
                  value={form.supplierRateOverride}
                  onChange={e => set('supplierRateOverride', e.target.value)}
                  className="h-8 text-xs mt-0.5 bg-background border-border"
                  placeholder={form.category === 'Diamond' ? 'Enter supplier rate' : '115'}
                />
              ) : (
                <Input value={supplierRate} readOnly className="h-8 text-xs mt-0.5 bg-muted border-border opacity-70 cursor-not-allowed" placeholder="Auto" />
              )}
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Currency</Label>
              <Select value={form.currency} onValueChange={v => set('currency', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {CURRENCY_OPTIONS.map(c => <SelectItem key={c} value={c} className="text-xs">{c}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Mode of Sale</Label>
              <Select value={form.modeOfSale} onValueChange={v => set('modeOfSale', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {MODE_OF_SALE_OPTIONS.map(m => <SelectItem key={m} value={m} className="text-xs">{m}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Source</Label>
              <Select value={form.source} onValueChange={v => set('source', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {SOURCE_OPTIONS.map(s => <SelectItem key={s} value={s} className="text-xs">{s}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Location</Label>
              <Select value={form.locationOfMiner} onValueChange={v => {
                set('locationOfMiner', v);
                if (v === 'Pinas') set('currency', 'PHP');
                else if (v === 'Local') set('currency', 'AED');
              }}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {LOCATION_OPTIONS.map(l => <SelectItem key={l} value={l} className="text-xs">{l}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            {isPinas && (
              <div className="col-span-2 bg-primary/10 border border-primary/20 rounded-lg p-2">
                <Label className="text-xs text-primary font-semibold">PHP Conversion Rate (AED → PHP)</Label>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-xs text-muted-foreground">1 AED =</span>
                  <Input
                    type="number"
                    value={phpRate}
                    onChange={e => setPhpRate(e.target.value)}
                    className="h-7 text-xs bg-background border-border w-24"
                    step="0.1"
                  />
                  <span className="text-xs text-muted-foreground">PHP</span>
                </div>
              </div>
            )}

            {form.locationOfMiner === 'Local' && (
              <div>
                <Label className="text-xs text-muted-foreground">Region</Label>
                <Select value={form.regions} onValueChange={v => set('regions', v)}>
                  <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                  <SelectContent className="bg-popover border-border">
                    {REGION_OPTIONS.map(r => <SelectItem key={r} value={r} className="text-xs">{r}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
            )}

            <div>
              <Label className="text-xs text-muted-foreground">Mode of Payment</Label>
              <Select value={form.modeOfPayment} onValueChange={v => set('modeOfPayment', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {MOP_OPTIONS.map(m => <SelectItem key={m} value={m} className="text-xs">{m}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Status</Label>
              <Select value={form.status} onValueChange={v => set('status', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {STATUS_OPTIONS.map(s => <SelectItem key={s} value={s} className="text-xs">{s}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Remittance Status</Label>
              <Select value={form.remittanceStatus} onValueChange={v => set('remittanceStatus', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {REMITTANCE_OPTIONS.map(r => <SelectItem key={r} value={r} className="text-xs">{r}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div className="col-span-2">
              <Label className="text-xs text-muted-foreground">Date of Live</Label>
              <Input type="date" value={form.dateOfLive} onChange={e => set('dateOfLive', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" />
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <Button variant="outline" className="text-xs h-8 border-border w-20 shrink-0" onClick={onClose}>
              Cancel
            </Button>
            <Button onClick={() => handleSave(true)} disabled={saving || isDuplicateBarcode} variant="secondary" className="flex-1 text-xs h-8 border-border">
              {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <><CopyPlus className="h-3.5 w-3.5 mr-1" /> Save & Add Another</>}
            </Button>
            <Button onClick={() => handleSave(false)} disabled={saving || isDuplicateBarcode} className="flex-1 text-xs h-8 bg-primary text-primary-foreground">
              {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : 'Create Record'}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

src/components/accounts/FinancialsForm.t.content:
import { useState, useEffect } from 'react';
import { Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { DatabaseRowType } from '@/types';
import {
  calcItemPrice, calcItemPriceAED, calcShippingFee, calcCCFee,
  calcTotalPaid, calcProfitAED, roundPrice, getEffectiveCurrency,
  toAED, fromAED, calcRemainingBalance
} from '@/lib/calculations';

interface Props {
  record: DatabaseRowType;
  onUpdate: (rowId: number, fields: Partial<DatabaseRowType>) => Promise<void>;
}

const REMITTANCE_OPTIONS = [
  'Pending Payment', 'Secured via Courier', 'Secured via Bank Transfer',
  'Secured via Cash', 'SECURED VIA TABBY', 'SECURED VIA TAMARA',
];
const MODE_OF_SALE_OPTIONS = ['Live', 'Outsource', 'Dropshipping', 'In-Store'];

export default function FinancialsForm({ record, onUpdate }: Props) {
  const [saving, setSaving] = useState(false);
  const isLayaway = record.modeOfPayment === 'Layaway';

  const currency = getEffectiveCurrency(record);

  const [form, setForm] = useState({
    goldRate: record.goldRate?.toString() || '',
    mc: record.mc || '',
    supplierRate: record.supplierRate || '',
    additionalCharges: record.additionalCharges || '',
    additionalFeeRemarks: record.liverAdminRemarks || '',
    downpayment: String(record.downpayment || ''),
    amountReceived: String(record.amountReceived || ''),
    la1MonthPayment: String(record.la1MonthPayment || ''),
    la2MonthPayment: String(record.la2MonthPayment || ''),
    la3MonthPayment: String(record.la3MonthPayment || ''),
    la4MonthPayment: String(record.la4MonthPayment || ''),
    remittanceStatus: record.remittanceStatus || '',
    modeOfSale: record.modeOfSale || '',
  });

  useEffect(() => {
    setForm({
      goldRate: record.goldRate?.toString() || '',
      mc: record.mc || '',
      supplierRate: record.supplierRate || '',
      additionalCharges: record.additionalCharges || '',
      additionalFeeRemarks: record.liverAdminRemarks || '',
      downpayment: String(record.downpayment || ''),
      amountReceived: String(record.amountReceived || ''),
      la1MonthPayment: String(record.la1MonthPayment || ''),
      la2MonthPayment: String(record.la2MonthPayment || ''),
      la3MonthPayment: String(record.la3MonthPayment || ''),
      la4MonthPayment: String(record.la4MonthPayment || ''),
      remittanceStatus: record.remittanceStatus || '',
      modeOfSale: record.modeOfSale || '',
    });
  }, [record.id]);

  const set = (key: string, val: string) => setForm(p => ({ ...p, [key]: val }));

  const toDisplay = (val: unknown): string => {
    const num = parseFloat(String(val ?? '')) || 0;
    if (!num) return '';
    return String(Math.round(toAED(num, record) * 100) / 100);
  };
  const fromDisplay = (aedStr: string): string => {
    const num = parseFloat(aedStr) || 0;
    if (!num) return '';
    return String(Math.round(fromAED(num, record) * 100) / 100);
  };

  const buildPreview = (): DatabaseRowType => ({
    ...record,
    goldRate: parseFloat(form.goldRate) || record.goldRate,
    supplierRate: form.supplierRate,
    mc: form.mc,
    additionalCharges: form.additionalCharges,
    downpayment: form.downpayment,
    amountReceived: form.amountReceived,
    la1MonthPayment: isLayaway ? form.la1MonthPayment : '',
    la2MonthPayment: isLayaway ? form.la2MonthPayment : '',
    la3MonthPayment: isLayaway ? form.la3MonthPayment : '',
    la4MonthPayment: isLayaway ? form.la4MonthPayment : '',
  });

  const handlePayFull = () => {
    const preview = buildPreview();
    preview.amountReceived = ''; 
    const remainingAED = calcRemainingBalance(preview); 

    if (remainingAED > 0) {
        set('amountReceived', String(fromAED(remainingAED, record)));
        toast.success(`Auto-filled full balance!`);
    } else {
        toast.info('Balance is already fully paid!');
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const previewRecord = buildPreview();
      const computedProfit = calcProfitAED(previewRecord).toFixed(2);

      await onUpdate(record.id, {
        goldRate: parseFloat(form.goldRate) || record.goldRate,
        supplierRate: form.supplierRate,
        mc: form.mc,
        additionalCharges: form.additionalCharges,
        liverAdminRemarks: form.additionalFeeRemarks,
        downpayment: form.downpayment,
        amountReceived: form.amountReceived,
        la1MonthPayment: isLayaway ? form.la1MonthPayment : '',
        la2MonthPayment: isLayaway ? form.la2MonthPayment : '',
        la3MonthPayment: isLayaway ? form.la3MonthPayment : '',
        la4MonthPayment: isLayaway ? form.la4MonthPayment : '',
        remittanceStatus: form.remittanceStatus,
        modeOfSale: form.modeOfSale,
        profit: computedProfit,
      });
      toast.success('Financials saved');
    } finally {
      setSaving(false);
    }
  };

  const previewRecord = buildPreview();
  const itemPrice = calcItemPrice(previewRecord);
  const itemPriceAED = calcItemPriceAED(previewRecord);
  const shippingFee = calcShippingFee(previewRecord);
  const ccFee = calcCCFee(previewRecord);
  const additionalAED = parseFloat(form.additionalCharges) || 0;
  const totalAmount = roundPrice(itemPriceAED + shippingFee + ccFee + additionalAED);
  const totalPaid = calcTotalPaid(previewRecord);
  const remaining = roundPrice(totalAmount - totalPaid);
  const profitAED = calcProfitAED(previewRecord);

  const numField = (label: string, key: string, disabled = false) => (
    <div>
      <Label className="text-xs text-muted-foreground">{label}</Label>
      <Input type="number" value={form[key as keyof typeof form]} onChange={e => set(key, e.target.value)}
        disabled={disabled} className="h-8 text-xs bg-background border-border mt-0.5 disabled:opacity-50" placeholder="0.00" />
    </div>
  );

  const paymentField = (label: string, key: string, disabled = false) => (
    <div>
      <Label className="text-xs text-muted-foreground">{label}</Label>
      <Input
        type="number"
        value={toDisplay(form[key as keyof typeof form])}
        onChange={e => set(key, fromDisplay(e.target.value))}
        disabled={disabled}
        className="h-8 text-xs bg-background border-border mt-0.5 disabled:opacity-50"
        placeholder="0.00"
      />
    </div>
  );

  return (
    <div className="border-t border-border pt-3 mt-2">
      <p className="text-xs font-medium text-muted-foreground mb-2 uppercase tracking-wide">Financials</p>

      <div className="mb-3">
        <Label className="text-xs text-muted-foreground">Mode of Sale</Label>
        <Select value={form.modeOfSale} onValueChange={v => set('modeOfSale', v)}>
          <SelectTrigger className="h-8 text-xs bg-background border-border mt-0.5">
            <SelectValue placeholder="Select mode of sale..." />
          </SelectTrigger>
          <SelectContent className="bg-popover border-border">
            {MODE_OF_SALE_OPTIONS.map(o => <SelectItem key={o} value={o} className="text-xs">{o}</SelectItem>)}
          </SelectContent>
        </Select>
      </div>

      <div className="grid grid-cols-2 gap-2 mb-3">
        {numField('Gold Rate', 'goldRate')}
        {numField('MC (Making Charge)', 'mc')}
        <div>
          <Label className="text-xs text-muted-foreground">Supplier Rate</Label>
          <Input type="number" value={form.supplierRate} onChange={e => set('supplierRate', e.target.value)}
            className="h-8 text-xs bg-background border-border mt-0.5" placeholder="0.00" />
        </div>
        {numField('Additional Fees (AED)', 'additionalCharges')}
      </div>

      <div className="mb-3">
        <Label className="text-xs text-muted-foreground">Additional Fee Remarks <span className="text-primary/60">(Col X)</span></Label>
        <Textarea value={form.additionalFeeRemarks} onChange={e => set('additionalFeeRemarks', e.target.value)}
          className="text-xs bg-background border-border mt-0.5 min-h-[60px]" placeholder="Enter remarks about additional fees..." />
      </div>

      <div className="grid grid-cols-2 gap-2 mb-3">
        {paymentField('Downpayment (AED)', 'downpayment')}

        <div>
          <div className="flex items-center justify-between mb-0.5">
            <Label className="text-xs text-muted-foreground">Amount Received (AED)</Label>
            <button 
              onClick={handlePayFull} 
              className="text-[9px] font-bold text-primary bg-primary/10 hover:bg-primary/20 px-1.5 py-0.5 rounded transition-colors"
              title="Auto-fill exact remaining balance"
            >
              PAY FULL
            </button>
          </div>
          <Input
            type="number"
            value={toDisplay(form.amountReceived)}
            onChange={e => set('amountReceived', fromDisplay(e.target.value))}
            className="h-8 text-xs bg-background border-border disabled:opacity-50"
            placeholder="0.00"
          />
        </div>
      </div>

      <div className={`grid grid-cols-2 gap-2 mb-3 ${!isLayaway ? 'opacity-40' : ''}`}>
        <p className="col-span-2 text-xs text-muted-foreground">Layaway Payments (AED){!isLayaway ? ' (locked)' : ''}</p>
        {paymentField('Month 1', 'la1MonthPayment', !isLayaway)}
        {paymentField('Month 2', 'la2MonthPayment', !isLayaway)}
        {paymentField('Month 3', 'la3MonthPayment', !isLayaway)}
        {paymentField('Month 4', 'la4MonthPayment', !isLayaway)}
      </div>

      <div className="mb-3">
        <Label className="text-xs text-muted-foreground">Remittance Status</Label>
        <Select value={form.remittanceStatus} onValueChange={v => set('remittanceStatus', v)}>
          <SelectTrigger className="h-8 text-xs bg-background border-border mt-0.5">
            <SelectValue placeholder="Select remittance..." />
          </SelectTrigger>
          <SelectContent className="bg-popover border-border">
            {REMITTANCE_OPTIONS.map(o => <SelectItem key={o} value={o} className="text-xs">{o}</SelectItem>)}
          </SelectContent>
        </Select>
      </div>

      <div className="bg-secondary/50 rounded-lg p-3 mb-3 space-y-1 text-xs">
        <div className="flex justify-between"><span className="text-muted-foreground">Item Price ({currency})</span><span>{currency} {itemPrice.toFixed(2)}</span></div>
        {currency !== 'AED' && <div className="flex justify-between"><span className="text-muted-foreground">Item Price (AED)</span><span>AED {itemPriceAED.toFixed(2)}</span></div>}
        <div className="flex justify-between"><span className="text-muted-foreground">Shipping Fee</span><span>AED {shippingFee.toFixed(2)}</span></div>
        {ccFee > 0 && <div className="flex justify-between"><span className="text-muted-foreground">CC Fee</span><span>AED {ccFee.toFixed(2)}</span></div>}
        {additionalAED > 0 && <div className="flex justify-between"><span className="text-muted-foreground">Additional Charges</span><span>AED {additionalAED.toFixed(2)}</span></div>}
        <div className="flex justify-between font-semibold pt-1 border-t border-border">
          <span>Total Amount</span><span>AED {totalAmount.toFixed(2)}</span>
        </div>
        <div className="flex justify-between"><span className="text-muted-foreground">Total Paid</span><span>AED {totalPaid.toFixed(2)}</span></div>
        <div className={`flex justify-between font-bold pt-1 border-t border-border ${remaining > 0 ? 'text-destructive' : 'text-green-400'}`}>
          <span>Remaining Balance</span><span>AED {remaining.toFixed(2)}</span>
        </div>
        <div className="flex justify-between pt-1 border-t border-border">
          <span className="text-muted-foreground">Expected Profit</span>
          <span className={profitAED >= 0 ? 'text-primary font-medium' : 'text-destructive font-medium'}>AED {profitAED.toFixed(2)}</span>
        </div>
      </div>

      <Button onClick={handleSave} disabled={saving} className="w-full bg-primary text-primary-foreground text-xs h-8">
        {saving ? <><Loader2 className="h-3.5 w-3.5 mr-1.5 animate-spin" /> Saving...</> : 'Save Financials'}
      </Button>
    </div>
  );
}

