import { useMemo, useState } from 'react';
import { Calendar, ChevronDown, Printer, History } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { TabProps, DatabaseRowType } from '@/types';
import {
  calcProfitAED,
  calcRemainingBalance,
  parseDateRobust,
  calcItemPriceAED,
  calcItemCostAED
} from '@/lib/calculations';
import { formatDate, applySearch } from '@/lib/formatters';
import TabHeader from '@/components/TabHeader';
import KpiCard from './KpiCard';
import StatusBadge from '@/components/StatusBadge';
import { startOfWeek, startOfMonth, subMonths } from 'date-fns';
import CustomerHistoryModal from '@/components/CustomerHistoryModal';

type DateRange = 'all' | 'week' | 'month' | '3months' | 'custom';

export default function BossingDashboard({ records, searchQuery, onSearchChange }: TabProps) {
  const [range, setRange] = useState<DateRange>('all');
  const [customFrom, setCustomFrom] = useState<Date | undefined>();
  const [customTo, setCustomTo] = useState<Date | undefined>();
  const [pickerOpen, setPickerOpen] = useState(false);
  const [expandedStatuses, setExpandedStatuses] = useState<Record<string, boolean>>({});
  const [liverFilter, setLiverFilter] = useState('all');
  const [statusLiverFilters, setStatusLiverFilters] = useState<Record<string, string>>({});
  const [showPrintDialog, setShowPrintDialog] = useState(false);
  const [selectedPrintStatuses, setSelectedPrintStatuses] = useState<Set<string>>(new Set());

  const [historyCustomer, setHistoryCustomer] = useState<{ id: string, name: string } | null>(null);

  const liverNames = useMemo(() => {
    const names = Array.from(new Set(records.map(r => r.liverName?.trim().toUpperCase()).filter(Boolean))) as string[];
    return names.sort();
  }, [records]);

  const dateFiltered = useMemo(() => {
    const base = records;
    if (range === 'all') return base;
    const now = new Date();
    let from: Date;
    if (range === 'week') from = startOfWeek(now, { weekStartsOn: 1 });
    else if (range === 'month') from = startOfMonth(now);
    else if (range === '3months') from = subMonths(now, 3);
    else from = customFrom || new Date(0);
    const to = range === 'custom' ? customTo : undefined;
    return base.filter(r => {
      if (!r.dateOfLive) return false;
      const d = parseDateRobust(r.dateOfLive);
      if (!d) return false;
      const itemTime = d.getTime();
      if (itemTime < from.getTime()) return false;
      if (to) {
        const endOfToDay = new Date(to);
        endOfToDay.setHours(23, 59, 59, 999);
        if (itemTime > endOfToDay.getTime()) return false;
      }
      return true;
    });
  }, [records, range, customFrom, customTo]);

  const filtered = useMemo(() => {
    let base = applySearch(dateFiltered, searchQuery);
    if (liverFilter !== 'all') {
      base = base.filter(r => r.liverName?.trim().toUpperCase() === liverFilter);
    }
    return base;
  }, [dateFiltered, searchQuery, liverFilter]);

  const kpis = useMemo(() => {
    // FIX: Exclude both Cancelled and Returned Item from active calculations
    const activeRecords = filtered.filter(r => r.status !== 'Cancelled' && r.status !== 'Returned Item');
    const totalProfit = activeRecords.reduce((sum, r) => sum + calcProfitAED(r), 0);
    const totalSold = filtered.filter(r => r.status === 'Delivered' || r.status === 'Given to Shop').length;
    const outstanding = activeRecords.reduce((sum, r) => sum + Math.max(0, calcRemainingBalance(r)), 0);
    const totalGrams = activeRecords.reduce((sum, r) => {
      const cat = (r.category || '').toLowerCase();
      if (cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond')) return sum;
      return sum + (Number(r.grams) || 0);
    }, 0);
    return { totalProfit, totalSold, outstanding, activeCount: activeRecords.length, totalGrams };
  }, [filtered]);

  const statusGroups = useMemo(() => {
    const grouped = new Map<string, DatabaseRowType[]>();
    for (const r of filtered) {
      const status = r.status || 'Unknown';
      if (!grouped.has(status)) grouped.set(status, []);
      grouped.get(status)!.push(r);
    }
    return grouped;
  }, [filtered]);

  const toggleStatus = (status: string) => {
    setExpandedStatuses(prev => ({ ...prev, [status]: !prev[status] }));
  };

  const RANGES: { key: DateRange; label: string }[] = [
    { key: 'all', label: 'All Time' },
    { key: 'week', label: 'This Week' },
    { key: 'month', label: 'This Month' },
    { key: '3months', label: '3 Months' },
    { key: 'custom', label: 'Custom' },
  ];

  const openPrintDialog = () => {
    setSelectedPrintStatuses(new Set(statusGroups.keys()));
    setShowPrintDialog(true);
  };

  const togglePrintStatus = (status: string) => {
    setSelectedPrintStatuses(prev => {
      const next = new Set(prev);
      if (next.has(status)) next.delete(status);
      else next.add(status);
      return next;
    });
  };

  const handlePrintReport = () => {
    setShowPrintDialog(false);
    const win = window.open('', '_blank');
    if (!win) return;

    const dateRangeLabel = RANGES.find(r => r.key === range)?.label || 'Custom';

    let html = `<html><head><title>Executive Report</title>
      <link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@700&display=swap" rel="stylesheet">
      <style>
        body { font-family: sans-serif; color: #111; background: #fff; margin: 0; padding: 24px; font-size: 12px; }
        .font-cinzel { font-family: 'Cinzel', serif; font-weight: 700; }
        h1 { margin-bottom: 4px; font-size: 24px; color: #111; }
        .summary { margin-bottom: 24px; padding: 16px; background: #f9f9f9; border-radius: 8px; border: 1px solid #ddd; }
        .summary p { margin: 6px 0; font-size: 14px; font-weight: bold; }
        table { width: 100%; border-collapse: collapse; margin-bottom: 32px; }
        th { background: #111; color: #fff; padding: 8px; text-align: left; font-size: 11px; }
        th.r, td.r { text-align: right; }
        td { padding: 8px; border-bottom: 1px solid #ddd; }
        .status-header { font-size: 16px; margin-top: 24px; margin-bottom: 8px; color: #C9A84C; border-bottom: 2px solid #C9A84C; padding-bottom: 4px;}
        .page-header { font-size: 13px; font-weight: bold; margin-top: 14px; margin-bottom: 4px; background: #222; color: #fff; padding: 5px 10px; border-radius: 4px; }
        .date-header { font-size: 11px; font-weight: bold; margin-top: 8px; margin-bottom: 2px; color: #555; padding: 3px 8px; background: #f0f0f0; border-left: 3px solid #C9A84C; }
        .profit-pos { color: #16a34a; }
        .profit-neg { color: #dc2626; }
      </style></head><body>

      <h1 class="font-cinzel">EXECUTIVE SUMMARY REPORT</h1>

      <div class="summary">
        <p>Total Expected Profit: <span class="profit-pos">AED ${kpis.totalProfit.toFixed(2)}</span></p>
        <p>Total Items Sold: ${kpis.totalSold}</p>
        <p>Outstanding Receivables: AED ${kpis.outstanding.toFixed(2)}</p>
        <p style="font-size: 11px; color: #666; font-weight: normal; margin-top: 12px;">Date Range: ${dateRangeLabel} | Generated: ${new Date().toLocaleString()}</p>
      </div>
    `;

    Array.from(statusGroups.entries())
      .filter(([status]) => selectedPrintStatuses.has(status))
      .sort((a, b) => {
        if (a[0] === 'Cancelled' || a[0] === 'Returned Item') return 1;
        if (b[0] === 'Cancelled' || b[0] === 'Returned Item') return -1;
        return a[0].localeCompare(b[0]);
      }).forEach(([status, items]) => {
        const isDeadStatus = status === 'Cancelled' || status === 'Returned Item';
        const statusProfit = items.reduce((s, r) => s + calcProfitAED(r), 0);
        const profitText = isDeadStatus ? '' : ` | Profit: AED ${statusProfit.toFixed(2)}`;
        html += `<h2 class="font-cinzel status-header">${status.toUpperCase()} (${items.length} items${profitText})</h2>`;

        const byPage = new Map<string, Map<string, DatabaseRowType[]>>();
        for (const r of items) {
          let pageKey = (r.page || 'Other').trim();
          if (pageKey.toUpperCase().includes('MYK')) pageKey = 'MYK';
          else if (pageKey.toUpperCase().includes('EMPIRE')) pageKey = 'Empire Gold By ETG';
          const date = formatDate(r.dateOfLive);
          if (!byPage.has(pageKey)) byPage.set(pageKey, new Map());
          const byDate = byPage.get(pageKey)!;
          if (!byDate.has(date)) byDate.set(date, []);
          byDate.get(date)!.push(r);
        }

        const profitHeader = isDeadStatus ? '' : `<th class="r">Profit (AED)</th>`;

        Array.from(byPage.entries()).sort((a, b) => {
          if (a[0] === 'MYK') return -1; if (b[0] === 'MYK') return 1;
          if (a[0] === 'Empire Gold By ETG') return -1; if (b[0] === 'Empire Gold By ETG') return 1;
          return a[0].localeCompare(b[0]);
        }).forEach(([page, dateMap]) => {
          html += `<div class="page-header">📄 ${page}</div>`;

          Array.from(dateMap.entries()).sort((a, b) => b[0].localeCompare(a[0])).forEach(([date, rows]) => {
            const dateProfit = rows.reduce((s, r) => s + calcProfitAED(r), 0);
            const dateProfitText = isDeadStatus ? '' : ` — Profit: AED ${dateProfit.toFixed(2)}`;
            html += `<div class="date-header">📅 ${date}${dateProfitText}</div>`;
            html += `<table><thead><tr>
              <th>Client</th><th>Item</th>
              <th class="r">Price (AED)</th><th class="r">Cost (AED)</th>
              ${profitHeader}
            </tr></thead><tbody>`;

            html += rows.map(r => {
              const profit = calcProfitAED(r);
              const profitClass = profit >= 0 ? 'profit-pos' : 'profit-neg';
              const profitCell = isDeadStatus ? '' : `<td class="r"><strong class="${profitClass}">${profit.toFixed(2)}</strong></td>`;
              return `<tr>
                <td><strong>${r.minerName || '—'}</strong></td>
                <td>${r.itemDescription || '—'}</td>
                <td class="r">${calcItemPriceAED(r).toFixed(2)}</td>
                <td class="r">${calcItemCostAED(r).toFixed(2)}</td>
                ${profitCell}
              </tr>`;
            }).join('');

            html += `</tbody></table>`;
          });
        });
      });

    html += `</body></html>`;
    win.document.write(html);
    win.document.close();
    win.print();
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader title="Bossing Dashboard" subtitle="Executive summary — AED" searchQuery={searchQuery} onSearchChange={onSearchChange} />
      <div className="px-4 pt-4">
        <div className="flex gap-1.5 flex-wrap mb-4">
          {RANGES.map(r => (
            <Button
              key={r.key}
              size="sm"
              variant={range === r.key ? 'default' : 'outline'}
              className={`text-xs h-7 ${range === r.key ? 'bg-primary text-primary-foreground' : 'border-border'}`}
              onClick={() => setRange(r.key)}
            >
              {r.key === 'custom' && <Calendar className="h-3 w-3 mr-1" />}
              {r.label}
            </Button>
          ))}
        </div>

        <div className="mb-3">
          <Select value={liverFilter} onValueChange={setLiverFilter}>
            <SelectTrigger className="h-8 text-xs w-44 bg-background border-border">
              <SelectValue placeholder="All Livers" />
            </SelectTrigger>
            <SelectContent className="bg-popover border-border">
              <SelectItem value="all" className="text-xs">All Livers</SelectItem>
              {liverNames.map(name => (
                <SelectItem key={name} value={name} className="text-xs">{name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {range === 'custom' && (
          <div className="flex gap-2 mb-4">
            <Popover open={pickerOpen} onOpenChange={setPickerOpen}>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customFrom ? formatDate(customFrom.toISOString()) : 'From date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customFrom} onSelect={d => { setCustomFrom(d); setPickerOpen(false); }} />
              </PopoverContent>
            </Popover>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customTo ? formatDate(customTo.toISOString()) : 'To date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customTo} onSelect={d => setCustomTo(d)} />
              </PopoverContent>
            </Popover>
          </div>
        )}

        <div className="grid grid-cols-1 gap-3 mb-6">
          <KpiCard title="Total Expected Profit" value={`AED ${kpis.totalProfit.toFixed(2)}`} subtitle={`${kpis.activeCount} active records (excl. Cancelled/Returned)`} highlight />
          <KpiCard title="Total Items Sold" value={kpis.totalSold.toString()} subtitle="Delivered/Given to Shop (excl. Cancelled/Returned)" />
          <KpiCard title="Total Grams Sold" value={`${kpis.totalGrams.toFixed(2)}g`} subtitle="Excl. Per PC / Screw Type / Diamond" />
          <KpiCard title="Outstanding Receivables" value={`AED ${kpis.outstanding.toFixed(2)}`} subtitle="Sum of remaining balances (excl. Cancelled/Returned)" />
        </div>

        <div className="flex items-center justify-between mb-4">
          <h2 className="font-cinzel text-lg text-primary">Detailed Breakdown</h2>
          <Button variant="outline" size="sm" className="h-8 text-xs border-primary/40 text-primary" onClick={openPrintDialog}>
            <Printer className="h-3.5 w-3.5 mr-1.5" /> Print Report
          </Button>
        </div>

        <div className="space-y-3">
          {Array.from(statusGroups.entries()).sort((a, b) => {
            if (a[0] === 'Cancelled' || a[0] === 'Returned Item') return 1;
            if (b[0] === 'Cancelled' || b[0] === 'Returned Item') return -1;
            return a[0].localeCompare(b[0]);
          }).map(([status, items]) => {
            const isDeadStatus = status === 'Cancelled' || status === 'Returned Item';
            const totalProfit = items.reduce((sum, r) => sum + calcProfitAED(r), 0);
            const groupGrams = items.reduce((sum, r) => {
              const cat = (r.category || '').toLowerCase();
              if (cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond')) return sum;
              return sum + (Number(r.grams) || 0);
            }, 0);
            const isExpanded = expandedStatuses[status];

            return (
              <div key={status} className="rounded-xl border border-border bg-card overflow-hidden">
                <button
                  onClick={() => toggleStatus(status)}
                  className="w-full flex items-center justify-between p-4 text-left focus:outline-none"
                >
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <StatusBadge status={status} />
                      <span className="text-xs text-muted-foreground">{items.length} items</span>
                    </div>
                    <div className="flex flex-wrap gap-x-3 gap-y-0.5">
                      {!isDeadStatus && (
                        <p className="text-xs font-medium">
                          Profit: <span className={totalProfit >= 0 ? 'text-green-400' : 'text-destructive'}>AED {totalProfit.toFixed(2)}</span>
                        </p>
                      )}
                      {groupGrams > 0 && (
                        <p className="text-xs font-medium text-muted-foreground">
                          Grams: <span className="text-foreground">{groupGrams.toFixed(2)}g</span>
                        </p>
                      )}
                    </div>
                  </div>
                  <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                </button>

                {isExpanded && (() => {
                  const statusLiver = statusLiverFilters[status] || 'all';
                  const statusLiverNames = [...new Set(items.map(r => r.liverName?.trim().toUpperCase()).filter(Boolean) as string[])].sort();
                  const visibleItems = statusLiver === 'all' ? items : items.filter(r => r.liverName?.trim().toUpperCase() === statusLiver);

                  const byPage = new Map<string, Map<string, DatabaseRowType[]>>();
                  for (const r of visibleItems) {
                    let pageKey = (r.page || 'Other').trim();
                    if (pageKey.toUpperCase().includes('MYK')) pageKey = 'MYK';
                    else if (pageKey.toUpperCase().includes('EMPIRE')) pageKey = 'Empire Gold By ETG';
                    const d = r.dateOfLive || 'Unknown Date';
                    if (!byPage.has(pageKey)) byPage.set(pageKey, new Map());
                    const byDate = byPage.get(pageKey)!;
                    if (!byDate.has(d)) byDate.set(d, []);
                    byDate.get(d)!.push(r);
                  }

                  const sortedPages = [...byPage.entries()].sort((a, b) => {
                    if (a[0] === 'MYK') return -1; if (b[0] === 'MYK') return 1;
                    if (a[0] === 'Empire Gold By ETG') return -1; if (b[0] === 'Empire Gold By ETG') return 1;
                    return a[0].localeCompare(b[0]);
                  });

                  return (
                    <div className="px-4 pb-4 border-t border-border pt-3 animate-in fade-in slide-in-from-top-2 duration-200">
                      {statusLiverNames.length > 1 && (
                        <div className="mb-3">
                          <Select value={statusLiver} onValueChange={v => setStatusLiverFilters(prev => ({ ...prev, [status]: v }))}>
                            <SelectTrigger className="h-7 text-xs w-40 bg-background border-border">
                              <SelectValue placeholder="All Livers" />
                            </SelectTrigger>
                            <SelectContent className="bg-popover border-border">
                              <SelectItem value="all" className="text-xs">All Livers</SelectItem>
                              {statusLiverNames.map(name => (
                                <SelectItem key={name} value={name} className="text-xs">{name}</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                      )}
                      <div className="space-y-4">
                        {sortedPages.map(([page, dateMap]) => {
                          const sortedDates = [...dateMap.entries()].sort((a, b) => b[0].localeCompare(a[0]));
                          return (
                            <div key={page}>
                              <div className="flex items-center gap-2 mb-2">
                                <span className="text-[10px] font-bold text-primary/70 uppercase tracking-widest">📄 {page}</span>
                                <div className="h-px flex-1 bg-border/50" />
                                <span className="text-[10px] text-muted-foreground">{Array.from(dateMap.values()).reduce((s, v) => s + v.length, 0)}</span>
                              </div>
                              <div className="space-y-3 ml-2">
                                {sortedDates.map(([date, dateItems]) => (
                                  <div key={date}>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                      <span className="text-[9px] font-semibold text-muted-foreground uppercase tracking-widest">📅 {formatDate(date)}</span>
                                      <div className="h-px flex-1 bg-border/30" />
                                      <span className="text-[9px] text-muted-foreground">{dateItems.length} · {dateItems.reduce((s, r) => { const c = (r.category||'').toLowerCase(); return c.includes('per pc')||c.includes('screw type')||c.includes('diamond') ? s : s+(Number(r.grams)||0); }, 0).toFixed(2)}g</span>
                                    </div>
                                    <div className="space-y-2 ml-2">
                                      {dateItems.map(record => {
                                        const profit = calcProfitAED(record);
                                        const cat = (record.category || '').toLowerCase();
                                        const isPc = cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond');
                                        const gramsDisplay = isPc ? 'PC' : (record.grams ? `${Number(record.grams).toFixed(2)}g` : '—');
                                        return (
                                          <div key={record.id} className="flex justify-between items-start border-b border-border/40 pb-2 last:border-0 last:pb-0">
                                            <div className="flex-1 pr-2">
                                              <div className="flex items-center gap-1.5">
                                                <p className="text-sm font-medium">{record.minerName || 'Unknown'}</p>
                                                {record.customerId && (
                                                  <button
                                                    onClick={(e) => {
                                                      e.stopPropagation();
                                                      setHistoryCustomer({ id: record.customerId!, name: record.minerName || '' });
                                                    }}
                                                    className="text-muted-foreground hover:text-primary transition-colors mt-0.5"
                                                    title="View Lifetime History"
                                                  >
                                                    <History className="h-3.5 w-3.5" />
                                                  </button>
                                                )}
                                              </div>
                                              <p className="text-xs text-muted-foreground mt-0.5 truncate">{record.itemDescription}</p>
                                            </div>
                                            <div className="text-right shrink-0 space-y-0.5">
                                              <p className="text-[10px] font-semibold text-muted-foreground">{gramsDisplay}</p>
                                              {!isDeadStatus && (
                                                <>
                                                  <p className={`text-sm font-medium ${profit >= 0 ? 'text-foreground' : 'text-destructive'}`}>AED {profit.toFixed(2)}</p>
                                                  <p className="text-[10px] text-muted-foreground">Profit</p>
                                                </>
                                              )}
                                            </div>
                                          </div>
                                        );
                                      })}
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })()}
              </div>
            );
          })}

          {statusGroups.size === 0 && (
            <div className="text-center py-12 border border-dashed border-border rounded-xl">
              <p className="text-sm text-muted-foreground">No records found for this period.</p>
            </div>
          )}
        </div>
      </div>

      <Dialog open={showPrintDialog} onOpenChange={setShowPrintDialog}>
        <DialogContent className="bg-card border-border max-w-sm">
          <DialogHeader>
            <DialogTitle className="font-cinzel text-primary text-base">Select Statuses to Print</DialogTitle>
          </DialogHeader>
          <div className="space-y-3 py-2">
            <div className="flex gap-2 mb-2">
              <Button size="sm" variant="outline" className="text-xs h-7 border-border" onClick={() => setSelectedPrintStatuses(new Set(statusGroups.keys()))}>Select All</Button>
              <Button size="sm" variant="outline" className="text-xs h-7 border-border" onClick={() => setSelectedPrintStatuses(new Set())}>Clear All</Button>
            </div>
            {Array.from(statusGroups.entries()).sort((a, b) => {
              if (a[0] === 'Cancelled' || a[0] === 'Returned Item') return 1;
              if (b[0] === 'Cancelled' || b[0] === 'Returned Item') return -1;
              return a[0].localeCompare(b[0]);
            }).map(([status, items]) => (
              <div key={status} className="flex items-center gap-3">
                <Checkbox
                  id={`print-${status}`}
                  checked={selectedPrintStatuses.has(status)}
                  onCheckedChange={() => togglePrintStatus(status)}
                />
                <Label htmlFor={`print-${status}`} className="text-sm cursor-pointer flex-1">
                  {status}
                  <span className="text-xs text-muted-foreground ml-2">({items.length} items)</span>
                </Label>
              </div>
            ))}
          </div>
          <DialogFooter>
            <Button variant="outline" size="sm" className="text-xs border-border" onClick={() => setShowPrintDialog(false)}>Cancel</Button>
            <Button
              size="sm"
              className="text-xs bg-primary text-primary-foreground"
              disabled={selectedPrintStatuses.size === 0}
              onClick={handlePrintReport}
            >
              <Printer className="h-3.5 w-3.5 mr-1.5" /> Print
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {historyCustomer && (
        <CustomerHistoryModal
          customerId={historyCustomer.id}
          minerName={historyCustomer.name}
          allRecords={records}
          onClose={() => setHistoryCustomer(null)}
        />
      )}
    </div>
  );
}

