import { useMemo, useState } from 'react';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { TabProps, DatabaseRowType } from '@/types';
import { applySearch, groupByPageDateMiner, formatDate } from '@/lib/formatters';
import CollapsibleGroup from '@/components/CollapsibleGroup';
import { calcRemainingBalance, parseDateRobust } from '@/lib/calculations';
import { startOfWeek, startOfMonth, subMonths } from 'date-fns';
import TabHeader from '@/components/TabHeader';
import AccountsClientCard from './AccountsClientCard';
import { ChevronDown, Plus, Calendar } from 'lucide-react';
import AddClientModal from './AddClientModal';

type DateRange = 'all' | 'week' | 'month' | '3months' | 'custom';

const DATE_RANGES: { key: DateRange; label: string }[] = [
  { key: 'all', label: 'All' },
  { key: 'week', label: 'Week' },
  { key: 'month', label: 'Month' },
  { key: '3months', label: '3 Mo' },
  { key: 'custom', label: 'Custom' },
];

export default function AccountsTracking({ records, searchQuery, onSearchChange, onUpdate, userFirstName, userEmail, onRefresh }: TabProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [deliveredExpanded, setDeliveredExpanded] = useState(false);
  const [otherExpanded, setOtherExpanded] = useState(false);
  const [liverFilter, setLiverFilter] = useState('all');
  const [dateRange, setDateRange] = useState<DateRange>('all');
  const [customFrom, setCustomFrom] = useState<Date | undefined>();
  const [customTo, setCustomTo] = useState<Date | undefined>();

  const liverNames = useMemo(() => {
    const names = Array.from(new Set(records.map(r => r.liverName?.trim().toUpperCase()).filter(Boolean))) as string[];
    return names.sort();
  }, [records]);

  const filteredRecords = useMemo(() => {
    let base = records;

    if (liverFilter !== 'all') {
      base = base.filter(r => r.liverName?.trim().toUpperCase() === liverFilter);
    }

    if (dateRange !== 'all') {
      const now = new Date();
      let from: Date;
      if (dateRange === 'week') from = startOfWeek(now, { weekStartsOn: 1 });
      else if (dateRange === 'month') from = startOfMonth(now);
      else if (dateRange === '3months') from = subMonths(now, 3);
      else from = customFrom || new Date(0);
      const to = dateRange === 'custom' ? customTo : undefined;

      base = base.filter(r => {
        if (!r.dateOfLive) return false;
        const d = parseDateRobust(r.dateOfLive);
        if (!d) return false;
        if (d.getTime() < from.getTime()) return false;
        if (to) {
          const end = new Date(to); end.setHours(23, 59, 59, 999);
          if (d.getTime() > end.getTime()) return false;
        }
        return true;
      });
    }

    return base;
  }, [records, liverFilter, dateRange, customFrom, customTo]);

  const { deliveredGroups, otherActiveGroups, clearedGroups } = useMemo(() => {
    const searched = applySearch(filteredRecords, searchQuery);

    // FIX: EXCLUSION FILTER - This forces all Active, Walk-ins, and Pending to show!
    const deadStatuses = ['Cancelled', 'Returned Item'];
    const aliveRecords = searched.filter(r => !deadStatuses.includes((r.status || '').trim()));

    const active: DatabaseRowType[] = [];
    const cleared: DatabaseRowType[] = [];

    aliveRecords.forEach(r => {
      const remStatus = (r.remittanceStatus || '').toLowerCase();
      const isCleared = remStatus.includes('secured') || remStatus.includes('received') || calcRemainingBalance(r) <= 0;

      if (isCleared) {
        cleared.push(r);
      } else {
        active.push(r);
      }
    });

    const delivered = active.filter(r => r.status === 'Delivered');
    const others = active.filter(r => r.status !== 'Delivered');

    return {
      deliveredGroups: groupByPageDateMiner(delivered),
      otherActiveGroups: groupByPageDateMiner(others),
      clearedGroups: groupByPageDateMiner(cleared),
    };
  }, [filteredRecords, searchQuery]);

  const renderGroups = (groups: Map<string, Map<string, Map<string, DatabaseRowType[]>>>) => (
    groups.size === 0 ? (
      <div className="text-center py-10 text-muted-foreground text-sm border border-dashed border-border rounded-lg mt-2">
        No records found in this section.
      </div>
    ) : (
      <div>
        {Array.from(groups.entries()).map(([page, dateMap]) => (
          <CollapsibleGroup key={page} label={page} colorClass="text-primary/70" lineClass="bg-primary/10" defaultOpen={false}>
            {Array.from(dateMap.entries()).map(([date, minerMap]) => (
              <CollapsibleGroup key={date} label={formatDate(date)} colorClass="text-muted-foreground" lineClass="bg-border/40" indent defaultOpen={false}>
                <div className="space-y-3">
                  {Array.from(minerMap.entries()).map(([minerName, items]) => (
                    <AccountsClientCard key={minerName} minerName={minerName} records={items} allRecords={records} onUpdate={onUpdate} />
                  ))}
                </div>
              </CollapsibleGroup>
            ))}
          </CollapsibleGroup>
        ))}
      </div>
    )
  );

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader
        title="Accounts Tracking"
        subtitle={`${deliveredGroups.size + otherActiveGroups.size} active clients`}
        searchQuery={searchQuery}
        onSearchChange={onSearchChange}
      />

      <div className="px-4 pt-4">
        <div className="flex flex-wrap gap-2 mb-3">
          <Select value={liverFilter} onValueChange={setLiverFilter}>
            <SelectTrigger className="h-8 text-xs w-40 bg-background border-border">
              <SelectValue placeholder="All Livers" />
            </SelectTrigger>
            <SelectContent className="bg-popover border-border">
              <SelectItem value="all" className="text-xs">All Livers</SelectItem>
              {liverNames.map(name => (
                <SelectItem key={name} value={name} className="text-xs">{name}</SelectItem>
              ))}
            </SelectContent>
          </Select>

          <div className="flex gap-1 flex-wrap">
            {DATE_RANGES.map(r => (
              <Button
                key={r.key}
                size="sm"
                variant={dateRange === r.key ? 'default' : 'outline'}
                className={`text-xs h-8 px-2.5 ${dateRange === r.key ? 'bg-primary text-primary-foreground' : 'border-border'}`}
                onClick={() => setDateRange(r.key)}
              >
                {r.key === 'custom' && <Calendar className="h-3 w-3 mr-1" />}
                {r.label}
              </Button>
            ))}
          </div>
        </div>

        {dateRange === 'custom' && (
          <div className="flex gap-2 mb-3">
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customFrom ? formatDate(customFrom.toISOString()) : 'From date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customFrom} onSelect={setCustomFrom} />
              </PopoverContent>
            </Popover>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customTo ? formatDate(customTo.toISOString()) : 'To date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customTo} onSelect={setCustomTo} />
              </PopoverContent>
            </Popover>
          </div>
        )}

        <div className="flex justify-end mb-4">
          <Button
            onClick={() => setShowAddModal(true)}
            className="bg-primary text-primary-foreground hover:bg-primary/90 text-xs h-9 shadow-sm"
          >
            <Plus className="h-4 w-4 mr-1.5" />
            Add Client
          </Button>
        </div>

        <Tabs defaultValue="active">
          <TabsList className="w-full mb-4 bg-secondary">
            <TabsTrigger value="active" className="flex-1 text-xs data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">
              Active ({deliveredGroups.size + otherActiveGroups.size})
            </TabsTrigger>
            <TabsTrigger value="cleared" className="flex-1 text-xs data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">
              Cleared ({clearedGroups.size})
            </TabsTrigger>
          </TabsList>

          <TabsContent value="active">
            <div className="mb-6">
              <button className="flex w-full items-center gap-3 mb-3 text-left focus:outline-none" onClick={() => setDeliveredExpanded(!deliveredExpanded)}>
                <span className="font-cinzel text-sm font-bold text-green-500 whitespace-nowrap tracking-wide">DELIVERED</span>
                <span className="text-xs bg-green-500/10 text-green-500 px-2.5 py-0.5 rounded-full font-bold whitespace-nowrap border border-green-500/20">{deliveredGroups.size} pages</span>
                <div className="h-px flex-1 bg-green-500/20" />
                <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${deliveredExpanded ? 'rotate-180' : ''}`} />
              </button>
              {deliveredExpanded && <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroups(deliveredGroups)}</div>}
            </div>

            <div className="mb-4">
              <button className="flex w-full items-center gap-3 mb-3 text-left focus:outline-none" onClick={() => setOtherExpanded(!otherExpanded)}>
                <span className="font-cinzel text-sm font-bold text-primary whitespace-nowrap tracking-wide">OTHER ACTIVE (LAYAWAY/SHOP)</span>
                <span className="text-xs bg-primary/10 text-primary px-2.5 py-0.5 rounded-full font-bold whitespace-nowrap border border-primary/20">{otherActiveGroups.size} pages</span>
                <div className="h-px flex-1 bg-primary/20" />
                <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${otherExpanded ? 'rotate-180' : ''}`} />
              </button>
              {otherExpanded && <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroups(otherActiveGroups)}</div>}
            </div>
          </TabsContent>

          <TabsContent value="cleared">
            <div className="space-y-3">{renderGroups(clearedGroups)}</div>
          </TabsContent>
        </Tabs>
      </div>

      {showAddModal && <AddClientModal onClose={() => setShowAddModal(false)} userFirstName={userFirstName} userEmail={userEmail} onRefresh={onRefresh} existingRecords={records} />}
    </div>
  );
}

