import { useEffect, useState, useCallback } from 'react';
import { useAuth } from 'zite-auth-sdk';
import { getRecords, updateRecord, getRoles } from 'zite-endpoints-sdk';
import { Toaster } from '@/components/ui/sonner';
import { toast } from 'sonner';
import { RefreshCw } from 'lucide-react'; // <-- Added refresh icon
import { getUserRole, SUPER_ADMIN_EMAILS } from '@/config/roles'; 
import { DatabaseRowType } from '@/types';
import LoadingSkeleton from '@/components/LoadingSkeleton';
import AccessDenied from '@/components/AccessDenied';
import UploadMasterlistFAB from '@/components/UploadMasterlistFAB';
import AdminPipeline from '@/components/admin/AdminPipeline';
import DispatchBoard from '@/components/dispatch/DispatchBoard';
import AccountsTracking from '@/components/accounts/AccountsTracking';
import BossingDashboard from '@/components/bossing/BossingDashboard';
import WelcomeScreen from '@/components/WelcomeScreen';
import LiverDashboard from '@/pages/LiverDashboard';

export default function App() {
  const { user, isLoading } = useAuth();
  const [records, setRecords] = useState<DatabaseRowType[]>([]);
  const [dynamicRoles, setDynamicRoles] = useState<any[] | null>(null);
  const [rolesError, setRolesError] = useState(false);

  const [dataLoading, setDataLoading] = useState(true); 
  const [isSyncing, setIsSyncing] = useState(false); // Track silent background syncs
  const [searchQuery, setSearchQuery] = useState('');

  // Keep track of what tab they click, but we'll validate it later
  const [activeTab, setActiveTab] = useState<'admin' | 'dispatch' | 'accounts' | 'bossing' | 'liver'>('admin');

  // Add a "silent" flag so it doesn't show the skeleton loader when refreshing in the background
  const fetchData = useCallback((silent = false) => {
    if (!user) return;

    if (silent) {
      setIsSyncing(true);
    } else {
      setDataLoading(true);
    }

    Promise.all([
      getRecords({}).catch(() => { toast.error('Failed to load records'); return []; }),
      getRoles({}).catch((err) => { 
        console.error('getRoles failed — failing closed for security:', err);
        setRolesError(true);
        return null;
      })
    ])
      .then(([recordsData, rolesData]) => {
        setRecords((recordsData as DatabaseRowType[]) || []);
        if (rolesData !== null) {
          setDynamicRoles((rolesData as any[]) || []);
        }
      })
      .finally(() => {
        setDataLoading(false);
        setIsSyncing(false);
      });
  }, [user]);

  useEffect(() => { fetchData(false); }, [fetchData]);

  const handleUpdate = async (rowId: number, fields: Partial<DatabaseRowType>) => {
    // 1. Optimistic UI update (makes the app feel instantly responsive)
    setRecords(prev => prev.map(r => r.id === rowId ? { ...r, ...fields } : r));

    try {
      // 2. Save to Google Sheets
      await updateRecord({ rowId, fields: fields as Record<string, unknown> });

      // 3. Silent Background Refresh (pulls everyone else's changes automatically)
      fetchData(true);
    } catch {
      toast.error('Failed to save changes');
      fetchData(true); // Revert the UI if the save fails
    }
  };

  if (isLoading) return <LoadingSkeleton />;
  if (!user) return <WelcomeScreen />;

  // role is now an ARRAY: e.g., ['admin', 'dispatch']
  const roles = getUserRole(user.email, dynamicRoles);
  const isSuperAdmin = roles.includes('super_admin');

  // Check if they have zero roles
  if (rolesError) return (
    <div className="min-h-screen flex items-center justify-center bg-background">
      <div className="text-center space-y-3 p-8 max-w-sm">
        <p className="text-destructive font-semibold">Failed to load roles</p>
        <p className="text-sm text-muted-foreground">Could not verify your permissions. Please refresh the page to try again.</p>
        <button onClick={() => { setRolesError(false); fetchData(false); }} className="text-xs text-primary underline">Retry</button>
      </div>
    </div>
  );
  if (dataLoading && dynamicRoles === null) return <LoadingSkeleton />;
  if (!dataLoading && roles.length === 0) return <AccessDenied email={user.email} />;

  // Determine exactly which tabs this user is allowed to see
  const ALL_TABS = ['admin', 'dispatch', 'accounts', 'bossing', 'liver'] as const;
  const allowedTabs = isSuperAdmin
    ? ALL_TABS
    : ([...ALL_TABS.filter(t => t === 'liver' || roles.includes(t as any))] as typeof ALL_TABS[number][]);

  // Smart routing: if their selected activeTab isn't in their allowed list, default to their first allowed tab
  const currentTab = allowedTabs.includes(activeTab) ? activeTab : allowedTabs[0];

  const tabProps = {
    records,
    searchQuery,
    onSearchChange: setSearchQuery,
    onUpdate: handleUpdate,
    userEmail: user.email,
    userFirstName: user.firstName,
    onRefresh: () => fetchData(true),
  };

  return (
    <div className="min-h-screen bg-background max-w-2xl mx-auto flex flex-col">
      <Toaster richColors position="top-center" />

      <div className="flex items-center justify-between border-b border-border sticky top-0 z-30 bg-background/95 backdrop-blur px-4">
        <div className="flex h-12 items-center">

          {/* Small Top Bar Logo */}
          <img 
            src="https://images.fillout.com/orgid-614156/flowpublicid-6ydzrkprmt/widgetid-default/mVy86cbPRgBbVeiVpWrXgn/pasted-image-1772870436282.png" 
            alt="Logo" 
            className="h-6 sm:h-8 w-auto object-contain mr-2 sm:mr-4" 
          />

          {/* Show Navigation Tabs if they are a super admin OR if they have more than 1 role */}
          {allowedTabs.length > 1 && (
            <div className="flex h-full items-center border-l border-border pl-2 sm:pl-4">
              {allowedTabs.includes('admin') && (
                <button onClick={() => setActiveTab('admin')} className={`h-full px-2 sm:px-3 text-[10px] sm:text-xs font-cinzel ${currentTab === 'admin' ? 'text-primary border-b-2 border-primary' : 'text-muted-foreground'}`}>Admin</button>
              )}
              {allowedTabs.includes('dispatch') && (
                <button onClick={() => setActiveTab('dispatch')} className={`h-full px-2 sm:px-3 text-[10px] sm:text-xs font-cinzel ${currentTab === 'dispatch' ? 'text-primary border-b-2 border-primary' : 'text-muted-foreground'}`}>Dispatch</button>
              )}
              {allowedTabs.includes('accounts') && (
                <button onClick={() => setActiveTab('accounts')} className={`h-full px-2 sm:px-3 text-[10px] sm:text-xs font-cinzel ${currentTab === 'accounts' ? 'text-primary border-b-2 border-primary' : 'text-muted-foreground'}`}>Accounts</button>
              )}
              {allowedTabs.includes('bossing') && (
                <button onClick={() => setActiveTab('bossing')} className={`h-full px-2 sm:px-3 text-[10px] sm:text-xs font-cinzel ${currentTab === 'bossing' ? 'text-primary border-b-2 border-primary' : 'text-muted-foreground'}`}>Bossing</button>
              )}
              {allowedTabs.includes('liver') && (
                <button onClick={() => setActiveTab('liver')} className={`h-full px-2 sm:px-3 text-[10px] sm:text-xs font-cinzel ${currentTab === 'liver' ? 'text-primary border-b-2 border-primary' : 'text-muted-foreground'}`}>My Sales</button>
              )}
            </div>
          )}
        </div>

        <div className="flex items-center gap-2 sm:gap-3">
          {/* Manual Refresh Button */}
          <button 
            onClick={() => fetchData(true)}
            disabled={isSyncing}
            className={`p-1.5 rounded-full hover:bg-secondary transition-colors ${isSyncing ? 'animate-spin text-primary' : 'text-muted-foreground'}`}
            title="Sync latest data"
          >
            <RefreshCw className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
          </button>

          <span className="text-[10px] sm:text-xs text-muted-foreground truncate max-w-[100px] sm:max-w-none">
            {user.email}
          </span>

          {(isSuperAdmin || roles.includes('admin')) && (
            <UploadMasterlistFAB onRefresh={() => fetchData(false)} />
          )}
        </div>
      </div>

      {dataLoading ? (
        <LoadingSkeleton />
      ) : (
        <div className="p-0 flex-1">
          {currentTab === 'admin' && <AdminPipeline {...tabProps} />}
          {currentTab === 'dispatch' && <DispatchBoard {...tabProps} />}
          {currentTab === 'accounts' && <AccountsTracking {...tabProps} />}
          {currentTab === 'bossing' && <BossingDashboard {...tabProps} />}
          {currentTab === 'liver' && <LiverDashboard {...tabProps} />}
        </div>
      )}
    </div>
  );
}

