export type UserRole = 'super_admin' | 'admin' | 'dispatch' | 'accounts' | 'bossing';

// Super-admins: always have full access and see ALL tabs.
export const SUPER_ADMIN_EMAILS = [
  "reynanteevillegas@gmail.com",
  "villegasenrique0921@gmail.com",
];

// Fallback roles if the Database 'Roles' tab hasn't been set up yet
export const fallbackRoleConfig = {
  adminEmails: ["roseannaranez2@gmail.com"],
  dispatchEmails: [] as string[],
  accountsEmails: [] as string[],
  bossingEmails: [] as string[],
};

export function getUserRole(
  email: string,
  dynamicRoles: any[] | null = null,
): UserRole[] {
  const e = email.toLowerCase().trim();

  // Super-admin check always wins
  if (SUPER_ADMIN_EMAILS.map(x => x.toLowerCase()).includes(e)) {
    return ['super_admin'];
  }

  const assignedRoles: UserRole[] = [];

  if (dynamicRoles && dynamicRoles.length > 0) {
    const found = dynamicRoles.find(r => {
      const rEmail = (r.email || r.Email || r.EMAIL || r['Email Address'] || '');
      return rEmail.toLowerCase().trim() === e;
    });

    if (found) {
      const role = (found.role || found.Role || found.ROLE || '').toLowerCase().trim();
      if (role === 'super_admin') assignedRoles.push('super_admin');
      if (role === 'admin' || role === 'super_admin') assignedRoles.push('admin');
      if (role === 'dispatch') assignedRoles.push('dispatch');
      if (role === 'accounts') assignedRoles.push('accounts');
      if (role === 'bossing') assignedRoles.push('bossing');

      // Support comma-separated multi-roles e.g. "admin,dispatch"
      if (assignedRoles.length === 0) {
        const parts = role.split(',').map((s: string) => s.trim());
        for (const p of parts) {
          if (['admin','dispatch','accounts','bossing','super_admin'].includes(p)) {
            assignedRoles.push(p as UserRole);
          }
        }
      }
    }
  }

  // Fallback check
  if (assignedRoles.length === 0) {
    if (fallbackRoleConfig.adminEmails.map(x => x.toLowerCase()).includes(e)) {
      assignedRoles.push('admin');
    }
    if (fallbackRoleConfig.dispatchEmails.map(x => x.toLowerCase()).includes(e)) {
      assignedRoles.push('dispatch');
    }
    if (fallbackRoleConfig.accountsEmails.map(x => x.toLowerCase()).includes(e)) {
      assignedRoles.push('accounts');
    }
    if (fallbackRoleConfig.bossingEmails.map(x => x.toLowerCase()).includes(e)) {
      assignedRoles.push('bossing');
    }
  }

  return assignedRoles;
}

