// SERVER-SIDE PROFIT CALCULATOR WITH SMART SNAP
function calculateServerProfit(fields: any, phpRate: number): string {
   const n = (val: any) => { const num = parseFloat(val); return isNaN(num) ? 0 : num; };
   const grams = n(fields.grams);
   const clientRate = n(fields.clientRate);
   const category = String(fields.category || '').toLowerCase();
   const currency = String(fields.currency || 'AED').toUpperCase();
   const qty = n(fields.qty) || 1;

   let rateAED = clientRate;
   if (currency === 'PHP') rateAED = clientRate / phpRate;
   else if (currency === 'USD') rateAED = clientRate * 3.67; // The 3.67 UAE Peg

   let totalSales = 0;
   let totalCost = 0;

   if (category.includes('screw type') || category.includes('per pc')) {
       totalSales = rateAED * qty;
       let sr = n(fields.supplierRate) > 0 ? n(fields.supplierRate) : (n(fields.goldRate) > 0 ? n(fields.goldRate) : 115);
       if (sr === 115 && String(fields.itemDescription || '').toUpperCase().includes('B1T1')) sr *= 2;
       totalCost = sr * qty;
   } else if (category.includes('silver branded')) {
       // SMART SNAP TO 60
       if (rateAED > 0 && Math.abs(rateAED - 60) <= 2) rateAED = 60;
       totalSales = (clientRate > 0 ? rateAED : 60) * grams;
       totalCost = 32 * grams;
   } else if (category.includes('silver')) {
       // SMART SNAP TO 45
       if (rateAED > 0 && Math.abs(rateAED - 45) <= 2) rateAED = 45;
       totalSales = (clientRate > 0 ? rateAED : 45) * grams;
       totalCost = 15 * grams;
   } else if (category.includes('diamond')) {
       totalSales = rateAED * qty;
       totalCost = n(fields.supplierRate) * qty;
   } else {
       totalSales = rateAED * grams;
       const gr = n(fields.goldRate);
       const sr = n(fields.supplierRate);
       if (gr > 0) {
           let mc = n(fields.mc);
           if (mc <= 0) {
               if (category.includes('special price ef')) mc = 25;
               else if (category.includes('special price')) mc = 21;
               else mc = 16;
           }
           totalCost = (gr + mc) * grams;
       } else if (sr > 0) {
           totalCost = sr * grams;
       }
   }
   return Math.round(totalSales - totalCost).toFixed(2);
}
export default createEndpoint({
  description: 'Create a new Database row securely',
  authenticated: true,
  inputSchema: z.object({
    fields: z.record(z.unknown()),
  }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input, context }) => {
    // 1. Backend Authorization Lockdown
    if (!context?.user?.email) throw new Error("Unauthorized request");
    const userEmail = context.user.email.toLowerCase().trim();

    let isAuthorized = SUPER_ADMIN_EMAILS.includes(userEmail);
    if (!isAuthorized) {
      const roles = await Roles.findAll({});
      const found = roles?.find(r => (r.email || '')?.toLowerCase().trim() === userEmail);
      if (found) {
         const roleStr = (found.role || '').toLowerCase();
         if (['super_admin', 'admin', 'dispatch', 'accounts', 'bossing'].some(r => roleStr.includes(r))) {
            isAuthorized = true;
         }
      }
    }

    if (!isAuthorized) {
      throw new Error("Forbidden: Your account does not have permission to modify the database.");
    }

    // 2. Payload Integrity Check
    const sanitized: Partial<DatabaseRowType> = {};
    for (const [key, value] of Object.entries(input.fields)) {
      if (!VALID_FIELDS.has(key as keyof DatabaseRowType)) continue;

      if (key === 'freeSf') {
        sanitized.freeSf = (value === true || value === 'TRUE' || value === 'true') ? 'TRUE' : 'FALSE';
      } else {
        (sanitized as Record<string, unknown>)[key] = value;
      }
    }

    await Database.create({ row: sanitized });
    return { success: true };
  },
});

