    let isAuthorized = SUPER_ADMIN_EMAILS.includes(userEmail);
    if (!isAuthorized) {
      const roles = await Roles.findAll({});
      const found = roles?.find(r => (r.email || '')?.toLowerCase().trim() === userEmail);
      if (found) {
         const roleStr = (found.role || '').toLowerCase();
         if (['super_admin', 'admin', 'dispatch'].some(r => roleStr.includes(r))) {
            isAuthorized = true;
         }
      }
    }

    if (!isAuthorized) {
      throw new Error("Forbidden: Your account does not have permission for bulk updates.");
    }

    // 2. Safely process the background batch
    let count = 0;
    for (const update of input.updates) {
      const sanitized: Partial<DatabaseRowType> = {};
      for (const [key, value] of Object.entries(update.fields)) {
        if (VALID_FIELDS.has(key as keyof DatabaseRowType)) {
          (sanitized as Record<string, unknown>)[key] = value;
        }
      }

      if (Object.keys(sanitized).length > 0) {
        await Database.update({ rowId: update.rowId, row: sanitized });
        count++;
      }
    }

    return { success: true, updatedCount: count };
  },
});

