            <tr>
              <td style={{ width: '50%', padding: '16px', verticalAlign: 'middle', border: '1px solid #999' }}>
                <div style={{ fontWeight: 900, fontSize: 26, lineHeight: 1.2, textAlign: 'center' }}>
                  CUSTOMER'S INVOICE<br />COPY
                </div>
                {mopLabel && (
                  <div style={{ marginTop: '8px', textAlign: 'center' }}>
                    <div style={{ display: 'inline-block', border: '2px solid red', color: 'red', padding: '4px 12px', fontWeight: 900, fontSize: '18px', letterSpacing: '2px', textTransform: 'uppercase' }}>
                      {mopLabel}
                    </div>
                  </div>
                )}
              </td>
              <td style={{ padding: 0, verticalAlign: 'top', border: '1px solid #999' }}>
                {summaryRows.map((row, i) => (
                  <div key={i} style={{ display: 'flex', justifyContent: 'space-between', background: row.red ? 'rgba(255, 240, 240, 0.9)' : (i % 2 === 0 ? 'rgba(224, 224, 224, 0.9)' : 'rgba(245, 245, 245, 0.9)'), padding: '5px 10px', borderBottom: '1px solid #ccc' }}>
                    <span style={{ fontWeight: 700, fontSize: 11, color: row.red ? '#cc0000' : '#111' }}>{row.label}</span>
                    <span style={{ fontSize: 11, fontWeight: row.red ? 700 : 400, color: row.red ? '#cc0000' : '#111' }}>{row.value}</span>
                  </div>
                ))}
              </td>
            </tr>
          </tbody>
        </table>

        <table style={{ width: '100%', borderCollapse: 'collapse', background: 'transparent' }}>
          <tbody>
            <tr>
              <td style={{ padding: '4px 12px', border: '1px solid #999', borderBottom: 'none' }}>
                <span style={{ color: 'red', fontWeight: 700, fontSize: 11 }}>Amount in Words:</span>
              </td>
            </tr>
            <tr>
              <td style={{ padding: '4px 12px 10px', textAlign: 'center', fontWeight: 700, fontSize: 13, border: '1px solid #999' }}>
                {amountInWords}
              </td>
            </tr>
          </tbody>
        </table>

        <div style={{ padding: '8px 12px', border: '1px solid #999', marginTop: -1, background: '#fff' }}>
          <div style={{ color: 'red', fontWeight: 700, fontSize: 12, marginBottom: 4 }}>NOTE:</div>
          {NOTES.map((note, i) => (
            <div key={i} style={{ fontSize: 10, marginBottom: 2 }}>{i + 1}. {note}</div>
          ))}
        </div>
      </div>
    </div>
  );
}

import { useState, useRef } from 'react';
import { Upload, X, Loader2, CheckCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Sheet, SheetContent, SheetHeader, SheetTitle, SheetTrigger } from '@/components/ui/sheet';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { uploadFile } from 'zite-file-upload-sdk';
import { createUpload } from 'zite-endpoints-sdk';

interface Props {
  onRefresh: () => void;
}

export default function UploadMasterlistFAB({ onRefresh }: Props) {
  const [open, setOpen] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const fileRef = useRef<HTMLInputElement>(null);

  const handleUpload = async () => {
    if (!selectedFile) { toast.error('Please select a file'); return; }
    setUploading(true);
    try {
      const { fileUrl } = await uploadFile({ data: selectedFile, filename: selectedFile.name });
      await createUpload({ masterlistFile: fileUrl, status: 'Uploaded' });
      toast.success('File uploaded successfully! Refresh the records when processing is complete.');
      setOpen(false);
      setSelectedFile(null);
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Upload failed');
    } finally {
      setUploading(false);
    }
  };

  return (
    <Sheet open={open} onOpenChange={setOpen}>
      <SheetTrigger asChild>
        <Button size="sm" className="h-7 px-2 text-[10px] sm:text-xs bg-primary text-primary-foreground cursor-pointer">
          <Upload className="h-3 w-3 sm:mr-1" />
          <span className="hidden sm:inline">Upload Masterlist</span>
          <span className="sm:hidden">Upload</span>
        </Button>
      </SheetTrigger>

      <SheetContent side="bottom" className="bg-card border-border pb-8">
        <SheetHeader className="mb-4">
          <SheetTitle className="font-cinzel text-primary">Upload Masterlist</SheetTitle>
        </SheetHeader>
        <div className="space-y-4">
          <div>
            <Label className="text-sm text-muted-foreground mb-2 block">Select Excel / CSV File</Label>
            <div
              className="border-2 border-dashed border-border rounded-lg p-6 text-center cursor-pointer"
              onClick={() => fileRef.current?.click()}
            >
              {selectedFile ? (
                <div className="flex items-center justify-center gap-2">
                  <CheckCircle className="h-4 w-4 text-primary" />
                  <span className="text-sm text-foreground">{selectedFile.name}</span>
                  <button onClick={e => { e.stopPropagation(); setSelectedFile(null); }}>
                    <X className="h-4 w-4 text-muted-foreground" />
                  </button>
                </div>
              ) : (
                <div>
                  <Upload className="h-8 w-8 text-muted-foreground mx-auto mb-2" />
                  <p className="text-sm text-muted-foreground">Tap to select file</p>
                </div>
              )}
            </div>
            <input ref={fileRef} type="file" className="hidden" onChange={e => setSelectedFile(e.target.files?.[0] || null)} />
          </div>
          <Button onClick={handleUpload} disabled={uploading || !selectedFile} className="w-full bg-primary text-primary-foreground">
            {uploading ? <><Loader2 className="h-4 w-4 mr-2 animate-spin" /> Uploading...</> : 'Upload File'}
          </Button>
        </div>
      </SheetContent>
    </Sheet>
  );
}

import { useMemo, useState } from 'react';
import { ChevronDown, Layout, Crown, BookOpen, Plus, Calendar, Clock, PauseCircle } from 'lucide-react';
import { TabProps, DatabaseRowType } from '@/types';
import { applySearch, groupByMiner, groupByMinerName, formatDate } from '@/lib/formatters';
import TabHeader from '@/components/TabHeader';
import AdminClientCard from './AdminClientCard';
import ReviewChasingCard from './ReviewChasingCard';
import AddClientModal from '@/components/accounts/AddClientModal';
import { Button } from '@/components/ui/button';

export default function AdminPipeline({ records, searchQuery, onSearchChange, onUpdate, userEmail, userFirstName, onRefresh }: TabProps) {
  const [expandedPages, setExpandedPages] = useState<Record<string, boolean>>({});
  const [expandedResellers, setExpandedResellers] = useState<Record<string, boolean>>({});
  const [expandedReviewChasing, setExpandedReviewChasing] = useState<Record<string, boolean>>({});
  const [expandedWFDP, setExpandedWFDP] = useState<Record<string, boolean>>({});
  const [expandedDates, setExpandedDates] = useState<Record<string, boolean>>({});
  const [showAddModal, setShowAddModal] = useState(false);

  const pageGroups = useMemo(() => {
    const searched = applySearch(records, searchQuery);

    // FIX: The 3-day restriction is removed. Delivered items stay forever UNTIL explicitly skipped or completed.
    const activeAdminRecords = searched.filter(r => {
      const status = r.status || '';
      if (status === 'Pending' || status === 'Waiting for Details' || status === 'Waiting for Downpayment') return true;
      if (status === 'Reseller') return true;
      if (status === 'Paid/DP but Item Hold') return true;
      if (status === 'Payment for Verification') return true;
      if (status === 'Delivered') {
        if (r.reviewChasing === 'Skipped' || r.reviewChasing === 'Completed') return false;
        return true; 
      }
      return false;
    });

    const groups: Record<string, DatabaseRowType[]> = {};
    activeAdminRecords.forEach(r => {
      let pageKey = (r.page || 'Other').trim();
      if (pageKey.toUpperCase().includes('MYK')) pageKey = 'MYK';
      else if (pageKey.toUpperCase().includes('EMPIRE')) pageKey = 'Empire Gold By ETG';
      if (!groups[pageKey]) groups[pageKey] = [];
      groups[pageKey].push(r);
    });

    return Object.keys(groups)
      .sort((a, b) => {
        if (a === 'MYK') return -1; if (b === 'MYK') return 1;
        if (a === 'Empire Gold By ETG') return -1; if (b === 'Empire Gold By ETG') return 1;
        return a.localeCompare(b);
      })
      .reduce((acc, key) => { acc[key] = groups[key]; return acc; }, {} as Record<string, DatabaseRowType[]>);
  }, [records, searchQuery]);

  const togglePage = (page: string) =>
    setExpandedPages(prev => ({ ...prev, [page]: !prev[page] }));

  const toggleDate = (key: string) =>
    setExpandedDates(prev => ({ ...prev, [key]: !prev[key] }));

  const groupMinedByDate = (minedItems: DatabaseRowType[]): Map<string, Map<string, DatabaseRowType[]>> => {
    const byDate = new Map<string, Map<string, DatabaseRowType[]>>();
    for (const r of minedItems) {
      const date = r.dateOfLive || 'Unknown Date';
      const miner = r.minerName?.trim() || 'Unknown Client';
      if (!byDate.has(date)) byDate.set(date, new Map());
      const byMiner = byDate.get(date)!;
      if (!byMiner.has(miner)) byMiner.set(miner, []);
      byMiner.get(miner)!.push(r);
    }
    return new Map([...byDate.entries()].sort((a, b) => b[0].localeCompare(a[0])));
  };

  const renderPageSection = (pageName: string, pageRecords: DatabaseRowType[]) => {
    const isExpanded = expandedPages[pageName] === true;
    const minedItems = pageRecords.filter(r =>
      r.status === 'Pending' || r.status === 'Waiting for Details'
    );
    const wfdpItems = pageRecords.filter(r => r.status === 'Waiting for Downpayment');
    const resellerItems = pageRecords.filter(r => r.status === 'Reseller');
    const onHoldItems = pageRecords.filter(r => r.status === 'Paid/DP but Item Hold' || r.status === 'Payment for Verification');
    const onHoldByDate = groupMinedByDate(onHoldItems);
    const reviewChasingItems = pageRecords.filter(r => r.status === 'Delivered');
    const minedByDate = groupMinedByDate(minedItems);
    const wfdpByDate = groupMinedByDate(wfdpItems);
    const resellerGrouped = groupByMiner(resellerItems);
    const reviewChasingGroups = groupByMinerName(reviewChasingItems);

    return (
      <div key={pageName} className="mb-10">
        <div
          className="flex items-center gap-3 py-2.5 px-4 bg-secondary/40 rounded-xl cursor-pointer mb-4 border border-primary/10 hover:bg-secondary/60 transition-colors"
          onClick={() => togglePage(pageName)}
        >
          {pageName === 'MYK' ? <Crown className="h-5 w-5 text-yellow-500" />
            : pageName === 'Empire Gold By ETG' ? <BookOpen className="h-5 w-5 text-primary" />
            : <Layout className="h-5 w-5 text-muted-foreground" />}
          <h2 className="font-cinzel text-base font-bold text-primary tracking-widest uppercase">{pageName}</h2>
          <div className="h-px flex-1 bg-primary/10" />
          <span className="text-[10px] font-bold bg-primary/20 text-primary px-2 py-0.5 rounded-md">{pageRecords.length}</span>
          <ChevronDown className={`h-5 w-5 text-muted-foreground transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
        </div>

        {isExpanded && (
          <div className="pl-2 sm:pl-4 space-y-8 animate-in fade-in slide-in-from-top-2 duration-300">
            {minedByDate.size > 0 && (
              <div>
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-[10px] font-black text-muted-foreground uppercase tracking-[0.2em] pl-1">Mined Items</span>
                  <div className="h-px flex-1 bg-border/60" />
                </div>
                {Array.from(minedByDate.entries()).map(([date, minerMap]) => {
                  const dateKey = `${pageName}__${date}`;
                  const isDateExpanded = expandedDates[dateKey] === true;
                  const totalItems = Array.from(minerMap.values()).reduce((s, v) => s + v.length, 0);
                  return (
                    <div key={date} className="mb-3">
                      <div
                        className="flex items-center gap-2 py-2 px-3 bg-primary/10 rounded-lg cursor-pointer mb-2 border border-primary/20 hover:bg-primary/15 transition-colors"
                        onClick={() => toggleDate(dateKey)}
                      >
                        <Calendar className="h-3.5 w-3.5 text-primary" />
                        <span className="text-xs font-bold text-primary uppercase tracking-widest">{formatDate(date)}</span>
                        <div className="h-px flex-1 bg-primary/20" />
                        <span className="text-[10px] font-bold bg-primary/20 text-primary px-2 py-0.5 rounded-md">{totalItems}</span>
                        <ChevronDown className={`h-4 w-4 text-primary transition-transform duration-200 ${isDateExpanded ? 'rotate-180' : ''}`} />
                      </div>
                      {isDateExpanded && (
                        <div className="pl-2 animate-in fade-in slide-in-from-top-1 duration-200">
                          {Array.from(minerMap.entries()).map(([name, items]) => (
                            <AdminClientCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} userEmail={userEmail} />
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}

            {wfdpByDate.size > 0 && (() => {
              const isWFDPExpanded = expandedWFDP[pageName] === true;
              const totalWFDP = wfdpItems.length;
              return (
                <div>
                  <div
                    className="flex items-center gap-2 mb-3 cursor-pointer"
                    onClick={() => setExpandedWFDP(prev => ({ ...prev, [pageName]: !prev[pageName] }))}
                  >
                    <Clock className="h-3.5 w-3.5 text-orange-400" />
                    <span className="text-[10px] font-black text-orange-400 uppercase tracking-[0.2em] pl-1">Waiting for Downpayment</span>
                    <div className="h-px flex-1 bg-orange-400/20" />
                    <span className="text-[10px] font-bold bg-orange-400/20 text-orange-400 px-2 py-0.5 rounded-md">{totalWFDP}</span>
                    <ChevronDown className={`h-4 w-4 text-orange-400 transition-transform duration-200 ${isWFDPExpanded ? 'rotate-180' : ''}`} />
                  </div>
                  {isWFDPExpanded && (
                    <div className="pl-2 animate-in fade-in slide-in-from-top-1 duration-200">
                      {Array.from(wfdpByDate.entries()).map(([date, minerMap]) => {
                        const dateKey = `wfdp__${pageName}__${date}`;
                        const isDateExpanded = expandedDates[dateKey] === true;
                        const totalItems = Array.from(minerMap.values()).reduce((s, v) => s + v.length, 0);
                        return (
                          <div key={date} className="mb-3">
                            <div
                              className="flex items-center gap-2 py-2 px-3 bg-orange-400/10 rounded-lg cursor-pointer mb-2 border border-orange-400/20 hover:bg-orange-400/15 transition-colors"
                              onClick={() => toggleDate(dateKey)}
                            >
                              <Calendar className="h-3.5 w-3.5 text-orange-400" />
                              <span className="text-xs font-bold text-orange-400 uppercase tracking-widest">{formatDate(date)}</span>
                              <div className="h-px flex-1 bg-orange-400/20" />
                              <span className="text-[10px] font-bold bg-orange-400/20 text-orange-400 px-2 py-0.5 rounded-md">{totalItems}</span>
                              <ChevronDown className={`h-4 w-4 text-orange-400 transition-transform duration-200 ${isDateExpanded ? 'rotate-180' : ''}`} />
                            </div>
                            {isDateExpanded && (
                              <div className="pl-2 animate-in fade-in slide-in-from-top-1 duration-200">
                                {Array.from(minerMap.entries()).map(([name, items]) => (
                                  <AdminClientCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} userEmail={userEmail} />
                                ))}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })()}

            {onHoldByDate.size > 0 && (() => {
              const isOnHoldExpanded = expandedDates[`onhold__${pageName}`] === true;
              const totalOnHold = onHoldItems.length;
              return (
                <div>
                  <div
                    className="flex items-center gap-2 mb-3 cursor-pointer"
                    onClick={() => toggleDate(`onhold__${pageName}`)}
                  >
                    <PauseCircle className="h-3.5 w-3.5 text-indigo-400" />
                    <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em] pl-1">Paid/DP but Item Hold</span>
                    <div className="h-px flex-1 bg-indigo-400/20" />
                    <span className="text-[10px] font-bold bg-indigo-400/20 text-indigo-400 px-2 py-0.5 rounded-md">{totalOnHold}</span>
                    <ChevronDown className={`h-4 w-4 text-indigo-400 transition-transform duration-200 ${isOnHoldExpanded ? 'rotate-180' : ''}`} />
                  </div>
                  {isOnHoldExpanded && (
                    <div className="pl-2 animate-in fade-in slide-in-from-top-1 duration-200">
                      {Array.from(onHoldByDate.entries()).map(([date, minerMap]) => {
                        const dateKey = `onhold__${pageName}__${date}`;
                        const isDateExpanded = expandedDates[dateKey] === true;
                        const totalItems = Array.from(minerMap.values()).reduce((s, v) => s + v.length, 0);
                        return (
                          <div key={date} className="mb-3">
                            <div
                              className="flex items-center gap-2 py-2 px-3 bg-indigo-400/10 rounded-lg cursor-pointer mb-2 border border-indigo-400/20 hover:bg-indigo-400/15 transition-colors"
                              onClick={() => toggleDate(dateKey)}
                            >
                              <Calendar className="h-3.5 w-3.5 text-indigo-400" />
                              <span className="text-xs font-bold text-indigo-400 uppercase tracking-widest">{formatDate(date)}</span>
                              <div className="h-px flex-1 bg-indigo-400/20" />
                              <span className="text-[10px] font-bold bg-indigo-400/20 text-indigo-400 px-2 py-0.5 rounded-md">{totalItems}</span>
                              <ChevronDown className={`h-4 w-4 text-indigo-400 transition-transform duration-200 ${isDateExpanded ? 'rotate-180' : ''}`} />
                            </div>
                            {isDateExpanded && (
                              <div className="pl-2 animate-in fade-in slide-in-from-top-1 duration-200">
                                {Array.from(minerMap.entries()).map(([name, items]) => (
                                  <AdminClientCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} userEmail={userEmail} />
                                ))}
                              </div>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })()}

            {resellerGrouped.size > 0 && (() => {
              const isResellerExpanded = expandedResellers[pageName] === true;
              return (
                <div>
                  <div
                    className="flex items-center gap-2 mb-4 cursor-pointer"
                    onClick={() => setExpandedResellers(prev => ({ ...prev, [pageName]: prev[pageName] === undefined ? false : !prev[pageName] }))}
                  >
                    <span className="text-[10px] font-black text-teal-500 uppercase tracking-[0.2em] pl-1">Resellers</span>
                    <div className="h-px flex-1 bg-teal-500/20" />
                    <span className="text-[10px] font-bold bg-teal-500/20 text-teal-500 px-2 py-0.5 rounded-md">{resellerGrouped.size}</span>
                    <ChevronDown className={`h-4 w-4 text-teal-500 transition-transform duration-200 ${isResellerExpanded ? 'rotate-180' : ''}`} />
                  </div>
                  {isResellerExpanded && Array.from(resellerGrouped.entries()).map(([name, items]) => (
                    <AdminClientCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} userEmail={userEmail} />
                  ))}
                </div>
              );
            })()}

            {reviewChasingGroups.size > 0 && (() => {
              const isReviewExpanded = expandedReviewChasing[pageName] === true;
              return (
                <div>
                  <div
                    className="flex items-center gap-2 mb-4 cursor-pointer"
                    onClick={() => setExpandedReviewChasing(prev => ({ ...prev, [pageName]: prev[pageName] === undefined ? false : !prev[pageName] }))}
                  >
                    <span className="text-[10px] font-black text-primary uppercase tracking-[0.2em] pl-1">Review Chasing</span>
                    <div className="h-px flex-1 bg-primary/20" />
                    <span className="text-[10px] font-bold bg-primary/20 text-primary px-2 py-0.5 rounded-md">{reviewChasingGroups.size}</span>
                    <ChevronDown className={`h-4 w-4 text-primary transition-transform duration-200 ${isReviewExpanded ? 'rotate-180' : ''}`} />
                  </div>
                  {isReviewExpanded && (
                    <div className="grid grid-cols-1 gap-3">
                      {Array.from(reviewChasingGroups.entries()).map(([name, items]) => (
                        <ReviewChasingCard key={name} minerName={name} records={items} allRecords={records} onUpdate={onUpdate} />
                      ))}
                    </div>
                  )}
                </div>
              );
            })()}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader title="Admin Pipeline" subtitle="Active Tasks & Pipeline" searchQuery={searchQuery} onSearchChange={onSearchChange} />
      <div className="px-4 pt-4">
        <div className="flex justify-end mb-4">
          <Button onClick={() => setShowAddModal(true)} className="bg-primary text-primary-foreground hover:bg-primary/90 text-xs h-9 shadow-sm">
            <Plus className="h-4 w-4 mr-1.5" /> Add Client
          </Button>
        </div>
      </div>
      <div className="px-4">
        {Object.keys(pageGroups).length > 0
          ? Object.keys(pageGroups).map(page => renderPageSection(page, pageGroups[page]))
          : (
            <div className="text-center py-24 border-2 border-dashed border-border rounded-2xl">
              <p className="text-sm text-muted-foreground font-medium">No records found matching your search.</p>
            </div>
          )}
      </div>
      {showAddModal && <AddClientModal onClose={() => setShowAddModal(false)} userFirstName={userFirstName} userEmail={userEmail} onRefresh={onRefresh} existingRecords={records} />}
    </div>
  );
}

import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { formatDate } from '@/lib/formatters';

interface Props {
  date: string;
  onConfirm: (phpRate: number, silverRate?: number, silverBrandedRate?: number) => void;
  onSkip: () => void;
}

export default function PhpRateDialog({ date, onConfirm, onSkip }: Props) {
  const [phpRate, setPhpRateVal] = useState('');
  const [silverRate, setSilverRateVal] = useState('');
  const [silverBrandedRate, setSilverBrandedRateVal] = useState('');

  const phpParsed = parseFloat(phpRate);
  const isValid = !isNaN(phpParsed) && phpParsed > 0;

  const handleConfirm = () => {
    if (!isValid) return;
    const sr = parseFloat(silverRate);
    const sbr = parseFloat(silverBrandedRate);
    onConfirm(phpParsed, isNaN(sr) ? undefined : sr, isNaN(sbr) ? undefined : sbr);
  };

  return (
    <Dialog open onOpenChange={onSkip}>
      <DialogContent className="bg-card border-border max-w-sm">
        <DialogHeader>
          <DialogTitle className="font-cinzel text-primary text-base">
            Set Rates for {formatDate(date)}
          </DialogTitle>
        </DialogHeader>
        <div className="py-2 space-y-4">
          <p className="text-xs text-muted-foreground">
            Pinas client detected. Set today's rates — these will be locked for all clients on this date.
          </p>

          <div>
            <Label className="text-xs text-muted-foreground">PHP Conversion Rate (1 AED =)</Label>
            <div className="flex items-center gap-2 mt-1">
              <Input type="number" step="0.01" value={phpRate} onChange={e => setPhpRateVal(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleConfirm()}
                placeholder="e.g. 16.80" className="h-9 text-sm bg-background border-border" autoFocus />
              <span className="text-sm font-semibold shrink-0">PHP</span>
            </div>
          </div>

          <div>
            <Label className="text-xs text-muted-foreground">Silver Rate (AED/gram) — optional</Label>
            <div className="flex items-center gap-2 mt-1">
              <Input type="number" step="0.5" value={silverRate} onChange={e => setSilverRateVal(e.target.value)}
                placeholder={`default: 45`} className="h-9 text-sm bg-background border-border" />
              <span className="text-sm font-semibold shrink-0">AED</span>
            </div>
          </div>

          <div>
            <Label className="text-xs text-muted-foreground">Silver Branded Rate (AED/gram) — optional</Label>
            <div className="flex items-center gap-2 mt-1">
              <Input type="number" step="0.5" value={silverBrandedRate} onChange={e => setSilverBrandedRateVal(e.target.value)}
                placeholder={`default: 60`} className="h-9 text-sm bg-background border-border" />
              <span className="text-sm font-semibold shrink-0">AED</span>
            </div>
          </div>
        </div>
        <DialogFooter className="gap-2">
          <Button variant="outline" size="sm" className="text-xs border-border" onClick={onSkip}>Skip</Button>
          <Button size="sm" className="text-xs bg-primary text-primary-foreground" disabled={!isValid} onClick={handleConfirm}>
            Lock Rates
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useMemo } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { DatabaseRowType } from '@/types';
import { calcItemPriceAED, calcTotalPaid, parseDateRobust } from '@/lib/calculations';
import { formatDate } from '@/lib/formatters';
import { Copy, CheckCircle2 } from 'lucide-react';
import { toast } from 'sonner';

interface Props {
  customerId: string;
  minerName: string;
  allRecords: DatabaseRowType[];
  onClose: () => void;
}

export default function CustomerHistoryModal({ customerId, minerName, allRecords, onClose }: Props) {
  const customerRecords = useMemo(() => {
    return allRecords
      .filter(r => r.customerId === customerId)
      .sort((a, b) => {
        const dateA = a.dateOfLive ? (parseDateRobust(a.dateOfLive)?.getTime() || 0) : 0;
        const dateB = b.dateOfLive ? (parseDateRobust(b.dateOfLive)?.getTime() || 0) : 0;
        return dateB - dateA;
      });
  }, [allRecords, customerId]);

  const summary = useMemo(() => {
    const totalItems = customerRecords.length;
    const activeItems = customerRecords.filter(r => r.status !== 'Cancelled' && r.status !== 'Returned Item');
    const totalSpent = activeItems.reduce((sum, r) => sum + calcItemPriceAED(r), 0);
    const totalPaid = activeItems.reduce((sum, r) => sum + calcTotalPaid(r), 0);
    const balance = Math.max(0, totalSpent - totalPaid);
    return { totalItems, activeCount: activeItems.length, totalSpent, balance };
  }, [customerRecords]);

  const handleCopyId = () => {
    navigator.clipboard.writeText(customerId);
    toast.success('Customer ID copied to clipboard!');
  };

  return (
    <Dialog open onOpenChange={onClose}>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto bg-card border-border">
        <DialogHeader>
          <DialogTitle className="font-cinzel text-primary flex items-center justify-between pr-6">
            <span>Client Ledger: {minerName.toUpperCase()}</span>
            <button 
              onClick={handleCopyId}
              className="group flex items-center gap-1.5 px-2.5 py-1 rounded bg-secondary/50 hover:bg-primary/10 transition-colors border border-border hover:border-primary/30"
              title="Copy Customer ID"
            >
              <span className="text-xs font-mono text-muted-foreground group-hover:text-primary transition-colors">{customerId}</span>
              <Copy className="h-3 w-3 text-muted-foreground group-hover:text-primary transition-colors" />
            </button>
          </DialogTitle>
        </DialogHeader>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 my-4">
          <div className="bg-secondary/30 border border-border rounded-lg p-3 text-center">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-1">Total Items</p>
            <p className="text-lg font-bold">{summary.totalItems}</p>
          </div>
          <div className="bg-secondary/30 border border-border rounded-lg p-3 text-center">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-1">Active Items</p>
            <p className="text-lg font-bold">{summary.activeCount}</p>
          </div>
          <div className="bg-secondary/30 border border-border rounded-lg p-3 text-center">
            <p className="text-[10px] uppercase tracking-wider text-muted-foreground mb-1">Total Value</p>
            <p className="text-lg font-bold text-foreground">AED {summary.totalSpent.toFixed(2)}</p>
          </div>
          <div className="bg-primary/5 border border-primary/20 rounded-lg p-3 text-center">
            <p className="text-[10px] uppercase tracking-wider text-primary/80 mb-1">Outstanding</p>
            <p className={`text-lg font-bold ${summary.balance > 0 ? 'text-destructive' : 'text-green-500'}`}>
              AED {summary.balance.toFixed(2)}
            </p>
          </div>
        </div>

        <div className="space-y-3">
          {customerRecords.map(record => {
            const price = calcItemPriceAED(record);
            const paid = calcTotalPaid(record);
            const balance = Math.max(0, price - paid);
            const isDead = record.status === 'Cancelled' || record.status === 'Returned Item';

            return (
              <div key={record.id} className={`p-4 rounded-xl border ${isDead ? 'border-border/50 bg-background/50 opacity-70' : 'border-border bg-card'}`}>
                <div className="flex flex-col md:flex-row justify-between gap-4">
                  <div className="space-y-1">
                    <div className="flex items-center gap-2">
                      <span className="text-xs font-semibold px-2 py-0.5 rounded-full bg-secondary text-secondary-foreground border border-border">
                        {record.status || 'Unknown'}
                      </span>
                      <span className="text-xs text-muted-foreground">{formatDate(record.dateOfLive)}</span>
                    </div>
                    <p className="text-sm font-medium mt-1">{record.itemDescription}</p>
                    <div className="flex items-center gap-3 text-xs text-muted-foreground">
                      {record.orderId && <span>ID: <span className="font-mono">{record.orderId}</span></span>}
                      <span>{record.category || 'N/A'}</span>
                      {record.grams && <span>{Number(record.grams).toFixed(2)}g</span>}
                    </div>
                  </div>

                  <div className="flex flex-col items-end justify-center min-w-[120px] shrink-0">
                    {!isDead && (
                      <>
                        <div className="text-right w-full flex justify-between gap-4 mb-0.5">
                          <span className="text-xs text-muted-foreground">Price:</span>
                          <span className="text-sm font-medium">AED {price.toFixed(2)}</span>
                        </div>
                        <div className="text-right w-full flex justify-between gap-4 mb-1">
                          <span className="text-xs text-muted-foreground">Paid:</span>
                          <span className="text-sm font-medium text-green-500">AED {paid.toFixed(2)}</span>
                        </div>
                        <div className="w-full h-px bg-border my-1" />
                        <div className="text-right w-full flex justify-between gap-4">
                          <span className="text-[10px] uppercase tracking-wide text-muted-foreground self-center">Bal:</span>
                          <span className={`text-sm font-bold ${balance > 0 ? 'text-destructive' : 'text-green-500 flex items-center gap-1'}`}>
                            {balance === 0 && <CheckCircle2 className="w-3.5 h-3.5" />}
                            AED {balance.toFixed(2)}
                          </span>
                        </div>
                      </>
                    )}
                  </div>
                </div>
              </div>
            );
          })}

          {customerRecords.length === 0 && (
            <div className="text-center py-8 text-muted-foreground border border-dashed border-border rounded-xl">
              No history found for this customer.
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { DatabaseRowType } from '@/types';

const LOCATION_OPTIONS = ['Local', 'Pinas', 'Dubai'];

interface Props {
  record: DatabaseRowType;
  onSave: (fields: Partial<DatabaseRowType>) => Promise<void>;
  onClose: () => void;
}

export default function EditItemDialog({ record, onSave, onClose }: Props) {
  const [minerName, setMinerName] = useState(record.minerName || '');
  const [grams, setGrams] = useState(record.grams != null ? String(record.grams) : '');
  const [location, setLocation] = useState(record.locationOfMiner || '');
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    setSaving(true);
    const fields: Partial<DatabaseRowType> = { minerName };
    if (grams !== '') fields.grams = parseFloat(grams) || 0;
    if (location) fields.locationOfMiner = location;
    await onSave(fields);
    setSaving(false);
    onClose();
  };

  return (
    <Dialog open onOpenChange={onClose}>
      <DialogContent className="bg-card border-border max-w-sm">
        <DialogHeader>
          <DialogTitle className="text-sm font-semibold">Edit Item Details</DialogTitle>
        </DialogHeader>
        <div className="space-y-3 py-1">
          <div>
            <Label className="text-xs text-muted-foreground">Client / Miner Name</Label>
            <Input
              value={minerName}
              onChange={e => setMinerName(e.target.value)}
              className="h-8 text-xs mt-0.5 bg-background border-border"
              placeholder="Enter name..."
            />
          </div>
          <div>
            <Label className="text-xs text-muted-foreground">Grams</Label>
            <Input
              type="number"
              value={grams}
              onChange={e => setGrams(e.target.value)}
              className="h-8 text-xs mt-0.5 bg-background border-border"
              placeholder="e.g. 7.28"
            />
          </div>
          <div>
            <Label className="text-xs text-muted-foreground">Location of Miner</Label>
            <Select value={location} onValueChange={setLocation}>
              <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border">
                <SelectValue placeholder="Select location..." />
              </SelectTrigger>
              <SelectContent className="bg-popover border-border">
                {LOCATION_OPTIONS.map(opt => (
                  <SelectItem key={opt} value={opt} className="text-xs">{opt}</SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        </div>
        <DialogFooter className="gap-2">
          <Button variant="outline" size="sm" onClick={onClose} disabled={saving}>Cancel</Button>
          <Button size="sm" onClick={handleSave} disabled={saving} className="bg-primary text-primary-foreground">
            {saving ? 'Saving...' : 'Save'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState, memo, useMemo, useEffect } from 'react';
import { ChevronDown, FileText, MapPin, Upload, History } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { DatabaseRowType } from '@/types';
import { isOverdue } from '@/lib/calculations';
import { formatDate } from '@/lib/formatters';
import { getPhpRate, setPhpRate, hasPhpRate, setSilverRate, setSilverBrandedRate } from '@/lib/ratesStore';
import StatusBadge from '@/components/StatusBadge';
import AdminItemRow from './AdminItemRow';
import PhpRateDialog from './PhpRateDialog';
import InvoiceModal from '@/components/InvoiceModal';
import CustomerHistoryModal from '@/components/CustomerHistoryModal';

interface Props {
  minerName: string;
  records: DatabaseRowType[];
  allRecords: DatabaseRowType[];
  onUpdate: (rowId: number, fields: Partial<DatabaseRowType>) => Promise<void>;
  userEmail?: string;
}

function isPinasRecord(r: DatabaseRowType) {
  return r.locationOfMiner === 'Pinas' || r.currency === 'PHP';
}

function AdminClientCard({ minerName, records, allRecords, onUpdate, userEmail }: Props) {
  const [expanded, setExpanded] = useState(false);
  const [showInvoice, setShowInvoice] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [collapsedDates, setCollapsedDates] = useState<Record<string, boolean>>({});
  const [phpRateDialogDate, setPhpRateDialogDate] = useState<string | null>(null);
  const [phpRates, setPhpRates] = useState<Record<string, number>>({});
  const first = records[0];
  const hasOverdue = records.some(isOverdue);

  const uniqueDates = useMemo(() => {
    const dates = [...new Set(records.map(r => r.dateOfLive).filter(Boolean) as string[])].sort();
    return dates;
  }, [records]);

  const dateLabel = uniqueDates.length === 1
    ? formatDate(uniqueDates[0])
    : uniqueDates.length > 1
      ? `${formatDate(uniqueDates[0])} – ${formatDate(uniqueDates[uniqueDates.length - 1])}`
      : '—';

  const grouped = useMemo(() => {
    const map: Record<string, Record<string, Record<string, DatabaseRowType[]>>> = {};
    for (const r of records) {
      const date = r.dateOfLive || 'Unknown Date';
      const liver = r.liverName?.trim().toUpperCase() || 'UNKNOWN LIVER';
      const status = r.status || 'No Status';
      if (!map[date]) map[date] = {};
      if (!map[date][liver]) map[date][liver] = {};
      if (!map[date][liver][status]) map[date][liver][status] = [];
      map[date][liver][status].push(r);
    }
    return map;
  }, [records]);

  const sortedDates = Object.keys(grouped).sort();

  const toggleDate = (date: string) =>
    setCollapsedDates(prev => ({ ...prev, [date]: !prev[date] }));

  const handleGroupUpdate = async (fields: Partial<DatabaseRowType>) => {
    for (const r of records) {
      await onUpdate(r.id, fields);
      await new Promise(res => setTimeout(res, 300));
    }
  };

  useEffect(() => {
    if (!expanded) return;
    const hasPinas = records.some(isPinasRecord);
    if (!hasPinas) return;

    const loaded: Record<string, number> = {};
    for (const date of uniqueDates) {
      const r = getPhpRate(date);
      if (r !== null) loaded[date] = r;
    }
    setPhpRates(loaded);

    const pinasRecords = records.filter(isPinasRecord);
    const pinasDates = [...new Set(pinasRecords.map(r => r.dateOfLive).filter(Boolean) as string[])];
    const needsRate = pinasDates.find(d => !hasPhpRate(d));
    if (needsRate) setPhpRateDialogDate(needsRate);
  }, [expanded, records, uniqueDates]);

  const handleRateConfirm = (phpRate: number, silverRate?: number, silverBrandedRate?: number) => {
    if (!phpRateDialogDate) return;
    setPhpRate(phpRateDialogDate, phpRate);
    if (silverRate) setSilverRate(phpRateDialogDate, silverRate);
    if (silverBrandedRate) setSilverBrandedRate(phpRateDialogDate, silverBrandedRate);
    setPhpRates(prev => ({ ...prev, [phpRateDialogDate]: phpRate }));
    setPhpRateDialogDate(null);
  };

  const invoicePhpRate = useMemo(() => {
    const pinasRecords = records.filter(isPinasRecord);
    if (pinasRecords.length === 0) return undefined;
    const date = pinasRecords[0].dateOfLive;
    if (!date) return undefined;
    return phpRates[date] ?? getPhpRate(date) ?? undefined;
  }, [records, phpRates]);

  const hasInvoiceNumber = first?.pureWeight && String(first.pureWeight).trim() !== '';

  return (
    <div className="mb-3 rounded-xl border border-border bg-card overflow-hidden">
      <button
        className="w-full text-left px-4 py-3 flex items-center justify-between"
        onClick={() => setExpanded(e => !e)}
      >
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <span className="font-cinzel text-sm text-primary truncate">{minerName}</span>
            {hasOverdue && (
              <span className="shrink-0 text-xs font-bold text-destructive bg-destructive/10 border border-destructive/30 px-1.5 py-0.5 rounded animate-pulse">NEEDS ATTENTION</span>
            )}
            {first?.customerId && (
              <button
                className="shrink-0 text-muted-foreground hover:text-primary transition-colors"
                title="View Lifetime History"
                onClick={e => { e.stopPropagation(); setShowHistory(true); }}
              >
                <History className="h-3.5 w-3.5" />
              </button>
            )}
          </div>
          <div className="flex flex-wrap gap-x-3 gap-y-0.5 text-xs text-muted-foreground">
            <span className="flex items-center gap-1"><MapPin className="h-3 w-3" />{first?.locationOfMiner || '—'}</span>
            {first?.liverName && <span className="flex items-center gap-1"><Upload className="h-3 w-3" />{first.liverName}</span>}
            <span>{records.length} item{records.length !== 1 ? 's' : ''}</span>
          </div>
          <div className="text-[11px] text-primary/70 font-semibold mt-0.5">📅 {dateLabel}</div>
        </div>
        <ChevronDown className={`h-4 w-4 text-muted-foreground shrink-0 ml-2 transition-transform ${expanded ? 'rotate-180' : ''}`} />
      </button>

      {expanded && (
        <div className="px-3 pb-3 border-t border-border pt-3">
          {records.some(isPinasRecord) && invoicePhpRate && (
            <div className="flex items-center justify-between mb-2 px-2 py-1.5 rounded-lg bg-amber-500/10 border border-amber-500/20">
              <span className="text-xs text-amber-400 font-medium">
                💱 1 AED = {invoicePhpRate} PHP
              </span>
              <button
                className="text-[10px] text-amber-400/70 underline"
                onClick={() => setPhpRateDialogDate(records.filter(isPinasRecord)[0]?.dateOfLive || null)}
              >
                Change
              </button>
            </div>
          )}

          <Button
            variant="outline"
            size="sm"
            onClick={(e) => {
              if (!hasInvoiceNumber) {
                e.preventDefault();
                e.stopPropagation();
                return;
              }
              setShowInvoice(true);
            }}
            disabled={!hasInvoiceNumber}
            className={`w-full mb-3 text-xs ${!hasInvoiceNumber ? 'opacity-50 cursor-not-allowed pointer-events-none bg-secondary/50 text-muted-foreground border-border' : 'border-primary/40 text-primary hover:bg-primary/10'}`}
          >
            <FileText className="h-3.5 w-3.5 mr-1.5" /> 
            {hasInvoiceNumber ? `Generate Invoice (${records.length} items)` : 'Click "Gen" on an item below to unlock'}
          </Button>

          {sortedDates.map(date => {
