function generateCustomerId(): string {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let id = 'CUST-';
  for (let i = 0; i < 5; i++) id += chars[Math.floor(Math.random() * chars.length)];
  return id;
}

function resolveCustomerId(minerName: string, existingRecords: DatabaseRowType[]): string {
  const key = minerName.trim().toLowerCase();
  const match = existingRecords.find(r => r.minerName?.trim().toLowerCase() === key && r.customerId);
  return match?.customerId || generateCustomerId();
}

