export default function AddClientModal({ onClose, userFirstName, userEmail, onRefresh, existingRecords = [] }: Props) {
  const [saving, setSaving] = useState(false);
  const [phpRate, setPhpRate] = useState('16.6');
  const [form, setForm] = useState({
    minerName: '',
    itemDescription: '',
    category: '',
    mc: '',
    grams: '',
    clientRate: '',
    goldRate: '',
    orderId: '',
    currency: 'AED',
    modeOfPayment: '',
    modeOfSale: '',
    source: '',
    locationOfMiner: 'Local',
    regions: '',
    status: 'Walk-in',
    remittanceStatus: 'Pending Payment',
    dateOfLive: new Date().toISOString().split('T')[0],
    liverName: userFirstName || '',
    page: '',
    tog: '',
    supplierRateOverride: '',
  });

  const set = (key: string, val: string) => setForm(p => ({ ...p, [key]: val }));

  const isManualSupplierRate = form.category === 'Diamond' || form.category === 'Per PC';
  const autoSupplierRate = useMemo(() => {
    const gr = parseFloat(form.goldRate) || 0;
    const mc = parseFloat(form.mc) || 0;
    return gr > 0 || mc > 0 ? (gr + mc).toFixed(2) : '';
  }, [form.goldRate, form.mc]);
  const supplierRate = isManualSupplierRate ? form.supplierRateOverride : autoSupplierRate;

  const getPerPcSupplierRate = (tog: string, category: string) => {
    if (category === 'Per PC') {
      if (tog === 'S-925') return '32';
      return '115';
    }
    return '';
  };

  const handleCategoryChange = (val: string) => {
    let newMc = form.mc;
    let newGoldRate = form.goldRate;
    let newSupplierRateOverride = form.supplierRateOverride;

    if (val === 'Normal') newMc = '16';
    else if (val === 'Special Price') newMc = '21';
    else if (val === 'Special Price EF') newMc = '25';
    else if (val === 'Silver' || val === 'Silver Branded') newMc = '0';
    else if (val === 'Diamond') {
      newMc = '0';
      newGoldRate = '0';
      newSupplierRateOverride = '';
    } else if (val === 'Per PC') {
      newMc = '0';
      newGoldRate = '0';
      newSupplierRateOverride = getPerPcSupplierRate(form.tog, val);
    }
    setForm(p => ({ ...p, category: val, mc: newMc, goldRate: newGoldRate, supplierRateOverride: newSupplierRateOverride }));
  };

  const handleTogChange = (val: string) => {
    const updates: Partial<typeof form> = { tog: val };
    if (form.category === 'Per PC') {
      updates.supplierRateOverride = getPerPcSupplierRate(val, 'Per PC');
    }
    setForm(p => ({ ...p, ...updates }));
  };

  const isDuplicateBarcode = useMemo(() => {
    if (!form.orderId.trim()) return false;
    const target = form.orderId.trim().toUpperCase();
    return existingRecords.some(r => r.orderId?.trim().toUpperCase() === target);
  }, [form.orderId, existingRecords]);

  const handleSave = async (isBulkAdd: boolean) => {
    if (!form.minerName.trim() || !form.itemDescription.trim()) {
      toast.error('Client name and item description are required');
      return;
    }
    if (!form.page) {
      toast.error('Page is required');
      return;
    }
    if (isDuplicateBarcode) {
      toast.error('Cannot save: This Order ID/Barcode already exists in the system.');
      return;
    }

    setSaving(true);

    const finalMinerName = form.minerName.trim().toUpperCase();
    const finalItemDesc = form.itemDescription.trim().toUpperCase();
    const finalOrderId = form.orderId ? form.orderId.trim().toUpperCase() : undefined;

    try {
      const preview: DatabaseRowType = {
        id: 0,
        minerName: finalMinerName,
        itemDescription: finalItemDesc,
        category: form.category,
        mc: form.mc,
        grams: form.grams ? parseFloat(form.grams) : undefined,
        clientRate: form.clientRate ? parseFloat(form.clientRate) : undefined,
        goldRate: form.goldRate ? parseFloat(form.goldRate) : undefined,
        supplierRate: (isManualSupplierRate ? form.supplierRateOverride : supplierRate) || undefined,
        currency: form.currency,
        tog: form.tog || undefined,
      };

      const profit = (calcItemPriceAED(preview) - calcItemCostAED(preview)).toFixed(2);

      const timestamp = new Date().toLocaleString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' });
      const creator = userEmail ? userEmail.split('@')[0] : (form.liverName || 'unknown');
      const auditTrail = `[Created by ${creator} on ${timestamp}]`;
      const customerId = resolveCustomerId(finalMinerName, existingRecords);

      await createRecord({
        fields: {
          minerName: finalMinerName,
          itemDescription: finalItemDesc,
          category: form.category,
          orderId: finalOrderId,
          mc: form.mc ? parseFloat(form.mc) : undefined,
          grams: form.grams ? parseFloat(form.grams) : undefined,
          clientRate: form.clientRate ? parseFloat(form.clientRate) : undefined,
          goldRate: form.goldRate ? parseFloat(form.goldRate) : undefined,
          supplierRate: (isManualSupplierRate ? form.supplierRateOverride : supplierRate) || undefined,
          pureWeight: undefined,
          currency: form.currency,
          modeOfPayment: form.modeOfPayment || undefined,
          modeOfSale: form.modeOfSale || undefined,
          source: form.source || undefined,
          locationOfMiner: form.locationOfMiner,
          regions: form.regions || undefined,
          status: form.status,
          remittanceStatus: form.remittanceStatus,
          dateOfLive: form.dateOfLive,
          liverName: form.liverName || undefined,
          page: form.page,
          tog: form.tog || undefined,
          reviewChasing: 'Pending',
          profit,
          auditTrail,
          customerId,
        },
      });
      if (isPinas && phpRate) {
        savePhpRate(form.dateOfLive, parseFloat(phpRate));
      }

      toast.success(isBulkAdd ? 'Item added! Ready for next item.' : 'Client record created');
      onRefresh?.();

      if (isBulkAdd) {
        setForm(p => ({ 
          ...p, 
          itemDescription: '', 
          grams: '', 
          orderId: '', 
          tog: '', 
          category: '', 
          mc: '', 
          goldRate: '', 
          clientRate: '', 
          supplierRateOverride: '' 
        }));
      } else {
        onClose();
      }

    } catch {
      toast.error('Failed to create record');
    } finally {
      setSaving(false);
    }
  };

  const isPinas = form.locationOfMiner === 'Pinas';

  return (
    <Dialog open onOpenChange={onClose}>
      <DialogContent className="max-w-md bg-card border-border max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="font-cinzel text-primary">Add Client Record</DialogTitle>
        </DialogHeader>

        <div className="space-y-3 text-sm">
          <div className="grid grid-cols-2 gap-2">
            <div className="col-span-2">
              <Label className="text-xs text-muted-foreground">Client Name *</Label>
              <Input value={form.minerName} onChange={e => set('minerName', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border uppercase" placeholder="Miner / Client name" />
            </div>
            <div className="col-span-2">
              <Label className="text-xs text-muted-foreground">Item Description *</Label>
              <Input value={form.itemDescription} onChange={e => set('itemDescription', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border uppercase" placeholder="e.g. GOLD RING 18K" />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Page *</Label>
              <Select value={form.page} onValueChange={v => set('page', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {PAGE_OPTIONS.map(p => <SelectItem key={p} value={p} className="text-xs">{p}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Liver Name</Label>
              <Input value={form.liverName} onChange={e => set('liverName', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="Liver name" />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Category</Label>
              <Select value={form.category} onValueChange={handleCategoryChange}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {CATEGORY_OPTIONS.map(c => <SelectItem key={c} value={c} className="text-xs">{c}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">T.O.G</Label>
              <Select value={form.tog} onValueChange={handleTogChange}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {TOG_OPTIONS.map(t => <SelectItem key={t} value={t} className="text-xs">{t}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            <div className="col-span-2">
              <div className="flex items-center justify-between mb-0.5">
                <Label className="text-xs text-muted-foreground">Order ID / Barcode</Label>
                {isDuplicateBarcode && (
                  <span className="text-[10px] font-bold text-destructive flex items-center animate-pulse">
                    <AlertTriangle className="w-3 h-3 mr-1" /> ALREADY EXISTS
                  </span>
                )}
              </div>
              <Input 
                value={form.orderId} 
                onChange={e => set('orderId', e.target.value)} 
                className={`h-8 text-xs bg-background uppercase transition-colors ${isDuplicateBarcode ? 'border-destructive focus-visible:ring-destructive' : 'border-border'}`} 
                placeholder="e.g. AM-SL-030909" 
              />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Grams (0 = PC)</Label>
              <Input type="number" value={form.grams} onChange={e => set('grams', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0.00" />
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">MC (Making Charge)</Label>
              <Input type="number" value={form.mc} onChange={e => set('mc', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0" />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Gold Rate</Label>
              <Input type="number" value={form.goldRate} onChange={e => set('goldRate', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0.00" />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Client Rate</Label>
              <Input type="number" value={form.clientRate} onChange={e => set('clientRate', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" placeholder="0.00" />
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">
                Supplier Rate
              </Label>
              {isManualSupplierRate ? (
                <Input
                  type="number"
                  value={form.supplierRateOverride}
                  onChange={e => set('supplierRateOverride', e.target.value)}
                  className="h-8 text-xs mt-0.5 bg-background border-border"
                  placeholder={form.category === 'Diamond' ? 'Enter supplier rate' : '115'}
                />
              ) : (
                <Input value={supplierRate} readOnly className="h-8 text-xs mt-0.5 bg-muted border-border opacity-70 cursor-not-allowed" placeholder="Auto" />
              )}
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Currency</Label>
              <Select value={form.currency} onValueChange={v => set('currency', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {CURRENCY_OPTIONS.map(c => <SelectItem key={c} value={c} className="text-xs">{c}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Mode of Sale</Label>
              <Select value={form.modeOfSale} onValueChange={v => set('modeOfSale', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {MODE_OF_SALE_OPTIONS.map(m => <SelectItem key={m} value={m} className="text-xs">{m}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Source</Label>
              <Select value={form.source} onValueChange={v => set('source', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {SOURCE_OPTIONS.map(s => <SelectItem key={s} value={s} className="text-xs">{s}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label className="text-xs text-muted-foreground">Location</Label>
              <Select value={form.locationOfMiner} onValueChange={v => {
                set('locationOfMiner', v);
                if (v === 'Pinas') set('currency', 'PHP');
                else if (v === 'Local') set('currency', 'AED');
              }}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {LOCATION_OPTIONS.map(l => <SelectItem key={l} value={l} className="text-xs">{l}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>

            {isPinas && (
              <div className="col-span-2 bg-primary/10 border border-primary/20 rounded-lg p-2">
                <Label className="text-xs text-primary font-semibold">PHP Conversion Rate (AED → PHP)</Label>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-xs text-muted-foreground">1 AED =</span>
                  <Input
                    type="number"
                    value={phpRate}
                    onChange={e => setPhpRate(e.target.value)}
                    className="h-7 text-xs bg-background border-border w-24"
                    step="0.1"
                  />
                  <span className="text-xs text-muted-foreground">PHP</span>
                </div>
              </div>
            )}

            {form.locationOfMiner === 'Local' && (
              <div>
                <Label className="text-xs text-muted-foreground">Region</Label>
                <Select value={form.regions} onValueChange={v => set('regions', v)}>
                  <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                  <SelectContent className="bg-popover border-border">
                    {REGION_OPTIONS.map(r => <SelectItem key={r} value={r} className="text-xs">{r}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
            )}

            <div>
              <Label className="text-xs text-muted-foreground">Mode of Payment</Label>
              <Select value={form.modeOfPayment} onValueChange={v => set('modeOfPayment', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue placeholder="Select..." /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {MOP_OPTIONS.map(m => <SelectItem key={m} value={m} className="text-xs">{m}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Status</Label>
              <Select value={form.status} onValueChange={v => set('status', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {STATUS_OPTIONS.map(s => <SelectItem key={s} value={s} className="text-xs">{s}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label className="text-xs text-muted-foreground">Remittance Status</Label>
              <Select value={form.remittanceStatus} onValueChange={v => set('remittanceStatus', v)}>
                <SelectTrigger className="h-8 text-xs mt-0.5 bg-background border-border"><SelectValue /></SelectTrigger>
                <SelectContent className="bg-popover border-border">
                  {REMITTANCE_OPTIONS.map(r => <SelectItem key={r} value={r} className="text-xs">{r}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div className="col-span-2">
              <Label className="text-xs text-muted-foreground">Date of Live</Label>
              <Input type="date" value={form.dateOfLive} onChange={e => set('dateOfLive', e.target.value)} className="h-8 text-xs mt-0.5 bg-background border-border" />
            </div>
          </div>

          <div className="flex gap-2 pt-2">
            <Button variant="outline" className="text-xs h-8 border-border w-20 shrink-0" onClick={onClose}>
              Cancel
            </Button>
            <Button onClick={() => handleSave(true)} disabled={saving || isDuplicateBarcode} variant="secondary" className="flex-1 text-xs h-8 border-border">
              {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <><CopyPlus className="h-3.5 w-3.5 mr-1" /> Save & Add Another</>}
            </Button>
            <Button onClick={() => handleSave(false)} disabled={saving || isDuplicateBarcode} className="flex-1 text-xs h-8 bg-primary text-primary-foreground">
              {saving ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : 'Create Record'}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from 'react';
import { Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { DatabaseRowType } from '@/types';
import {
  calcItemPrice, calcItemPriceAED, calcShippingFee, calcCCFee,
  calcTotalPaid, calcProfitAED, roundPrice, getEffectiveCurrency,
  toAED, fromAED, calcRemainingBalance
} from '@/lib/calculations';

interface Props {
  record: DatabaseRowType;
  onUpdate: (rowId: number, fields: Partial<DatabaseRowType>) => Promise<void>;
}

const REMITTANCE_OPTIONS = [
  'Pending Payment', 'Secured via Courier', 'Secured via Bank Transfer',
  'Secured via Cash', 'SECURED VIA TABBY', 'SECURED VIA TAMARA',
];
const MODE_OF_SALE_OPTIONS = ['Live', 'Outsource', 'Dropshipping', 'In-Store'];

export default function FinancialsForm({ record, onUpdate }: Props) {
  const [saving, setSaving] = useState(false);
  const isLayaway = record.modeOfPayment === 'Layaway';

  const currency = getEffectiveCurrency(record);

  const [form, setForm] = useState({
    goldRate: record.goldRate?.toString() || '',
    mc: record.mc || '',
    supplierRate: record.supplierRate || '',
    additionalCharges: record.additionalCharges || '',
    additionalFeeRemarks: record.liverAdminRemarks || '',
    downpayment: String(record.downpayment || ''),
    amountReceived: String(record.amountReceived || ''),
    la1MonthPayment: String(record.la1MonthPayment || ''),
    la2MonthPayment: String(record.la2MonthPayment || ''),
    la3MonthPayment: String(record.la3MonthPayment || ''),
    la4MonthPayment: String(record.la4MonthPayment || ''),
    remittanceStatus: record.remittanceStatus || '',
    modeOfSale: record.modeOfSale || '',
  });

  useEffect(() => {
    setForm({
      goldRate: record.goldRate?.toString() || '',
      mc: record.mc || '',
      supplierRate: record.supplierRate || '',
      additionalCharges: record.additionalCharges || '',
      additionalFeeRemarks: record.liverAdminRemarks || '',
      downpayment: String(record.downpayment || ''),
      amountReceived: String(record.amountReceived || ''),
      la1MonthPayment: String(record.la1MonthPayment || ''),
      la2MonthPayment: String(record.la2MonthPayment || ''),
      la3MonthPayment: String(record.la3MonthPayment || ''),
      la4MonthPayment: String(record.la4MonthPayment || ''),
      remittanceStatus: record.remittanceStatus || '',
      modeOfSale: record.modeOfSale || '',
    });
  }, [record.id]);

  const set = (key: string, val: string) => setForm(p => ({ ...p, [key]: val }));

  const toDisplay = (val: unknown): string => {
    const num = parseFloat(String(val ?? '')) || 0;
    if (!num) return '';
    return String(Math.round(toAED(num, record) * 100) / 100);
  };
  const fromDisplay = (aedStr: string): string => {
    const num = parseFloat(aedStr) || 0;
    if (!num) return '';
    return String(Math.round(fromAED(num, record) * 100) / 100);
  };

  const buildPreview = (): DatabaseRowType => ({
    ...record,
    goldRate: parseFloat(form.goldRate) || record.goldRate,
    supplierRate: form.supplierRate,
    mc: form.mc,
    additionalCharges: form.additionalCharges,
    downpayment: form.downpayment,
    amountReceived: form.amountReceived,
    la1MonthPayment: isLayaway ? form.la1MonthPayment : '',
    la2MonthPayment: isLayaway ? form.la2MonthPayment : '',
    la3MonthPayment: isLayaway ? form.la3MonthPayment : '',
    la4MonthPayment: isLayaway ? form.la4MonthPayment : '',
  });

  const handlePayFull = () => {
    const preview = buildPreview();
    preview.amountReceived = ''; 
    const remainingAED = calcRemainingBalance(preview); 

    if (remainingAED > 0) {
        set('amountReceived', String(fromAED(remainingAED, record)));
        toast.success(`Auto-filled full balance!`);
    } else {
        toast.info('Balance is already fully paid!');
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const previewRecord = buildPreview();
      const computedProfit = calcProfitAED(previewRecord).toFixed(2);

      await onUpdate(record.id, {
        goldRate: parseFloat(form.goldRate) || record.goldRate,
        supplierRate: form.supplierRate,
        mc: form.mc,
        additionalCharges: form.additionalCharges,
        liverAdminRemarks: form.additionalFeeRemarks,
        downpayment: form.downpayment,
        amountReceived: form.amountReceived,
        la1MonthPayment: isLayaway ? form.la1MonthPayment : '',
        la2MonthPayment: isLayaway ? form.la2MonthPayment : '',
        la3MonthPayment: isLayaway ? form.la3MonthPayment : '',
        la4MonthPayment: isLayaway ? form.la4MonthPayment : '',
        remittanceStatus: form.remittanceStatus,
        modeOfSale: form.modeOfSale,
        profit: computedProfit,
      });
      toast.success('Financials saved');
    } finally {
      setSaving(false);
    }
  };

  const previewRecord = buildPreview();
  const itemPrice = calcItemPrice(previewRecord);
  const itemPriceAED = calcItemPriceAED(previewRecord);
  const shippingFee = calcShippingFee(previewRecord);
  const ccFee = calcCCFee(previewRecord);
  const additionalAED = parseFloat(form.additionalCharges) || 0;
  const totalAmount = roundPrice(itemPriceAED + shippingFee + ccFee + additionalAED);
  const totalPaid = calcTotalPaid(previewRecord);
  const remaining = roundPrice(totalAmount - totalPaid);
  const profitAED = calcProfitAED(previewRecord);

  const numField = (label: string, key: string, disabled = false) => (
    <div>
      <Label className="text-xs text-muted-foreground">{label}</Label>
      <Input type="number" value={form[key as keyof typeof form]} onChange={e => set(key, e.target.value)}
        disabled={disabled} className="h-8 text-xs bg-background border-border mt-0.5 disabled:opacity-50" placeholder="0.00" />
    </div>
  );

  const paymentField = (label: string, key: string, disabled = false) => (
    <div>
      <Label className="text-xs text-muted-foreground">{label}</Label>
      <Input
        type="number"
        value={toDisplay(form[key as keyof typeof form])}
        onChange={e => set(key, fromDisplay(e.target.value))}
        disabled={disabled}
        className="h-8 text-xs bg-background border-border mt-0.5 disabled:opacity-50"
        placeholder="0.00"
      />
    </div>
  );

  return (
    <div className="border-t border-border pt-3 mt-2">
      <p className="text-xs font-medium text-muted-foreground mb-2 uppercase tracking-wide">Financials</p>

      <div className="mb-3">
        <Label className="text-xs text-muted-foreground">Mode of Sale</Label>
        <Select value={form.modeOfSale} onValueChange={v => set('modeOfSale', v)}>
          <SelectTrigger className="h-8 text-xs bg-background border-border mt-0.5">
            <SelectValue placeholder="Select mode of sale..." />
          </SelectTrigger>
          <SelectContent className="bg-popover border-border">
            {MODE_OF_SALE_OPTIONS.map(o => <SelectItem key={o} value={o} className="text-xs">{o}</SelectItem>)}
          </SelectContent>
        </Select>
      </div>

      <div className="grid grid-cols-2 gap-2 mb-3">
        {numField('Gold Rate', 'goldRate')}
        {numField('MC (Making Charge)', 'mc')}
        <div>
          <Label className="text-xs text-muted-foreground">Supplier Rate</Label>
          <Input type="number" value={form.supplierRate} onChange={e => set('supplierRate', e.target.value)}
            className="h-8 text-xs bg-background border-border mt-0.5" placeholder="0.00" />
        </div>
        {numField('Additional Fees (AED)', 'additionalCharges')}
      </div>

      <div className="mb-3">
        <Label className="text-xs text-muted-foreground">Additional Fee Remarks <span className="text-primary/60">(Col X)</span></Label>
        <Textarea value={form.additionalFeeRemarks} onChange={e => set('additionalFeeRemarks', e.target.value)}
          className="text-xs bg-background border-border mt-0.5 min-h-[60px]" placeholder="Enter remarks about additional fees..." />
      </div>

      <div className="grid grid-cols-2 gap-2 mb-3">
        {paymentField('Downpayment (AED)', 'downpayment')}

        <div>
          <div className="flex items-center justify-between mb-0.5">
            <Label className="text-xs text-muted-foreground">Amount Received (AED)</Label>
            <button 
              onClick={handlePayFull} 
              className="text-[9px] font-bold text-primary bg-primary/10 hover:bg-primary/20 px-1.5 py-0.5 rounded transition-colors"
              title="Auto-fill exact remaining balance"
            >
              PAY FULL
            </button>
          </div>
          <Input
            type="number"
            value={toDisplay(form.amountReceived)}
            onChange={e => set('amountReceived', fromDisplay(e.target.value))}
            className="h-8 text-xs bg-background border-border disabled:opacity-50"
            placeholder="0.00"
          />
        </div>
      </div>

      <div className={`grid grid-cols-2 gap-2 mb-3 ${!isLayaway ? 'opacity-40' : ''}`}>
        <p className="col-span-2 text-xs text-muted-foreground">Layaway Payments (AED){!isLayaway ? ' (locked)' : ''}</p>
        {paymentField('Month 1', 'la1MonthPayment', !isLayaway)}
        {paymentField('Month 2', 'la2MonthPayment', !isLayaway)}
        {paymentField('Month 3', 'la3MonthPayment', !isLayaway)}
        {paymentField('Month 4', 'la4MonthPayment', !isLayaway)}
      </div>

      <div className="mb-3">
        <Label className="text-xs text-muted-foreground">Remittance Status</Label>
        <Select value={form.remittanceStatus} onValueChange={v => set('remittanceStatus', v)}>
          <SelectTrigger className="h-8 text-xs bg-background border-border mt-0.5">
            <SelectValue placeholder="Select remittance..." />
          </SelectTrigger>
          <SelectContent className="bg-popover border-border">
            {REMITTANCE_OPTIONS.map(o => <SelectItem key={o} value={o} className="text-xs">{o}</SelectItem>)}
          </SelectContent>
        </Select>
      </div>

      <div className="bg-secondary/50 rounded-lg p-3 mb-3 space-y-1 text-xs">
        <div className="flex justify-between"><span className="text-muted-foreground">Item Price ({currency})</span><span>{currency} {itemPrice.toFixed(2)}</span></div>
        {currency !== 'AED' && <div className="flex justify-between"><span className="text-muted-foreground">Item Price (AED)</span><span>AED {itemPriceAED.toFixed(2)}</span></div>}
        <div className="flex justify-between"><span className="text-muted-foreground">Shipping Fee</span><span>AED {shippingFee.toFixed(2)}</span></div>
        {ccFee > 0 && <div className="flex justify-between"><span className="text-muted-foreground">CC Fee</span><span>AED {ccFee.toFixed(2)}</span></div>}
        {additionalAED > 0 && <div className="flex justify-between"><span className="text-muted-foreground">Additional Charges</span><span>AED {additionalAED.toFixed(2)}</span></div>}
        <div className="flex justify-between font-semibold pt-1 border-t border-border">
          <span>Total Amount</span><span>AED {totalAmount.toFixed(2)}</span>
        </div>
        <div className="flex justify-between"><span className="text-muted-foreground">Total Paid</span><span>AED {totalPaid.toFixed(2)}</span></div>
        <div className={`flex justify-between font-bold pt-1 border-t border-border ${remaining > 0 ? 'text-destructive' : 'text-green-400'}`}>
          <span>Remaining Balance</span><span>AED {remaining.toFixed(2)}</span>
        </div>
        <div className="flex justify-between pt-1 border-t border-border">
          <span className="text-muted-foreground">Expected Profit</span>
          <span className={profitAED >= 0 ? 'text-primary font-medium' : 'text-destructive font-medium'}>AED {profitAED.toFixed(2)}</span>
        </div>
      </div>

      <Button onClick={handleSave} disabled={saving} className="w-full bg-primary text-primary-foreground text-xs h-8">
        {saving ? <><Loader2 className="h-3.5 w-3.5 mr-1.5 animate-spin" /> Saving...</> : 'Save Financials'}
      </Button>
    </div>
  );
}

import { memo, useState } from 'react';
import { History } from 'lucide-react';
import { DatabaseRowType } from '@/types';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { formatDate } from '@/lib/formatters';
import { toast } from 'sonner';
import CustomerHistoryModal from '@/components/CustomerHistoryModal';

interface Props {
  minerName: string;
  records: DatabaseRowType[];
  allRecords: DatabaseRowType[];
  onUpdate: (id: number, fields: Partial<DatabaseRowType>) => Promise<void>;
}

function ReviewChasingCard({ minerName, records, allRecords, onUpdate }: Props) {
  const [showHistory, setShowHistory] = useState(false);
  // Use the first record to dictate display values
  const firstRecord = records[0];
  const status = firstRecord.reviewChasing || 'Pending';
  const isChased = status === 'Chased';

  const handleStatusChange = async (val: string) => {
    // Update sequentially to avoid Google Sheets rate limits
    for (const r of records) {
      await onUpdate(r.id, { reviewChasing: val });
      await new Promise(res => setTimeout(res, 300));
    }
    toast.success(`Marked ${minerName} as ${val}`);
  };

  return (
    <div className={`bg-card border border-border rounded-lg p-4 transition-all duration-500 ease-in-out ${isChased ? 'opacity-50 scale-[0.98] py-2.5' : ''}`}>
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <h3 className={`font-medium truncate ${isChased ? 'text-xs' : 'text-sm'}`}>
              {minerName || 'Unknown Client'}
            </h3>
            {firstRecord.customerId && (
              <button
                className="shrink-0 text-muted-foreground hover:text-primary transition-colors"
                title="View Lifetime History"
                onClick={() => setShowHistory(true)}
              >
                <History className="h-3.5 w-3.5" />
              </button>
            )}
          </div>

          {/* Hide the item descriptions when chased to save space (auto-minimize) */}
          {!isChased && (
            <p className="text-xs text-muted-foreground mt-1 line-clamp-2">
              {records.map(r => r.itemDescription).join(', ')}
            </p>
          )}

          <p className="text-[10px] text-muted-foreground mt-1">
            Delivered: {firstRecord.deliveredDate ? formatDate(firstRecord.deliveredDate) : 'Unknown'}
            {records.length > 1 && ` · ${records.length} items`}
          </p>
        </div>

        <div className="flex items-center gap-2 shrink-0">
          <Select
            value={status}
            onValueChange={handleStatusChange}
          >
            <SelectTrigger className={`w-[130px] border-border bg-secondary/30 ${isChased ? 'h-7 text-[10px]' : 'h-8 text-xs'}`}>
              <SelectValue placeholder="Select status" />
            </SelectTrigger>
            <SelectContent className="border-border">
              <SelectItem value="Pending">Pending</SelectItem>
              <SelectItem value="Chased">Chased</SelectItem>
              <SelectItem value="Skipped">Skipped</SelectItem>
              <SelectItem value="Completed">Completed</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>
      {showHistory && firstRecord.customerId && (
        <CustomerHistoryModal
          customerId={firstRecord.customerId}
          minerName={minerName}
          allRecords={allRecords}
          onClose={() => setShowHistory(false)}
        />
      )}
    </div>
  );
}

// MEMO: Prevent re-rendering unchanged clients for performance
export default memo(ReviewChasingCard, (prev, next) => {
  if (prev.minerName !== next.minerName) return false;
  if (prev.records.length !== next.records.length) return false;
  for (let i = 0; i < prev.records.length; i++) {
    if (prev.records[i] !== next.records[i]) return false;
  }
  if (prev.allRecords !== next.allRecords) return false;
  return true;
});

import { useMemo, useState } from 'react';
import { Calendar, ChevronDown, Printer, History } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { TabProps, DatabaseRowType } from '@/types';
import {
  calcProfitAED,
  calcRemainingBalance,
  parseDateRobust,
  calcItemPriceAED,
  calcItemCostAED
} from '@/lib/calculations';
import { formatDate, applySearch } from '@/lib/formatters';
import TabHeader from '@/components/TabHeader';
import KpiCard from './KpiCard';
import StatusBadge from '@/components/StatusBadge';
import { startOfWeek, startOfMonth, subMonths } from 'date-fns';
import CustomerHistoryModal from '@/components/CustomerHistoryModal';

type DateRange = 'all' | 'week' | 'month' | '3months' | 'custom';

export default function BossingDashboard({ records, searchQuery, onSearchChange }: TabProps) {
  const [range, setRange] = useState<DateRange>('all');
  const [customFrom, setCustomFrom] = useState<Date | undefined>();
  const [customTo, setCustomTo] = useState<Date | undefined>();
  const [pickerOpen, setPickerOpen] = useState(false);
  const [expandedStatuses, setExpandedStatuses] = useState<Record<string, boolean>>({});
  const [liverFilter, setLiverFilter] = useState('all');
  const [statusLiverFilters, setStatusLiverFilters] = useState<Record<string, string>>({});
  const [showPrintDialog, setShowPrintDialog] = useState(false);
  const [selectedPrintStatuses, setSelectedPrintStatuses] = useState<Set<string>>(new Set());

  const [historyCustomer, setHistoryCustomer] = useState<{ id: string, name: string } | null>(null);

  const liverNames = useMemo(() => {
    const names = Array.from(new Set(records.map(r => r.liverName?.trim().toUpperCase()).filter(Boolean))) as string[];
    return names.sort();
  }, [records]);

  const dateFiltered = useMemo(() => {
    const base = records;
    if (range === 'all') return base;
    const now = new Date();
    let from: Date;
    if (range === 'week') from = startOfWeek(now, { weekStartsOn: 1 });
    else if (range === 'month') from = startOfMonth(now);
    else if (range === '3months') from = subMonths(now, 3);
    else from = customFrom || new Date(0);
    const to = range === 'custom' ? customTo : undefined;
    return base.filter(r => {
      if (!r.dateOfLive) return false;
      const d = parseDateRobust(r.dateOfLive);
      if (!d) return false;
      const itemTime = d.getTime();
      if (itemTime < from.getTime()) return false;
      if (to) {
        const endOfToDay = new Date(to);
        endOfToDay.setHours(23, 59, 59, 999);
        if (itemTime > endOfToDay.getTime()) return false;
      }
      return true;
    });
  }, [records, range, customFrom, customTo]);

  const filtered = useMemo(() => {
    let base = applySearch(dateFiltered, searchQuery);
    if (liverFilter !== 'all') {
      base = base.filter(r => r.liverName?.trim().toUpperCase() === liverFilter);
    }
    return base;
  }, [dateFiltered, searchQuery, liverFilter]);

  const kpis = useMemo(() => {
    // FIX: Exclude both Cancelled and Returned Item from active calculations
    const activeRecords = filtered.filter(r => r.status !== 'Cancelled' && r.status !== 'Returned Item');
    const totalProfit = activeRecords.reduce((sum, r) => sum + calcProfitAED(r), 0);
    const totalSold = filtered.filter(r => r.status === 'Delivered' || r.status === 'Given to Shop').length;
    const outstanding = activeRecords.reduce((sum, r) => sum + Math.max(0, calcRemainingBalance(r)), 0);
    const totalGrams = activeRecords.reduce((sum, r) => {
      const cat = (r.category || '').toLowerCase();
      if (cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond')) return sum;
      return sum + (Number(r.grams) || 0);
    }, 0);
    return { totalProfit, totalSold, outstanding, activeCount: activeRecords.length, totalGrams };
  }, [filtered]);

  const statusGroups = useMemo(() => {
    const grouped = new Map<string, DatabaseRowType[]>();
    for (const r of filtered) {
      const status = r.status || 'Unknown';
      if (!grouped.has(status)) grouped.set(status, []);
      grouped.get(status)!.push(r);
    }
    return grouped;
  }, [filtered]);

  const toggleStatus = (status: string) => {
    setExpandedStatuses(prev => ({ ...prev, [status]: !prev[status] }));
  };

  const RANGES: { key: DateRange; label: string }[] = [
    { key: 'all', label: 'All Time' },
    { key: 'week', label: 'This Week' },
    { key: 'month', label: 'This Month' },
    { key: '3months', label: '3 Months' },
    { key: 'custom', label: 'Custom' },
  ];

  const openPrintDialog = () => {
    setSelectedPrintStatuses(new Set(statusGroups.keys()));
    setShowPrintDialog(true);
  };

  const togglePrintStatus = (status: string) => {
    setSelectedPrintStatuses(prev => {
      const next = new Set(prev);
      if (next.has(status)) next.delete(status);
      else next.add(status);
      return next;
    });
  };

  const handlePrintReport = () => {
    setShowPrintDialog(false);
    const win = window.open('', '_blank');
    if (!win) return;

    const dateRangeLabel = RANGES.find(r => r.key === range)?.label || 'Custom';

    let html = `<html><head><title>Executive Report</title>
      <link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@700&display=swap" rel="stylesheet">
      <style>
        body { font-family: sans-serif; color: #111; background: #fff; margin: 0; padding: 24px; font-size: 12px; }
        .font-cinzel { font-family: 'Cinzel', serif; font-weight: 700; }
        h1 { margin-bottom: 4px; font-size: 24px; color: #111; }
        .summary { margin-bottom: 24px; padding: 16px; background: #f9f9f9; border-radius: 8px; border: 1px solid #ddd; }
        .summary p { margin: 6px 0; font-size: 14px; font-weight: bold; }
        table { width: 100%; border-collapse: collapse; margin-bottom: 32px; }
        th { background: #111; color: #fff; padding: 8px; text-align: left; font-size: 11px; }
        th.r, td.r { text-align: right; }
        td { padding: 8px; border-bottom: 1px solid #ddd; }
        .status-header { font-size: 16px; margin-top: 24px; margin-bottom: 8px; color: #C9A84C; border-bottom: 2px solid #C9A84C; padding-bottom: 4px;}
        .page-header { font-size: 13px; font-weight: bold; margin-top: 14px; margin-bottom: 4px; background: #222; color: #fff; padding: 5px 10px; border-radius: 4px; }
        .date-header { font-size: 11px; font-weight: bold; margin-top: 8px; margin-bottom: 2px; color: #555; padding: 3px 8px; background: #f0f0f0; border-left: 3px solid #C9A84C; }
        .profit-pos { color: #16a34a; }
        .profit-neg { color: #dc2626; }
      </style></head><body>

      <h1 class="font-cinzel">EXECUTIVE SUMMARY REPORT</h1>

      <div class="summary">
        <p>Total Expected Profit: <span class="profit-pos">AED ${kpis.totalProfit.toFixed(2)}</span></p>
        <p>Total Items Sold: ${kpis.totalSold}</p>
        <p>Outstanding Receivables: AED ${kpis.outstanding.toFixed(2)}</p>
        <p style="font-size: 11px; color: #666; font-weight: normal; margin-top: 12px;">Date Range: ${dateRangeLabel} | Generated: ${new Date().toLocaleString()}</p>
      </div>
    `;

    Array.from(statusGroups.entries())
      .filter(([status]) => selectedPrintStatuses.has(status))
      .sort((a, b) => {
        if (a[0] === 'Cancelled' || a[0] === 'Returned Item') return 1;
        if (b[0] === 'Cancelled' || b[0] === 'Returned Item') return -1;
        return a[0].localeCompare(b[0]);
      }).forEach(([status, items]) => {
        const isDeadStatus = status === 'Cancelled' || status === 'Returned Item';
        const statusProfit = items.reduce((s, r) => s + calcProfitAED(r), 0);
        const profitText = isDeadStatus ? '' : ` | Profit: AED ${statusProfit.toFixed(2)}`;
        html += `<h2 class="font-cinzel status-header">${status.toUpperCase()} (${items.length} items${profitText})</h2>`;

        const byPage = new Map<string, Map<string, DatabaseRowType[]>>();
        for (const r of items) {
          let pageKey = (r.page || 'Other').trim();
          if (pageKey.toUpperCase().includes('MYK')) pageKey = 'MYK';
          else if (pageKey.toUpperCase().includes('EMPIRE')) pageKey = 'Empire Gold By ETG';
          const date = formatDate(r.dateOfLive);
          if (!byPage.has(pageKey)) byPage.set(pageKey, new Map());
          const byDate = byPage.get(pageKey)!;
          if (!byDate.has(date)) byDate.set(date, []);
          byDate.get(date)!.push(r);
        }

        const profitHeader = isDeadStatus ? '' : `<th class="r">Profit (AED)</th>`;

        Array.from(byPage.entries()).sort((a, b) => {
          if (a[0] === 'MYK') return -1; if (b[0] === 'MYK') return 1;
          if (a[0] === 'Empire Gold By ETG') return -1; if (b[0] === 'Empire Gold By ETG') return 1;
          return a[0].localeCompare(b[0]);
        }).forEach(([page, dateMap]) => {
          html += `<div class="page-header">📄 ${page}</div>`;

          Array.from(dateMap.entries()).sort((a, b) => b[0].localeCompare(a[0])).forEach(([date, rows]) => {
            const dateProfit = rows.reduce((s, r) => s + calcProfitAED(r), 0);
            const dateProfitText = isDeadStatus ? '' : ` — Profit: AED ${dateProfit.toFixed(2)}`;
            html += `<div class="date-header">📅 ${date}${dateProfitText}</div>`;
            html += `<table><thead><tr>
              <th>Client</th><th>Item</th>
              <th class="r">Price (AED)</th><th class="r">Cost (AED)</th>
              ${profitHeader}
            </tr></thead><tbody>`;

            html += rows.map(r => {
              const profit = calcProfitAED(r);
              const profitClass = profit >= 0 ? 'profit-pos' : 'profit-neg';
              const profitCell = isDeadStatus ? '' : `<td class="r"><strong class="${profitClass}">${profit.toFixed(2)}</strong></td>`;
              return `<tr>
                <td><strong>${r.minerName || '—'}</strong></td>
                <td>${r.itemDescription || '—'}</td>
                <td class="r">${calcItemPriceAED(r).toFixed(2)}</td>
                <td class="r">${calcItemCostAED(r).toFixed(2)}</td>
                ${profitCell}
              </tr>`;
            }).join('');

            html += `</tbody></table>`;
          });
        });
      });

    html += `</body></html>`;
    win.document.write(html);
    win.document.close();
    win.print();
  };

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader title="Bossing Dashboard" subtitle="Executive summary — AED" searchQuery={searchQuery} onSearchChange={onSearchChange} />
      <div className="px-4 pt-4">
        <div className="flex gap-1.5 flex-wrap mb-4">
          {RANGES.map(r => (
            <Button
              key={r.key}
              size="sm"
              variant={range === r.key ? 'default' : 'outline'}
              className={`text-xs h-7 ${range === r.key ? 'bg-primary text-primary-foreground' : 'border-border'}`}
              onClick={() => setRange(r.key)}
            >
              {r.key === 'custom' && <Calendar className="h-3 w-3 mr-1" />}
              {r.label}
            </Button>
          ))}
        </div>

        <div className="mb-3">
          <Select value={liverFilter} onValueChange={setLiverFilter}>
            <SelectTrigger className="h-8 text-xs w-44 bg-background border-border">
              <SelectValue placeholder="All Livers" />
            </SelectTrigger>
            <SelectContent className="bg-popover border-border">
              <SelectItem value="all" className="text-xs">All Livers</SelectItem>
              {liverNames.map(name => (
                <SelectItem key={name} value={name} className="text-xs">{name}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {range === 'custom' && (
          <div className="flex gap-2 mb-4">
            <Popover open={pickerOpen} onOpenChange={setPickerOpen}>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customFrom ? formatDate(customFrom.toISOString()) : 'From date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customFrom} onSelect={d => { setCustomFrom(d); setPickerOpen(false); }} />
              </PopoverContent>
            </Popover>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customTo ? formatDate(customTo.toISOString()) : 'To date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customTo} onSelect={d => setCustomTo(d)} />
              </PopoverContent>
            </Popover>
          </div>
        )}

        <div className="grid grid-cols-1 gap-3 mb-6">
          <KpiCard title="Total Expected Profit" value={`AED ${kpis.totalProfit.toFixed(2)}`} subtitle={`${kpis.activeCount} active records (excl. Cancelled/Returned)`} highlight />
          <KpiCard title="Total Items Sold" value={kpis.totalSold.toString()} subtitle="Delivered/Given to Shop (excl. Cancelled/Returned)" />
          <KpiCard title="Total Grams Sold" value={`${kpis.totalGrams.toFixed(2)}g`} subtitle="Excl. Per PC / Screw Type / Diamond" />
          <KpiCard title="Outstanding Receivables" value={`AED ${kpis.outstanding.toFixed(2)}`} subtitle="Sum of remaining balances (excl. Cancelled/Returned)" />
        </div>

        <div className="flex items-center justify-between mb-4">
          <h2 className="font-cinzel text-lg text-primary">Detailed Breakdown</h2>
          <Button variant="outline" size="sm" className="h-8 text-xs border-primary/40 text-primary" onClick={openPrintDialog}>
            <Printer className="h-3.5 w-3.5 mr-1.5" /> Print Report
          </Button>
        </div>

        <div className="space-y-3">
          {Array.from(statusGroups.entries()).sort((a, b) => {
            if (a[0] === 'Cancelled' || a[0] === 'Returned Item') return 1;
            if (b[0] === 'Cancelled' || b[0] === 'Returned Item') return -1;
            return a[0].localeCompare(b[0]);
          }).map(([status, items]) => {
            const isDeadStatus = status === 'Cancelled' || status === 'Returned Item';
            const totalProfit = items.reduce((sum, r) => sum + calcProfitAED(r), 0);
            const groupGrams = items.reduce((sum, r) => {
              const cat = (r.category || '').toLowerCase();
              if (cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond')) return sum;
              return sum + (Number(r.grams) || 0);
            }, 0);
            const isExpanded = expandedStatuses[status];

            return (
              <div key={status} className="rounded-xl border border-border bg-card overflow-hidden">
                <button
                  onClick={() => toggleStatus(status)}
                  className="w-full flex items-center justify-between p-4 text-left focus:outline-none"
                >
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <StatusBadge status={status} />
                      <span className="text-xs text-muted-foreground">{items.length} items</span>
                    </div>
                    <div className="flex flex-wrap gap-x-3 gap-y-0.5">
                      {!isDeadStatus && (
                        <p className="text-xs font-medium">
                          Profit: <span className={totalProfit >= 0 ? 'text-green-400' : 'text-destructive'}>AED {totalProfit.toFixed(2)}</span>
                        </p>
                      )}
                      {groupGrams > 0 && (
                        <p className="text-xs font-medium text-muted-foreground">
                          Grams: <span className="text-foreground">{groupGrams.toFixed(2)}g</span>
                        </p>
                      )}
                    </div>
                  </div>
                  <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                </button>

                {isExpanded && (() => {
                  const statusLiver = statusLiverFilters[status] || 'all';
                  const statusLiverNames = [...new Set(items.map(r => r.liverName?.trim().toUpperCase()).filter(Boolean) as string[])].sort();
                  const visibleItems = statusLiver === 'all' ? items : items.filter(r => r.liverName?.trim().toUpperCase() === statusLiver);

                  const byPage = new Map<string, Map<string, DatabaseRowType[]>>();
                  for (const r of visibleItems) {
                    let pageKey = (r.page || 'Other').trim();
                    if (pageKey.toUpperCase().includes('MYK')) pageKey = 'MYK';
                    else if (pageKey.toUpperCase().includes('EMPIRE')) pageKey = 'Empire Gold By ETG';
                    const d = r.dateOfLive || 'Unknown Date';
                    if (!byPage.has(pageKey)) byPage.set(pageKey, new Map());
                    const byDate = byPage.get(pageKey)!;
                    if (!byDate.has(d)) byDate.set(d, []);
                    byDate.get(d)!.push(r);
                  }

                  const sortedPages = [...byPage.entries()].sort((a, b) => {
                    if (a[0] === 'MYK') return -1; if (b[0] === 'MYK') return 1;
                    if (a[0] === 'Empire Gold By ETG') return -1; if (b[0] === 'Empire Gold By ETG') return 1;
                    return a[0].localeCompare(b[0]);
                  });

                  return (
                    <div className="px-4 pb-4 border-t border-border pt-3 animate-in fade-in slide-in-from-top-2 duration-200">
                      {statusLiverNames.length > 1 && (
                        <div className="mb-3">
                          <Select value={statusLiver} onValueChange={v => setStatusLiverFilters(prev => ({ ...prev, [status]: v }))}>
                            <SelectTrigger className="h-7 text-xs w-40 bg-background border-border">
                              <SelectValue placeholder="All Livers" />
                            </SelectTrigger>
                            <SelectContent className="bg-popover border-border">
                              <SelectItem value="all" className="text-xs">All Livers</SelectItem>
                              {statusLiverNames.map(name => (
                                <SelectItem key={name} value={name} className="text-xs">{name}</SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>
                      )}
                      <div className="space-y-4">
                        {sortedPages.map(([page, dateMap]) => {
                          const sortedDates = [...dateMap.entries()].sort((a, b) => b[0].localeCompare(a[0]));
                          return (
                            <div key={page}>
                              <div className="flex items-center gap-2 mb-2">
                                <span className="text-[10px] font-bold text-primary/70 uppercase tracking-widest">📄 {page}</span>
                                <div className="h-px flex-1 bg-border/50" />
                                <span className="text-[10px] text-muted-foreground">{Array.from(dateMap.values()).reduce((s, v) => s + v.length, 0)}</span>
                              </div>
                              <div className="space-y-3 ml-2">
                                {sortedDates.map(([date, dateItems]) => (
                                  <div key={date}>
                                    <div className="flex items-center gap-1.5 mb-1.5">
                                      <span className="text-[9px] font-semibold text-muted-foreground uppercase tracking-widest">📅 {formatDate(date)}</span>
                                      <div className="h-px flex-1 bg-border/30" />
                                      <span className="text-[9px] text-muted-foreground">{dateItems.length} · {dateItems.reduce((s, r) => { const c = (r.category||'').toLowerCase(); return c.includes('per pc')||c.includes('screw type')||c.includes('diamond') ? s : s+(Number(r.grams)||0); }, 0).toFixed(2)}g</span>
                                    </div>
                                    <div className="space-y-2 ml-2">
                                      {dateItems.map(record => {
                                        const profit = calcProfitAED(record);
                                        const cat = (record.category || '').toLowerCase();
                                        const isPc = cat.includes('per pc') || cat.includes('screw type') || cat.includes('diamond');
                                        const gramsDisplay = isPc ? 'PC' : (record.grams ? `${Number(record.grams).toFixed(2)}g` : '—');
                                        return (
                                          <div key={record.id} className="flex justify-between items-start border-b border-border/40 pb-2 last:border-0 last:pb-0">
                                            <div className="flex-1 pr-2">
                                              <div className="flex items-center gap-1.5">
                                                <p className="text-sm font-medium">{record.minerName || 'Unknown'}</p>
                                                {record.customerId && (
                                                  <button
                                                    onClick={(e) => {
                                                      e.stopPropagation();
                                                      setHistoryCustomer({ id: record.customerId!, name: record.minerName || '' });
                                                    }}
                                                    className="text-muted-foreground hover:text-primary transition-colors mt-0.5"
                                                    title="View Lifetime History"
                                                  >
                                                    <History className="h-3.5 w-3.5" />
                                                  </button>
                                                )}
                                              </div>
                                              <p className="text-xs text-muted-foreground mt-0.5 truncate">{record.itemDescription}</p>
                                            </div>
                                            <div className="text-right shrink-0 space-y-0.5">
                                              <p className="text-[10px] font-semibold text-muted-foreground">{gramsDisplay}</p>
                                              {!isDeadStatus && (
                                                <>
                                                  <p className={`text-sm font-medium ${profit >= 0 ? 'text-foreground' : 'text-destructive'}`}>AED {profit.toFixed(2)}</p>
                                                  <p className="text-[10px] text-muted-foreground">Profit</p>
                                                </>
                                              )}
                                            </div>
                                          </div>
                                        );
                                      })}
                                    </div>
                                  </div>
                                ))}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                })()}
              </div>
            );
          })}

          {statusGroups.size === 0 && (
            <div className="text-center py-12 border border-dashed border-border rounded-xl">
              <p className="text-sm text-muted-foreground">No records found for this period.</p>
            </div>
          )}
        </div>
      </div>

      <Dialog open={showPrintDialog} onOpenChange={setShowPrintDialog}>
        <DialogContent className="bg-card border-border max-w-sm">
          <DialogHeader>
            <DialogTitle className="font-cinzel text-primary text-base">Select Statuses to Print</DialogTitle>
          </DialogHeader>
          <div className="space-y-3 py-2">
            <div className="flex gap-2 mb-2">
              <Button size="sm" variant="outline" className="text-xs h-7 border-border" onClick={() => setSelectedPrintStatuses(new Set(statusGroups.keys()))}>Select All</Button>
              <Button size="sm" variant="outline" className="text-xs h-7 border-border" onClick={() => setSelectedPrintStatuses(new Set())}>Clear All</Button>
            </div>
            {Array.from(statusGroups.entries()).sort((a, b) => {
              if (a[0] === 'Cancelled' || a[0] === 'Returned Item') return 1;
              if (b[0] === 'Cancelled' || b[0] === 'Returned Item') return -1;
              return a[0].localeCompare(b[0]);
            }).map(([status, items]) => (
              <div key={status} className="flex items-center gap-3">
                <Checkbox
                  id={`print-${status}`}
                  checked={selectedPrintStatuses.has(status)}
                  onCheckedChange={() => togglePrintStatus(status)}
                />
                <Label htmlFor={`print-${status}`} className="text-sm cursor-pointer flex-1">
                  {status}
                  <span className="text-xs text-muted-foreground ml-2">({items.length} items)</span>
                </Label>
              </div>
            ))}
          </div>
          <DialogFooter>
            <Button variant="outline" size="sm" className="text-xs border-border" onClick={() => setShowPrintDialog(false)}>Cancel</Button>
            <Button
              size="sm"
              className="text-xs bg-primary text-primary-foreground"
              disabled={selectedPrintStatuses.size === 0}
              onClick={handlePrintReport}
            >
              <Printer className="h-3.5 w-3.5 mr-1.5" /> Print
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {historyCustomer && (
        <CustomerHistoryModal
          customerId={historyCustomer.id}
          minerName={historyCustomer.name}
          allRecords={records}
          onClose={() => setHistoryCustomer(null)}
        />
      )}
    </div>
  );
}

import { useMemo, useState } from 'react';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarComponent } from '@/components/ui/calendar';
import { TabProps, DatabaseRowType } from '@/types';
import { applySearch, groupByPageDateMiner, formatDate } from '@/lib/formatters';
import CollapsibleGroup from '@/components/CollapsibleGroup';
import { calcRemainingBalance, parseDateRobust } from '@/lib/calculations';
import { startOfWeek, startOfMonth, subMonths } from 'date-fns';
import TabHeader from '@/components/TabHeader';
import AccountsClientCard from './AccountsClientCard';
import { ChevronDown, Plus, Calendar } from 'lucide-react';
import AddClientModal from './AddClientModal';

type DateRange = 'all' | 'week' | 'month' | '3months' | 'custom';

const DATE_RANGES: { key: DateRange; label: string }[] = [
  { key: 'all', label: 'All' },
  { key: 'week', label: 'Week' },
  { key: 'month', label: 'Month' },
  { key: '3months', label: '3 Mo' },
  { key: 'custom', label: 'Custom' },
];

export default function AccountsTracking({ records, searchQuery, onSearchChange, onUpdate, userFirstName, userEmail, onRefresh }: TabProps) {
  const [showAddModal, setShowAddModal] = useState(false);
  const [deliveredExpanded, setDeliveredExpanded] = useState(false);
  const [otherExpanded, setOtherExpanded] = useState(false);
  const [liverFilter, setLiverFilter] = useState('all');
  const [dateRange, setDateRange] = useState<DateRange>('all');
  const [customFrom, setCustomFrom] = useState<Date | undefined>();
  const [customTo, setCustomTo] = useState<Date | undefined>();

  const liverNames = useMemo(() => {
    const names = Array.from(new Set(records.map(r => r.liverName?.trim().toUpperCase()).filter(Boolean))) as string[];
    return names.sort();
  }, [records]);

  const filteredRecords = useMemo(() => {
    let base = records;

    if (liverFilter !== 'all') {
      base = base.filter(r => r.liverName?.trim().toUpperCase() === liverFilter);
    }

    if (dateRange !== 'all') {
      const now = new Date();
      let from: Date;
      if (dateRange === 'week') from = startOfWeek(now, { weekStartsOn: 1 });
      else if (dateRange === 'month') from = startOfMonth(now);
      else if (dateRange === '3months') from = subMonths(now, 3);
      else from = customFrom || new Date(0);
      const to = dateRange === 'custom' ? customTo : undefined;

      base = base.filter(r => {
        if (!r.dateOfLive) return false;
        const d = parseDateRobust(r.dateOfLive);
        if (!d) return false;
        if (d.getTime() < from.getTime()) return false;
        if (to) {
          const end = new Date(to); end.setHours(23, 59, 59, 999);
          if (d.getTime() > end.getTime()) return false;
        }
        return true;
      });
    }

    return base;
  }, [records, liverFilter, dateRange, customFrom, customTo]);

  const { deliveredGroups, otherActiveGroups, clearedGroups } = useMemo(() => {
    const searched = applySearch(filteredRecords, searchQuery);

    // FIX: EXCLUSION FILTER - This forces all Active, Walk-ins, and Pending to show!
    const deadStatuses = ['Cancelled', 'Returned Item'];
    const aliveRecords = searched.filter(r => !deadStatuses.includes((r.status || '').trim()));

    const active: DatabaseRowType[] = [];
    const cleared: DatabaseRowType[] = [];

    aliveRecords.forEach(r => {
      const remStatus = (r.remittanceStatus || '').toLowerCase();
      const isCleared = remStatus.includes('secured') || remStatus.includes('received') || calcRemainingBalance(r) <= 0;

      if (isCleared) {
        cleared.push(r);
      } else {
        active.push(r);
      }
    });

    const delivered = active.filter(r => r.status === 'Delivered');
    const others = active.filter(r => r.status !== 'Delivered');

    return {
      deliveredGroups: groupByPageDateMiner(delivered),
      otherActiveGroups: groupByPageDateMiner(others),
      clearedGroups: groupByPageDateMiner(cleared),
    };
  }, [filteredRecords, searchQuery]);

  const renderGroups = (groups: Map<string, Map<string, Map<string, DatabaseRowType[]>>>) => (
    groups.size === 0 ? (
      <div className="text-center py-10 text-muted-foreground text-sm border border-dashed border-border rounded-lg mt-2">
        No records found in this section.
      </div>
    ) : (
      <div>
        {Array.from(groups.entries()).map(([page, dateMap]) => (
          <CollapsibleGroup key={page} label={page} colorClass="text-primary/70" lineClass="bg-primary/10" defaultOpen={false}>
            {Array.from(dateMap.entries()).map(([date, minerMap]) => (
              <CollapsibleGroup key={date} label={formatDate(date)} colorClass="text-muted-foreground" lineClass="bg-border/40" indent defaultOpen={false}>
                <div className="space-y-3">
                  {Array.from(minerMap.entries()).map(([minerName, items]) => (
                    <AccountsClientCard key={minerName} minerName={minerName} records={items} allRecords={records} onUpdate={onUpdate} />
                  ))}
                </div>
              </CollapsibleGroup>
            ))}
          </CollapsibleGroup>
        ))}
      </div>
    )
  );

  return (
    <div className="min-h-screen bg-background pb-24">
      <TabHeader
        title="Accounts Tracking"
        subtitle={`${deliveredGroups.size + otherActiveGroups.size} active clients`}
        searchQuery={searchQuery}
        onSearchChange={onSearchChange}
      />

      <div className="px-4 pt-4">
        <div className="flex flex-wrap gap-2 mb-3">
          <Select value={liverFilter} onValueChange={setLiverFilter}>
            <SelectTrigger className="h-8 text-xs w-40 bg-background border-border">
              <SelectValue placeholder="All Livers" />
            </SelectTrigger>
            <SelectContent className="bg-popover border-border">
              <SelectItem value="all" className="text-xs">All Livers</SelectItem>
              {liverNames.map(name => (
                <SelectItem key={name} value={name} className="text-xs">{name}</SelectItem>
              ))}
            </SelectContent>
          </Select>

          <div className="flex gap-1 flex-wrap">
            {DATE_RANGES.map(r => (
              <Button
                key={r.key}
                size="sm"
                variant={dateRange === r.key ? 'default' : 'outline'}
                className={`text-xs h-8 px-2.5 ${dateRange === r.key ? 'bg-primary text-primary-foreground' : 'border-border'}`}
                onClick={() => setDateRange(r.key)}
              >
                {r.key === 'custom' && <Calendar className="h-3 w-3 mr-1" />}
                {r.label}
              </Button>
            ))}
          </div>
        </div>

        {dateRange === 'custom' && (
          <div className="flex gap-2 mb-3">
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customFrom ? formatDate(customFrom.toISOString()) : 'From date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customFrom} onSelect={setCustomFrom} />
              </PopoverContent>
            </Popover>
            <Popover>
              <PopoverTrigger asChild>
                <Button variant="outline" size="sm" className="text-xs border-border h-8">
                  {customTo ? formatDate(customTo.toISOString()) : 'To date'}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0 bg-card border-border">
                <CalendarComponent mode="single" selected={customTo} onSelect={setCustomTo} />
              </PopoverContent>
            </Popover>
          </div>
        )}

        <div className="flex justify-end mb-4">
          <Button
            onClick={() => setShowAddModal(true)}
            className="bg-primary text-primary-foreground hover:bg-primary/90 text-xs h-9 shadow-sm"
          >
            <Plus className="h-4 w-4 mr-1.5" />
            Add Client
          </Button>
        </div>

        <Tabs defaultValue="active">
          <TabsList className="w-full mb-4 bg-secondary">
            <TabsTrigger value="active" className="flex-1 text-xs data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">
              Active ({deliveredGroups.size + otherActiveGroups.size})
            </TabsTrigger>
            <TabsTrigger value="cleared" className="flex-1 text-xs data-[state=active]:bg-primary data-[state=active]:text-primary-foreground">
              Cleared ({clearedGroups.size})
            </TabsTrigger>
          </TabsList>

          <TabsContent value="active">
            <div className="mb-6">
              <button className="flex w-full items-center gap-3 mb-3 text-left focus:outline-none" onClick={() => setDeliveredExpanded(!deliveredExpanded)}>
                <span className="font-cinzel text-sm font-bold text-green-500 whitespace-nowrap tracking-wide">DELIVERED</span>
                <span className="text-xs bg-green-500/10 text-green-500 px-2.5 py-0.5 rounded-full font-bold whitespace-nowrap border border-green-500/20">{deliveredGroups.size} pages</span>
                <div className="h-px flex-1 bg-green-500/20" />
                <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${deliveredExpanded ? 'rotate-180' : ''}`} />
              </button>
              {deliveredExpanded && <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroups(deliveredGroups)}</div>}
            </div>

            <div className="mb-4">
              <button className="flex w-full items-center gap-3 mb-3 text-left focus:outline-none" onClick={() => setOtherExpanded(!otherExpanded)}>
                <span className="font-cinzel text-sm font-bold text-primary whitespace-nowrap tracking-wide">OTHER ACTIVE (LAYAWAY/SHOP)</span>
                <span className="text-xs bg-primary/10 text-primary px-2.5 py-0.5 rounded-full font-bold whitespace-nowrap border border-primary/20">{otherActiveGroups.size} pages</span>
                <div className="h-px flex-1 bg-primary/20" />
                <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${otherExpanded ? 'rotate-180' : ''}`} />
              </button>
              {otherExpanded && <div className="space-y-3 animate-in fade-in slide-in-from-top-2 duration-200">{renderGroups(otherActiveGroups)}</div>}
            </div>
          </TabsContent>

          <TabsContent value="cleared">
            <div className="space-y-3">{renderGroups(clearedGroups)}</div>
          </TabsContent>
        </Tabs>
      </div>

      {showAddModal && <AddClientModal onClose={() => setShowAddModal(false)} userFirstName={userFirstName} userEmail={userEmail} onRefresh={onRefresh} existingRecords={records} />}
    </div>
  );
}

import { useState, memo, useMemo } from 'react';
import { ChevronDown, FileText, History } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { DatabaseRowType } from '@/types';
import { calcRemainingBalance, calcShippingFee, calcCCFee, calcItemPrice, calcDueDate, getQty } from '@/lib/calculations';
import { formatDateObj, formatDate } from '@/lib/formatters';
import StatusBadge from '@/components/StatusBadge';
import InvoiceModal from '@/components/InvoiceModal';
import FinancialsForm from './FinancialsForm';
import CustomerHistoryModal from '@/components/CustomerHistoryModal';

interface Props {
  minerName: string;
  records: DatabaseRowType[];
  allRecords: DatabaseRowType[];
  onUpdate: (rowId: number, fields: Partial<DatabaseRowType>) => Promise<void>;
}

function AccountsClientCard({ minerName, records, allRecords, onUpdate }: Props) {
  const [expanded, setExpanded] = useState(false);
  const [showInvoice, setShowInvoice] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [expandedItem, setExpandedItem] = useState<number | null>(null);

  const first = records[0];
  const dueDate = formatDateObj(calcDueDate(first?.dateOfLive));
  const totalRemaining = records.reduce((sum, r) => sum + Math.max(0, calcRemainingBalance(r)), 0);

  // Group records by Date → Liver → Status
  const grouped = useMemo(() => {
    const byDate: Record<string, Record<string, Record<string, DatabaseRowType[]>>> = {};
    for (const r of records) {
      const date = r.dateOfLive || 'No Date';
      const liver = r.liverName || 'Unknown Liver';
      const status = r.status || 'No Status';
      if (!byDate[date]) byDate[date] = {};
      if (!byDate[date][liver]) byDate[date][liver] = {};
      if (!byDate[date][liver][status]) byDate[date][liver][status] = [];
      byDate[date][liver][status].push(r);
    }
    return byDate;
  }, [records]);

  return (
    <div className="mb-3 rounded-xl border border-border bg-card overflow-hidden">
      <button className="w-full text-left px-4 py-3 flex items-center justify-between" onClick={() => setExpanded(e => !e)}>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2">
            <span className="font-cinzel text-sm text-primary">{minerName}</span>
            {first?.customerId && (
              <button
                className="text-muted-foreground hover:text-primary transition-colors"
                title="View Lifetime History"
                onClick={e => { e.stopPropagation(); setShowHistory(true); }}
              >
                <History className="h-3.5 w-3.5" />
              </button>
            )}
          </div>
          <div className="flex gap-3 text-xs text-muted-foreground mt-0.5">
            <span>{records.length} item{records.length !== 1 ? 's' : ''}</span>
            <span>Due: {dueDate}</span>
          </div>
          {totalRemaining > 0 && (
            <span className="text-xs font-medium text-destructive">Balance: AED {totalRemaining.toFixed(2)}</span>
          )}
        </div>
        <ChevronDown className={`h-4 w-4 text-muted-foreground shrink-0 ml-2 transition-transform ${expanded ? 'rotate-180' : ''}`} />
      </button>

      {expanded && (
        <div className="px-3 pb-3 border-t border-border pt-3">
          {/* Generate Invoice at the TOP */}
          <Button
            variant="outline"
            size="sm"
            className="w-full mb-3 border-primary/40 text-primary text-xs"
            onClick={() => setShowInvoice(true)}
          >
            <FileText className="h-3.5 w-3.5 mr-1.5" /> Generate Invoice
          </Button>

          {/* Grouped by Date → Liver → Status */}
          {Object.entries(grouped).sort().map(([date, livers]) => (
            <div key={date} className="mb-3">
              <div className="text-xs font-semibold text-muted-foreground uppercase tracking-wide mb-2 px-1">
                📅 {formatDate(date)}
              </div>
              {Object.entries(livers).map(([liver, statuses]) => (
                <div key={liver} className="mb-2 ml-2">
                  <div className="text-xs font-medium text-primary/80 mb-1 px-1">🧑 {liver}</div>
                  {Object.entries(statuses).map(([status, items]) => (
                    <div key={status} className="mb-2 ml-2">
                      <div className="text-xs text-muted-foreground mb-1 px-1 flex items-center gap-1">
                        <StatusBadge status={status} /> <span className="ml-1">({items.length})</span>
                      </div>
                      {items.map(record => (
                        <div key={record.id} className="mb-2 rounded-lg border border-border/50 bg-secondary/20 overflow-hidden">
                          <button
                            className="w-full text-left p-3 flex items-start justify-between"
                            onClick={() => setExpandedItem(expandedItem === record.id ? null : record.id)}
                          >
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-medium truncate mb-1">{record.itemDescription}</p>
                              <div className="text-xs text-muted-foreground">
                                {record.category} · {(record.category || '').toLowerCase().includes('screw type') ? `${getQty(record)} PCS` : (record.grams ? `${record.grams}g` : 'PC')} · {record.modeOfPayment}
                              </div>
                              <div className="flex gap-3 text-xs mt-1">
                                <span className="text-muted-foreground">Price: <span className="text-foreground">{record.currency || 'AED'} {calcItemPrice(record).toFixed(2)}</span></span>
                                <span className="text-muted-foreground">SF: <span className="text-foreground">AED {calcShippingFee(record).toFixed(2)}</span></span>
                                {calcCCFee(record) > 0 && <span className="text-muted-foreground">CC: <span className="text-foreground">AED {calcCCFee(record).toFixed(2)}</span></span>}
                              </div>
                              <div className="text-xs mt-0.5">
                                <span className={`font-medium ${calcRemainingBalance(record) > 0 ? 'text-destructive' : 'text-green-400'}`}>
                                  Balance: AED {calcRemainingBalance(record).toFixed(2)}
                                </span>
                              </div>
                            </div>
                            <ChevronDown className={`h-3.5 w-3.5 text-muted-foreground shrink-0 ml-2 mt-1 transition-transform ${expandedItem === record.id ? 'rotate-180' : ''}`} />
                          </button>

                          {expandedItem === record.id && (
                            <div className="px-3 pb-3 animate-in fade-in slide-in-from-top-2 duration-200">
                              <FinancialsForm record={record} onUpdate={onUpdate} />
                            </div>
                          )}
                        </div>
                      ))}
                    </div>
                  ))}
                </div>
              ))}
            </div>
          ))}
        </div>
      )}

      {showInvoice && <InvoiceModal records={records} onClose={() => setShowInvoice(false)} />}
      {showHistory && first?.customerId && (
        <CustomerHistoryModal
          customerId={first.customerId}
          minerName={minerName}
          allRecords={allRecords}
          onClose={() => setShowHistory(false)}
        />
      )}
    </div>
  );
}

export default memo(AccountsClientCard, (prev, next) => {
  if (prev.minerName !== next.minerName) return false;
  if (prev.records.length !== next.records.length) return false;
  for (let i = 0; i < prev.records.length; i++) {
    if (prev.records[i] !== next.records[i]) return false;
  }
  if (prev.allRecords !== next.allRecords) return false;
  return true;
});

import { useState, memo } from 'react';
import { FileText, Truck, Upload, History, ChevronDown } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { toast } from 'sonner';
import { DatabaseRowType } from '@/types';
import { calcShippingFee, isFreeSf, getQty } from '@/lib/calculations';
import StatusBadge from '@/components/StatusBadge';
import InvoiceModal from '@/components/InvoiceModal';
import CustomerHistoryModal from '@/components/CustomerHistoryModal';

interface Props {
  minerName: string;
  records: DatabaseRowType[];
  allRecords: DatabaseRowType[];
  onUpdate: (rowId: number, fields: Partial<DatabaseRowType>) => Promise<void>;
  userEmail?: string;
}

function isGivenToShopMode(record: DatabaseRowType): boolean {
  const location = (record.locationOfMiner || '').toLowerCase();
  const region = (record.regions || '').toLowerCase();
  return (
    record.modeOfPayment === 'Layaway' ||
    location.includes('pinas') ||
    location.includes('international') ||
    region.includes('pinas') ||
    region.includes('international')
